-- Poems batch 30
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('71bcf274-befb-4e57-b20c-f067fe4c6aa1','途中','楊炯','唐','唐诗','tang','','[]','悠悠辭鼎邑，去去指金墉。',60,'全唐诗/poet.tang.3000.json','["悠悠辭鼎邑，去去指金墉。", "途路盈千里，山川亙百重。", "風行常有地，雲出本多峰。", "鬱鬱園中柳，亭亭山上松。", "客心殊不樂，鄉淚獨無從。"]'),
('0a09c065-3355-47dc-8561-2d911a34b8dc','送劉校書從軍','楊炯','唐','唐诗','tang','','[]','天將下三宮，星門召五戎。',72,'全唐诗/poet.tang.3000.json','["天將下三宮，星門召五戎。", "坐謀資廟略，飛檄佇文雄。", "赤土流星劍，烏號明月弓。", "秋陰生蜀道，殺氣繞湟中。", "風雨何年別，琴尊此日同。", "離亭不可望，溝水自西東。"]'),
('7599fb2b-43f5-41cd-88cb-20f0fe828e99','遊廢觀','楊炯','唐','唐诗','tang','','[]','青幛倚丹田，荒涼數百年。',72,'全唐诗/poet.tang.3000.json','["青幛倚丹田，荒涼數百年。", "猶知小山桂，尚識大羅天。", "藥敗金爐火，苔昏玉女泉。", "歲時無壁畫，朝夕有階煙。", "花柳三春節，江山四望懸。", "悠然出塵網，從此狎神仙。"]'),
('837b2750-0ba8-421e-b124-3d6ab7381c16','和石侍御山莊','楊炯','唐','唐诗','tang','','[]','煙霞非俗宇，巖壑只幽居。',72,'全唐诗/poet.tang.3000.json','["煙霞非俗宇，巖壑只幽居。", "水浸何曾畎，荒郊不復鋤。", "影濃山樹密，香淺澤花疎。", "闊塹防斜徑，平堤夾小渠。", "蓮房若箇實，竹節幾重虛。", "蕭然隔城市，酌醴焚枯魚。"]'),
('7afeddef-90a3-4908-b6fc-875d2a64c3de','送李庶子致仕還洛','楊炯','唐','唐诗','tang','','[]','此地傾城日，由來供帳華。',72,'全唐诗/poet.tang.3000.json','["此地傾城日，由來供帳華。", "亭逢李廣騎，門接邵平瓜。", "原野煙氛匝，關河遊望賒。", "白雲斷巖岫，綠草覆江沙。", "詔賜扶陽宅，人榮御史車。", "灞池一相送，流涕向煙霞。"]'),
('b7fbbf94-16ae-4cbe-8ebb-05c240c60f5e','早行','楊炯','唐','唐诗','tang','','[]','敞朗東方徹，闌干北斗斜。',72,'全唐诗/poet.tang.3000.json','["敞朗東方徹，闌干北斗斜。", "地氣俄成霧，天雲漸作霞。", "河流纔辨馬，巖路不容車。", "阡陌經三歲，閭閻對五家。", "露文沾細草，風影轉高花。", "日月從來惜，關山猶自賒。"]'),
('81ce81a6-2e44-432f-a440-9c548f3517ff','和崔司空傷姬人','楊炯','唐','唐诗','tang','','[]','昔時南浦別，鶴怨寶琴弦。',72,'全唐诗/poet.tang.3000.json','["昔時南浦別，鶴怨寶琴弦。", "今日東方至，鸞銷珠鏡前。", "水流銜砌咽，月影向窗懸。", "妝匣悽餘粉，熏爐滅舊煙。", "晚庭摧玉樹，寒帳委金蓮。", "佳人不再得，雲日幾千年。"]'),
('db33d521-9935-4748-a166-743e40cf4ab7','和騫右丞省中暮望','楊炯','唐','唐诗','tang','','[]','故事閒臺閣，仙門藹已深。',84,'全唐诗/poet.tang.3000.json','["故事閒臺閣，仙門藹已深。", "舊章窺複道，雲幌肅重陰。", "玄律葭灰變，青陽斗柄臨。", "年光搖樹色，春氣繞蘭心。", "風響高窗度，流痕曲岸侵。", "天門總樞轄，人鏡辨衣簪。", "日暮南宮靜，瑤華振雅音。"]'),
('082bf240-136b-498f-88a4-48b1a1ac3c6c','和酬虢州李司法','楊炯','唐','唐诗','tang','','[]','唇齒標形勝，關河壯邑居。',96,'全唐诗/poet.tang.3000.json','["唇齒標形勝，關河壯邑居。", "寒山抵方伯，秋水面鴻臚。", "君子從遊宦，忘情任卷舒。", "風霜下刀筆，軒蓋擁門閭。", "平野芸黃遍，長洲鴻雁初。", "菊花宜泛酒，浦葉好裁書。", "昔我芝蘭契，悠然雲雨疎。", "非君重千里，誰有惠雙魚。"]'),
('85f36d32-337d-440a-8317-a61d3d3595cc','和鄭讎校內省眺矚思鄉懷友','楊炯','唐','唐诗','tang','','[]','銅門初下辟，石館始沈研。',96,'全唐诗/poet.tang.3000.json','["銅門初下辟，石館始沈研。", "遊霧千金字，飛雲五色牋。", "樓臺橫紫極，城闕俯青田。", "暄入瑤房裏，春回玉宇前。", "霞文埋落照，風物澹歸煙。", "翰墨三餘隙，關山四望懸。", "頹峰暌酌羽，流水曠鳴絃。", "雖欣承白雪，終恨隔青天。"]'),
('ed2a08a5-1d28-4144-a920-faee72408b45','和旻上人傷果禪師','楊炯','唐','唐诗','tang','','[]','淨業初中日，浮生大小年。',96,'全唐诗/poet.tang.3000.json','["淨業初中日，浮生大小年。", "無人本無我，非後亦非前。", "簫鼓旁喧地，龍蛇直映天。", "法門摧棟宇，覺海破舟船。", "書鎮秦王餉，經文宋國傳。", "聲華周百億，風烈被三千。", "蕪沒青園寺，荒涼紫陌田。", "德音殊未遠，拱木已生煙。"]'),
('952ec2cf-b0ac-4fc9-b83e-90b60ab4c4a9','和劉侍郎入隆唐觀','楊炯','唐','唐诗','tang','','[]','福地陰陽合，仙都日月開。',120,'全唐诗/poet.tang.3000.json','["福地陰陽合，仙都日月開。", "山川臨四險，城樹隱三臺。", "伏檻排雲出，飛軒遶澗回。", "參差凌倒影，瀟灑軼浮埃。", "百果珠爲實，羣峰錦作苔。", "懸蘿暗疑霧，瀑布響成雷。", "方士燒丹液，真人泛玉杯。", "還如問桃水，更似得蓬萊。", "漢帝求仙日，相如作賦才。", "自然金石奏，何必上天台。"]'),
('b6b3b553-be08-42d5-bc7c-fcce3348cb0d','和輔先入昊天觀星瞻','楊炯','唐','唐诗','tang','','[]','遁甲爰皇里，星占太乙宮。',144,'全唐诗/poet.tang.3000.json','["遁甲爰皇里，星占太乙宮。", "天門開奕奕，佳氣鬱蔥蔥。", "碧落三乾外，黃圖四海中。", "邑居環若水，城闕抵新豐。", "玉檻崑崙側，金樞地軸東。", "上真朝北斗，元始詠南風。", "漢君祠五帝，淮王禮八公。", "道書編竹簡，靈液灌梧桐。", "草茂瓊階綠，花繁寶樹紅。", "石樓紛似畫，地鏡淼如空。", "桑海年應積，桃源路不窮。", "黃軒若有問，三月住崆峒。"]'),
('c262982e-59e4-4fd5-b435-31997a5aa6c6','和劉長史荅十九兄','楊炯','唐','唐诗','tang','','[]','帝堯平百姓，高祖宅三秦。',288,'全唐诗/poet.tang.3000.json','["帝堯平百姓，高祖宅三秦。", "子弟分河岳，衣冠動縉紳。", "盛名恆不隕，歷代幾相因。", "街巷塗山曲，門閭洛水濱。", "五龍金作友，一子玉爲人。", "寶劍豐城氣，明珠魏國珍。", "風標自落落，文質且彬彬。", "共許刁元亮，同推周伯仁。", "石城俯天闕，鍾阜對江津。", "驥足方遐騁，狼心獨未馴。", "鼓鼙鳴九域，風火集重闉。", "城勢餘三板，兵威乏四鄰。", "居然混玉石，直置保松筠。", "耿介酬天子，危言數賊臣。", "鍾儀琴未奏，蘇武節猶新。", "受祿寧辭死，揚名不顧身。", "精誠動天地，忠義感明神。", "怪鳥俄垂翼，修蛇竟暴鱗。", "來朝拜休命，述職下梁岷。", "善政馳金馬，嘉聲繞玉輪。", "三荆忽有贈，四海更相親。", "宮徵諧鳴石，光輝掩燭銀。", "山川遙滿目，零露坐沾巾。", "友愛光天下，恩波浹後塵。"]'),
('957f6814-e4c7-4d03-b8bc-9370952dbb05','夜送趙縱','楊炯','唐','唐诗','tang','','["\u9001\u522b"]','趙氏連城璧，由來天下傳。',24,'全唐诗/poet.tang.3000.json','["趙氏連城璧，由來天下傳。", "送君還舊府，明月滿前川。"]'),
('cdab1a54-9805-4c24-a89a-4b9c58594cf4','息夫人','宋之問','唐','唐诗','tang','','[]','可憐楚破息，腸斷息夫人。',48,'全唐诗/poet.tang.3000.json','["可憐楚破息，腸斷息夫人。", "仍爲泉下骨，不作楚王嬪。", "楚王寵莫盛，息君情更親。", "情親怨生別，一朝俱殺身。"]'),
('fa42d2ac-f630-4aa6-b93b-65ebba9e3d9a','初到陸渾山莊','宋之問','唐','唐诗','tang','','[]','授衣感窮節，策馬凌伊關。',48,'全唐诗/poet.tang.3000.json','["授衣感窮節，策馬凌伊關。", "歸齊逸人趣，日覺秋琴閑。", "寒露衰北阜，夕陽破東山。", "浩歌步榛樾，棲鳥隨我還。"]'),
('2846a406-001c-45f8-824e-a5cf45523500','夜飲東亭','宋之問','唐','唐诗','tang','','[]','春泉鳴大壑，皓月吐層岑。',48,'全唐诗/poet.tang.3000.json','["春泉鳴大壑，皓月吐層岑。", "岑壑景色佳，慰我遠遊心。", "暗芳足幽氣，驚棲多衆音。", "高興南山曲，長謠橫素琴。"]'),
('7637858b-ae90-4d68-9696-83eebfd4770f','芳樹','宋之問','唐','唐诗','tang','','[]','何地早芳菲，宛在長門殿。',48,'全唐诗/poet.tang.3000.json','["何地早芳菲，宛在長門殿。", "夭桃色若綬，穠李光如練。", "啼鳥弄花疎，遊蜂飲香遍。", "歎息春風起，飄零君不見。"]'),
('90440b5c-fb49-4153-8cb1-87680ecbe3b4','送趙六貞固','宋之問','唐','唐诗','tang','','[]','目斷南浦雲，心醉東郊柳。',48,'全唐诗/poet.tang.3000.json','["目斷南浦雲，心醉東郊柳。", "怨別此何時，春芳來已久。", "與君共時物，盡此盈樽酒。", "始願今不從，春風戀攜手。"]'),
('624fb484-7d7a-4a63-b972-c2f35c3ca313','題張老松樹','宋之問','唐','唐诗','tang','','[]','歲晚東巖下，周顧何悽惻。',48,'全唐诗/poet.tang.3000.json','["歲晚東巖下，周顧何悽惻。", "日落西山陰，衆草起寒色。", "中有喬松樹，使我長歎息。", "百尺無寸枝，一生自孤直。"]'),
('62527274-ee49-4fd2-a641-2d6822c9f033','別之望後獨宿藍田山莊','宋之問','唐','唐诗','tang','','[]','鶺鴒有舊曲，調苦不成歌。',72,'全唐诗/poet.tang.3000.json','["鶺鴒有舊曲，調苦不成歌。", "自歎兄弟少，常嗟離別多。", "爾尋北京路，予臥南山阿。", "泉晚更幽咽，雲秋尚嵯峨。", "藥欄聽蟬噪，書幌見禽過。", "愁至願甘寢，其如鄉夢何。"]'),
('1987a53d-8e9c-40de-8f6a-dea28f1c64c2','浣紗篇贈陸上人','宋之問','唐','唐诗','tang','','[]','越女顏如花，越王聞浣紗。',204,'全唐诗/poet.tang.3000.json','["越女顏如花，越王聞浣紗。", "國微不自寵，獻作吳宮娃。", "山藪半潛匿，苧蘿更蒙遮。", "一行霸句踐，再笑傾夫差。", "豔色奪人目，斆嚬亦相誇。", "一朝還舊都，靚粧尋若耶。", "鳥驚入松網，魚畏沈荷花。", "始覺冶容妄，方悟羣心邪。", "欽子秉幽意，世人共稱嗟。", "願言托君懷，倘類蓬生麻。", "家住雷門曲，高閣凌飛霞。", "淋漓翠羽帳，旖旎采雲軍。", "春風豔楚舞，秋月纏胡笳。", "自昔專嬌愛，襲玩唯矜奢。", "達本知空寂，棄彼猶泥沙。", "永割偏執性，自長薰修芽。", "攜妾不障道，來止妾西家。"]'),
('097e4aee-c82b-4d38-9ea4-b5ac775290dc','雨從箕山來','宋之問','唐','唐诗','tang','','[]','雨從箕山來，倏與飄風度。',84,'全唐诗/poet.tang.3000.json','["雨從箕山來，倏與飄風度。", "晴明西峰日，綠縟南溪樹。", "此時客精廬，幸蒙真僧顧。", "深入清淨理，妙斷往來趣。", "意得兩契如，言盡共忘喻。", "觀花寂不動，聞鳥懸可悟。", "向夕聞天香，淹留不能去。"]'),
('f2d614c6-6fa6-4f1f-b191-e5e0e49c3154','初至崖口','宋之問','唐','唐诗','tang','','[]','崖口衆山斷，嶔崟聳天壁。',72,'全唐诗/poet.tang.3000.json','["崖口衆山斷，嶔崟聳天壁。", "氣衝落日紅，影入春潭碧。", "錦繢織苔蘚，丹青畫松石。", "水禽泛容與，巖花飛的皪。", "微路從此深，我來限于役。", "惆悵情未已，羣峰暗將夕。"]'),
('2bddb506-d53e-414b-bb71-3165b72ee162','自湘源至潭州衡山縣','宋之問','唐','唐诗','tang','','["\u8861\u5c71"]','浮湘沿迅湍，逗浦凝遠盼。',96,'全唐诗/poet.tang.3000.json','["浮湘沿迅湍，逗浦凝遠盼。", "漸見江勢闊，行嗟水流漫。", "赤岸雜雲霞，綠竹緣溪澗。", "向背羣山轉，應接良景晏。", "沓障連夜猿，平沙覆陽雁。", "紛吾望闕客，歸橈速已慣。", "中道方泝洄，遲念自茲撰。", "賴欣衡陽美，持以蠲憂患。"]'),
('87eb79bf-7f11-4152-abb9-a20e0eb24259','入崖口五渡寄李適','宋之問','唐','唐诗','tang','','[]','抱琴登絕壑，伐木泝清川。',132,'全唐诗/poet.tang.3000.json','["抱琴登絕壑，伐木泝清川。", "路極意謂盡，勢回趣轉綿。", "人遠草木秀，山深雲景鮮。", "余負海嶠情，自昔微尚然。", "彌曠十餘載，今來宛仍前。", "未窺仙源極，獨進野人船。", "時攀乳竇憩，屢薄天窗眠。", "夜弦響松月，朝楫弄苔泉。", "因冥象外理，永謝區中緣。", "碧潭可遺老，丹砂堪學仙。", "莫使馳光暮，空令歸鶴憐。"]'),
('ba43da13-4f89-4d65-a1bf-62efa5f5d6c0','洞庭湖','宋之問','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','地盡天水合，朝及洞庭湖。',132,'全唐诗/poet.tang.3000.json','["地盡天水合，朝及洞庭湖。", "初日當中涌，莫辨東西隅。", "晶耀目何在，瀅熒心欲無。", "靈光晏海若，游氣耿天吳。", "張樂軒皇至，征苗夏禹徂。", "楚臣悲落葉，堯女泣蒼梧。", "野積九江潤，山通五嶽圖。", "風恬魚自躍，雲夕雁相呼。", "獨此臨泛漾，浩將人代殊。", "永言洗氛濁，卒歲爲清娛。", "要使功成退，徒勞越大夫。"]'),
('d0a304ef-b9f1-4f9c-b9e3-9890a1ca86d0','景龍四年春祠海','宋之問','唐','唐诗','tang','','[]','肅事祠春溟，宵齋洗蒙慮。',180,'全唐诗/poet.tang.3000.json','["肅事祠春溟，宵齋洗蒙慮。", "雞鳴見日出，鷺下驚濤鶩。", "地闊八荒近，天回百川澍。", "筵端接空曲，目外唯雰霧。", "暖氣物象來，周遊晦明互。", "致牲匪玄享，禋滌期靈煦。", "的的波際禽，沄沄島間樹。", "安期今何在，方丈蔑尋路。", "仙事與世隔，冥搜徒已屢。", "四明背羣山，遺老莫辨處。", "撫中良自慨，弱齡忝恩遇。", "三入文史林，兩拜神仙署。", "雖歎出關遠，始知臨海趣。", "賞來空自多，理勝孰能喻。", "留楫竟何待，徙倚忽云暮。"]'),
('a9957052-6982-4ff5-9e8c-5472eaddfc6b','溫泉莊臥病寄楊七炯','宋之問','唐','唐诗','tang','','[]','移疾臥茲嶺，寥寥倦幽獨。',120,'全唐诗/poet.tang.3000.json','["移疾臥茲嶺，寥寥倦幽獨。", "賴有嵩丘山，高枕長在目。", "茲山棲靈異，朝夜翳雲族。", "是日濛雨晴，返景入巖谷。", "冪冪澗畔草，青青山下木。", "此意方無窮，環顧悵林麓。", "伊洛何悠漫，川原信重複。", "夏餘鳥獸蕃，秋末禾黍熟。", "秉願守樊圃，歸閑欣藝牧。", "惜無載酒人，徒把涼泉掬。"]'),
('08aa0cab-ac13-486b-b6fa-42ef81a09899','荅田徵君','宋之問','唐','唐诗','tang','','[]','家臨清溪水，溪水繞盤石。',72,'全唐诗/poet.tang.3000.json','["家臨清溪水，溪水繞盤石。", "綠蘿四面垂，褭褭百餘尺。", "風泉度絲管，苔蘚鋪茵席。", "傳聞潁陽人，霞外漱靈液。", "忽枉巖中翰，吟望朝復夕。", "何當遂遠遊，物色候逋客。"]'),
('d96d2ca0-c18e-4a72-abc3-b3d015bac44c','自衡陽至韶州謁能禪師','宋之問','唐','唐诗','tang','','[]','謫居竄炎壑，孤帆淼不繫。',180,'全唐诗/poet.tang.3000.json','["謫居竄炎壑，孤帆淼不繫。", "別家萬里餘，流目三春際。", "猿啼山館曉，虹飲江皐霽。", "湘岸竹泉幽，衡峯石囷閉。", "嶺嶂窮攀越，風濤極沿濟。", "吾師在韶陽，欣此得躬詣。", "洗慮賓空寂，焚香結精誓。", "願以有漏軀，聿薰無生慧。", "物用益沖曠，心源日閑細。", "伊我獲此途，遊道回晚計。", "宗師信捨法，擯落文史藝。", "坐禪羅浮中，尋異窮海裔。", "何辭禦魑魅，自可乘炎癘。", "回首望舊鄉，雲林浩虧蔽。", "不作離別苦，歸期多年歲。"]'),
('b02d795c-799a-4d28-b5aa-26d833736bde','見南山夕陽召監師不至','宋之問','唐','唐诗','tang','','[]','夕陽黯晴碧，山翠互明滅。',48,'全唐诗/poet.tang.3000.json','["夕陽黯晴碧，山翠互明滅。", "此中意無限，要與開士說。", "徒鬱仲舉思，詎迴道林轍。", "孤興欲待誰，待此湖上月。"]'),
('563eb155-69f0-40ec-9bbb-105167dbc4ac','遊法華寺','宋之問','唐','唐诗','tang','','[]','薄游京都日，遙羨稽山名。',120,'全唐诗/poet.tang.3000.json','["薄游京都日，遙羨稽山名。", "分刺江海郡，朅來徵素情。", "松露洗心眷，象筵敷念誠。", "薄雲界青嶂，皎日鶱朱甍。", "苔澗深不測，竹房閑且清。", "感真六象見，垂兆二𪅝鳴。", "古今信靈跡，中州莫與京。", "林巘永棲業，豈伊佐一生。", "浮悟雖已久，事試去來成。", "觀念幸相續，庶幾最後明。"]'),
('2a9362bf-5d80-4528-af3a-96c7cb7d0848','宿雲門寺','宋之問','唐','唐诗','tang','','[]','雲門若邪裏，泛鷁路纔通。',132,'全唐诗/poet.tang.3000.json','["雲門若邪裏，泛鷁路纔通。", "夤緣綠篠岸，遂得青蓮宮。", "天香衆壑滿，夜梵前山空。", "漾漾潭際月，颸飀杉上風。", "茲焉多嘉遯，數子今莫同。", "鳳歸慨處士，鹿化聞仙公。", "樵路鄭州北，舉井阿巖東。", "永夜豈云寐，曙華忽葱蘢。", "谷鳥囀尚澀，源桃驚未紅。", "再來期春暮，當造林端窮。", "庶幾蹤謝客，開山投剡中。"]'),
('7e923cd3-3ab2-4e21-9cd8-09b732e339eb','春湖古意','宋之問','唐','唐诗','tang','','[]','院梅發向尺，園鳥復成曲。',48,'全唐诗/poet.tang.3000.json','["院梅發向尺，園鳥復成曲。", "落日遊南湖，果擲顏如玉。", "含情不得語，轉盼知所屬。", "惆悵未可歸，寧關須采菉。"]'),
('cefe7e6a-f5fc-4cee-bf22-17c832e3bf4a','游陸渾南山自歇馬嶺到楓香林以詩代書荅李舍人適','宋之問','唐','唐诗','tang','','[]','晨登歇馬嶺，遙望伏牛山。',156,'全唐诗/poet.tang.3000.json','["晨登歇馬嶺，遙望伏牛山。", "孤出羣峰首，熊熊元氣間。", "太和亦崔嵬，石扇橫閃倏。", "細岑互攢倚，浮巘競奔蹙。", "白雲遙入懷，青靄近可掬。", "徒尋靈異跡，周顧愜心目。", "晨拂鳥路行，暮投人煙宿。", "稉稻遠彌秀，栗芋秋新熟。", "石髓非一巖，藥苗乃萬族。", "間關踏雲雨，繚繞緣水木。", "西見商山芝，南到楚鄉竹。", "楚竹幽且深，半雜楓香林。", "浩歌清潭曲，寄爾桃源心。"]'),
('ab2b3f7a-4caf-4d5f-9615-79c2eeb1f0a1','早發大庾嶺','宋之問','唐','唐诗','tang','','[]','晨躋大庾險，驛鞍馳復息。',180,'全唐诗/poet.tang.3000.json','["晨躋大庾險，驛鞍馳復息。", "霧露晝未開，浩途不可測。", "嵥起華夷界，信爲造化力。", "歇鞍問徒旅，鄉關在西北。", "出門怨別家，登嶺恨辭國。", "自惟勗忠孝，斯罪懵所得。", "皇明頗照洗，延議日紛惑。", "兄弟遠淪居，妻子成異域。", "羽翮傷已毀，童幼憐未識。", "躊躕戀北顧，亭午晞霽色。", "春煖陰梅花，瘴回陽鳥翼。", "含沙緣澗聚，吻草依林植。", "適蠻悲疾首，懷鞏淚沾臆。", "感謝鵷鷺朝，勤修魑魅職。", "生還倘非遠，誓擬酬恩德。"]'),
('c736146d-7acb-4eb1-84ab-ce420bbbf057','自洪府舟行直書其事','宋之問','唐','唐诗','tang','','[]','仲春辭國門，畏途橫萬里。',288,'全唐诗/poet.tang.3000.json','["仲春辭國門，畏途橫萬里。", "越淮乘楚嶂，造江泛吳汜。", "嚴程無休隙，日夜涉風水。", "昔聞垂堂言，將誡千金子。", "問余何奇剝，遷竄極炎鄙。", "揆己道德餘，幼聞虛白旨。", "貴身賤外物，抗跡遠塵軌。", "朝遊伊水湄，夕臥箕山趾。", "妙年拙自晦，皎潔弄文史。", "謬辱紫泥書，揮翰青雲裏。", "事往每增傷，寵來常誓止。", "銘骨懷報稱，逆鱗讓金紫。", "安位釁潛搆，退耕禍猶起。", "棲巖實吾策，觸藩誠內恥。", "濟濟同時人，台庭鳴劒履。", "愚以卑自衞，兀坐去沈滓。", "迨茲理已極，竊位申知己。", "羣議負宿心，獲戾光華始。", "黃金忽銷鑠，素業坐淪毀。", "浩歎誣平生，何獨戀枌梓。", "浦樹浮鬱鬱，皐蘭覆靡靡。", "百越去魂斷，九疑望心死。", "未盡匡阜遊，遠欣羅浮美。", "周旋本師訓，佩服無生理。"]'),
('8bff19a0-00a9-441d-902e-06058fa045e8','下桂江縣黎壁','宋之問','唐','唐诗','tang','','[]','放溜覿前漵，連山分上干。',132,'全唐诗/poet.tang.3000.json','["放溜覿前漵，連山分上干。", "江回雲壁轉，天小霧峯攢。", "吼沫跳急浪，合流環峻灘。", "欹離出漩劃，繚繞避渦盤。", "舟子怯桂水，最言斯路難。", "吾生抱忠信，吟嘯自安閑。", "旦別已千歲，夜愁勞萬端。", "企予見夜月，委曲破林巒。", "潭曠竹煙盡，洲香橘露團。", "豈傲夙所好，對之與俱歡。", "思君罷琴酌，泣此夜漫漫。"]'),
('b3744261-baec-4685-967c-0fa09ff5b9c4','奉使嵩山途經緱嶺','宋之問','唐','唐诗','tang','','[]','侵星發洛城，城中歌吹聲。',48,'全唐诗/poet.tang.3000.json','["侵星發洛城，城中歌吹聲。", "畢景至緱嶺，嶺上煙霞生。", "草樹饒野意，山川多古情。", "大隱德所薄，歸來可退耕。"]'),
('a2d34ce5-4731-4099-98e1-7debaf6078ae','傷王七秘書監寄呈揚州陸長史通簡府僚廣陵以廣好事','宋之問','唐','唐诗','tang','','[]','王氏貴先宗，衡門棲道風。',132,'全唐诗/poet.tang.3000.json','["王氏貴先宗，衡門棲道風。", "傳心晤有物，秉化遊無窮。", "學奧九流異，機玄三語同。", "書乃墨場絕，文稱詞伯雄。", "白屋藩魏主，蒼生期謝公。", "一祗賢良詔，遂謁承明宮。", "補衮望奚塞，尊儒位未充。", "罷官七門裏，歸老一丘中。", "嘗忝長者轍，微言私謂通。", "我行會稽郡，路出廣陵東。", "物在人已矣，都疑淮海空。"]'),
('eb4e6da2-b504-4eb3-9f74-60da168ca9a7','使至嵩山尋杜四不遇慨然復傷田洗馬韓觀主因以題壁贈杜侯杜四','宋之問','唐','唐诗','tang','','[]','洛橋瞻太室，期子在雲煙。',108,'全唐诗/poet.tang.3000.json','["洛橋瞻太室，期子在雲煙。", "歸來不相見，孤賞弄寒泉。", "與君闊松石，于茲二十年。", "田公謝昭世，韓子秘幽埏。", "憶昔同攜手，山棲接二賢。", "笙歌入玄地，詩酒坐寥天。", "舊友悉零落，罷琴私自憐。", "逝者非藥誤，餐霞意可全。", "爲余理還策，相與事靈仙。"]'),
('48bfe21e-41a1-4e70-865a-322188c27a3e','翫郡齋海榴','宋之問','唐','唐诗','tang','','[]','澤國韶氣早，開簾延霽天。',132,'全唐诗/poet.tang.3000.json','["澤國韶氣早，開簾延霽天。", "野禽宵未囀，山蜚晝仍眠。", "目茲海榴發，列暎巖楹前。", "熠爚禦風靜，葳蕤含景鮮。", "清晨綠堪佩，亭午丹欲然。", "昔忝金閨籍，嘗見玉池蓮。", "未若宗族地，更逢榮耀全。", "南金雖自貴，賀賞詎能遷。", "撫躬萬里絕，豈染一朝妍。", "徒緣滯遐郡，常是惜流年。", "越俗鄙章甫，捫心空自憐。"]'),
('a130b9ea-0f41-4f06-8394-d9e6a053a27b','長安路','宋之問','唐','唐诗','tang','','[]','秦地平如掌，層城出雲漢。',48,'全唐诗/poet.tang.3000.json','["秦地平如掌，層城出雲漢。", "樓閣九衢春，車馬千門旦。", "綠柳開復合，紅塵聚還散。", "日晚鬬雞場，經過狹斜看。"]'),
('6c745c97-2a26-40cb-bc79-de9ca78abb77','折楊柳','宋之問','唐','唐诗','tang','','[]','玉樹朝日映，羅帳春風吹。',48,'全唐诗/poet.tang.3000.json','["玉樹朝日映，羅帳春風吹。", "拭淚攀楊柳，長條宛地垂。", "白花飛歷亂，黃鳥思參差。", "妾自肝腸斷，傍人那得知。"]'),
('e450b85e-af1e-4bfc-ad52-deecdea08a4f','有所思','宋之問','唐','唐诗','tang','','[]','君子事行役，再空芳歲期。',48,'全唐诗/poet.tang.3000.json','["君子事行役，再空芳歲期。", "美人曠遙佇，萬里浮雲思。", "園桃綻紅豔，郊葉柔綠滋。", "坐看長夏晚，秋月生羅帷。"]'),
('722a5190-983c-4b15-beae-49851178c7a4','軍中人日登高贈房明府','宋之問','唐','唐诗','tang','','[]','幽郊昨夜陰風斷，頓覺朝來陽吹暖。',64,'全唐诗/poet.tang.3000.json','["幽郊昨夜陰風斷，頓覺朝來陽吹暖。", "涇水橋南柳欲黃，杜陵城北花應滿。", "長安昨夜寄春衣，短翮登茲一望歸。", "聞道凱旋乘騎入，看君走馬見芳菲。"]'),
('b129aaf4-a51b-4651-8c11-19391eb12d6f','寒食還陸渾別業','宋之問','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u5bd2\u98df\u8282"]','洛陽城裏花如雪，陸渾山中今始發。',64,'全唐诗/poet.tang.3000.json','["洛陽城裏花如雪，陸渾山中今始發。", "旦別河橋楊柳風，夕臥伊川桃李月。", "伊川桃李正芳新，寒食山中酒復春。", "野老不知堯舜力，酣歌一曲太平人。"]'),
('11f43cfd-a277-41f9-b9b9-b3347f6a6be9','寒食江州滿塘驛','宋之問','唐','唐诗','tang','','["\u5e90\u5c71", "\u5bd2\u98df\u8282", "\u601d\u4e61", "\u4f24\u6000"]','去年上巳洛橋邊，今年寒食廬山曲。',64,'全唐诗/poet.tang.3000.json','["去年上巳洛橋邊，今年寒食廬山曲。", "遙憐鞏樹花應滿，復見吳洲草新綠。", "吳洲春草蘭杜芳，感物思歸懷故鄉。", "驛騎明朝宿何處？猿聲今夜斷君腸。"]'),
('88a79a0a-16e5-486d-8519-53f99a76a414','至端州驛見杜五審言沈三佺期閻五朝隱王二無競題壁慨然成詠','宋之問','唐','唐诗','tang','','[]','逐臣北地承嚴譴，謂到南中每相見。',64,'全唐诗/poet.tang.3000.json','["逐臣北地承嚴譴，謂到南中每相見。", "豈意南中岐路多，千山萬水分鄉縣。", "雲搖雨散各翻飛，海闊天長音信稀。", "處處山川同瘴癘，自憐能得幾人歸。"]'),
('60057685-5b50-4eb2-8b0f-c47fe8dbe4e2','綠竹引','宋之問','唐','唐诗','tang','','[]','青溪綠潭潭水側，修竹嬋娟同一色。',64,'全唐诗/poet.tang.3000.json','["青溪綠潭潭水側，修竹嬋娟同一色。", "徒生僊實鳳不遊，老死空山人詎識。", "妙年秉願逃俗紛，歸臥嵩丘弄白雲。", "含情傲睨慰心目，何可一日無此君。"]'),
('13d52444-8892-40d3-af0a-3ff50214e201','明河篇','宋之問','唐','唐诗','tang','','[]','八月涼風天氣晶，萬里無雲河漢明。',192,'全唐诗/poet.tang.3000.json','["八月涼風天氣晶，萬里無雲河漢明。", "昏見南樓清且淺，曉落西山縱復橫。", "洛陽城闕天中起，長河夜夜千門裏。", "複道連甍共蔽虧，畫堂瓊戶特相宜。", "雲母帳前初泛濫，水精簾外轉逶迤。", "倬彼昭回如練白，復出東城接南陌。", "南陌征人去不歸，誰家今夜擣寒衣。", "鴛鴦機上疎螢度，烏鵲橋邊一雁飛。", "雁飛螢度愁難歇，坐見明河漸微沒。", "已能舒卷任浮雲，不惜光輝讓流月。", "明河可望不可親，願得乘槎一問津。", "更將織女支機石，還訪成都賣卜人。"]'),
('49d170cf-fc74-4f8f-b207-b82d364091b7','龍門應制','宋之問','唐','唐诗','tang','','[]','宿雨霽氛埃，流雲度城闕。',328,'全唐诗/poet.tang.3000.json','["宿雨霽氛埃，流雲度城闕。", "河堤柳新翠，苑樹花先發。", "洛陽花柳此時濃，山水樓臺暎幾重。", "羣公拂霧朝翔鳳，天子乘春幸鑿龍。", "鑿龍近出王城外，羽從琳琅擁軒蓋。", "雲罕纔臨御水橋，天衣已入香山會。", "山壁嶄巖斷復連，清流澄澈俯伊川。", "雁塔遙遙綠波上，星龕奕奕翠微邊。", "層巒舊長千尋木，遠壑初飛百丈泉。", "綵仗蜺旌遶香閣，下輦登高望河洛。", "東城宮闕擬昭回，南陌溝塍殊綺錯。", "林下天香七寶臺，山中春酒萬年杯。", "微風一起祥花落，仙樂初鳴瑞鳥來。", "鳥來花落紛無已，稱觴獻壽煙霞裏。", "歌舞淹留景欲斜，石關猶駐五雲車。", "鳥旗翼翼留芳草，龍騎駸駸暎晚花。", "千乘萬騎鑾輿出，水靜山空嚴警蹕。", "郊外喧喧引看人，傾都南望屬車塵。", "囂聲引颺聞黃道，佳氣周迴入紫宸。", "先王定鼎山河固，寶命乘周萬物新。", "吾皇不事瑤池樂，時雨來觀農扈春。"]'),
('e438ac7e-6725-47eb-b683-a6b9a25f3466','初宿淮口','宋之問','唐','唐诗','tang','','[]','孤舟汴河水，去國情無已。',56,'全唐诗/poet.tang.3000.json','["孤舟汴河水，去國情無已。", "晚泊投楚鄉，明月清淮裏。", "汴河東瀉路窮茲，洛陽西顧日增悲。", "夜聞楚歌思欲斷，況值淮南木落時。"]'),
('2b4100e1-f53e-43bb-8af8-8a5e04946306','王子喬','宋之問','唐','唐诗','tang','','[]','王子喬，愛神仙，七月七日上賓天。',60,'全唐诗/poet.tang.3000.json','["王子喬，愛神仙，七月七日上賓天。", "白虎搖瑟鳳吹笙，乘騎雲氣吸日精。", "吸日精，長不歸，遺廟今在而人非。", "空望山頭草，草露溼人衣。"]'),
('add550b8-b152-4880-8f58-ffa183eadcab','放白鷴篇','宋之問','唐','唐诗','tang','','[]','故人贈我綠綺琴，兼致白鷴鳥。',106,'全唐诗/poet.tang.3000.json','["故人贈我綠綺琴，兼致白鷴鳥。", "琴是嶧山桐，鳥出吳溪中。", "我心松石清霞裏，弄此幽弦不能已。", "我心河海白雲垂，憐此珍禽空自知。", "著書晚下麒麟閣，幼稚驕癡候門樂。", "乃言物性不可違，白鷴愁慕刷毛衣。", "玉徽閉匣留爲念，六翮開籠任爾飛。"]'),
('5ae42510-1f4b-4dfd-9e4e-9bcdfaeada69','桂州三月三日','宋之問','唐','唐诗','tang','','["\u9ec4\u6cb3"]','代業京華裏，遠投魑魅鄉。',304,'全唐诗/poet.tang.3000.json','["代業京華裏，遠投魑魅鄉。", "登高望不極，雲海四茫茫。", "伊昔承休盼，曾爲人所羨。", "兩朝賜顏色，二紀陪歡宴。", "昆明御宿侍龍媒，伊闕天泉復幾回。", "西夏黃河水心劒，東周清洛羽觴杯。", "苑中落花掃還合，河畔垂楊撥不開。", "千春萬壽多行樂，柏梁和歌攀睿作。", "賜金分帛奉恩輝，風舉雲搖入紫微。", "晨趨北闕鳴珂至，夜出南宮把燭歸。", "載筆儒林多歲月，襆被文昌佐吳越。", "越中山海高且深，興來無處不登臨。", "永和九年刺海郡，暮春三月醉山陰。", "愚謂嬉遊長似昔，不言流寓歘成今。", "始安繁華舊風俗，帳飲傾城沸江曲。", "主人絲管清且悲，客子肝腸斷還續。", "荔浦蘅皐萬里餘，洛陽音信絕能疎。", "故園今日應愁思，曲水何能更祓除。", "逐伴誰憐合浦葉，思歸豈食桂江魚。", "不求漢使金囊贈，願得佳人錦字書。"]'),
('aa1a1768-8324-4aed-b777-5ef11e4e64f6','下山歌','宋之問','唐','唐诗','tang','','[]','下嵩山兮多所思，攜佳人兮步遲遲。',32,'全唐诗/poet.tang.3000.json','["下嵩山兮多所思，攜佳人兮步遲遲。", "松間明月長如此，君再遊兮復何時。"]'),
('51d5147b-c37b-4783-bde5-3f789d8f9bfd','冬宵引贈司馬承禎','宋之問','唐','唐诗','tang','','[]','河有冰兮山有雪，北戶墐兮行人絕。',65,'全唐诗/poet.tang.3000.json','["河有冰兮山有雪，北戶墐兮行人絕。", "獨坐山中兮對松月，懷美人兮屢盈缺。", "明月的的寒潭中，青松幽幽吟勁風。", "此情不向俗人說，愛而不見恨無窮。"]'),
('194fb28b-2216-41fc-8037-9fface1d9dad','高山引','宋之問','唐','唐诗','tang','','[]','攀雲窈窕兮上躋懸峰，長路浩浩兮此去何從。',82,'全唐诗/poet.tang.3000.json','["攀雲窈窕兮上躋懸峰，長路浩浩兮此去何從。", "水一曲兮腸一曲，山一重兮悲一重。", "松檟邈已遠，友于何日逢？", "況滿室兮童稚，攢衆慮於心胷。", "天高難訴兮遠負明德，却望咸京兮揮涕龍鍾。"]'),
('a6fc5b12-6130-47da-8aea-c3778a946943','嵩山天門歌','宋之問','唐','唐诗','tang','','[]','登天門兮坐盤石之磷𥒘，前漎漎兮未半，下漠漠兮無垠。',143,'全唐诗/poet.tang.3000.json','["登天門兮坐盤石之磷𥒘，前漎漎兮未半，下漠漠兮無垠。", "紛窈窕兮巖倚披以鵬翅，洞膠葛兮峰稜層以龍鱗。", "松移岫轉，左變而右易。", "風生雲起，出鬼而入神。", "吾亦不知其靈怪如此，願遊杳冥兮見羽人。", "重曰：天門兮穹崇，回合兮攢藂。", "松萬接兮柱日，石千尋兮倚空。", "晚陰兮足風，夕陽兮赩紅。", "試一望兮奪魄，況衆妙之無窮。"]'),
('0f8a36f2-88f3-48f8-97aa-8b65bbfc105e','有所思','宋之問','唐','唐诗','tang','','["\u9752\u6625", "\u82b1", "\u5199\u82b1", "\u76f8\u548c\u6b4c\u8f9e", "\u611f\u4f24"]','洛陽城東桃李花，飛來飛去落誰家。',208,'全唐诗/poet.tang.3000.json','["洛陽城東桃李花，飛來飛去落誰家。", "幽閨女兒惜顏色，坐見落花長歎息。", "今年花落顏色改，明年花開復誰在。", "已見松柏摧爲薪，更聞桑田變成海。", "古人無復洛城東，今人還對落花風。", "年年歲歲花相似，歲歲年年人不同。", "寄言全盛紅顏子，須憐半死白頭翁。", "此翁白頭真可憐，伊昔紅顏美少年。", "公子王孫芳樹下，清歌妙舞落花前。", "光祿池臺交錦繡，將軍樓閣畫神仙。", "一朝臥病無相識，三春行樂在誰邊。", "婉轉蛾眉能幾時，須臾鶴髮亂如絲。", "但看古來歌舞地，唯有黃昏鳥雀飛。"]'),
('e2e43fa5-5665-42f4-95ca-2d4f1c795a60','奉和立春日侍宴內出剪綵花應制','宋之問','唐','唐诗','tang','','[]','金閣粧新杏，瓊筵弄綺梅。',48,'全唐诗/poet.tang.3000.json','["金閣粧新杏，瓊筵弄綺梅。", "人間都未識，天上忽先開。", "蜨繞香絲住，蜂憐豔粉迴。", "今年春色早，應爲剪刀催。"]'),
('1622e79d-fde5-47d9-9916-82248fd23aee','春日芙蓉園侍宴應制','宋之問','唐','唐诗','tang','','[]','芙蓉秦地沼，盧橘漢家園。',48,'全唐诗/poet.tang.3000.json','["芙蓉秦地沼，盧橘漢家園。", "谷轉斜盤徑，川迴曲抱原。", "風來花自舞，春入鳥能言。", "侍宴瑤池夕，歸途笳吹繁。"]'),
('a5de475d-f8b1-4e54-9512-b5b9ad65e847','夏日仙蕚亭應制','宋之問','唐','唐诗','tang','','[]','高嶺逼星河，乘輿此日過。',48,'全唐诗/poet.tang.3000.json','["高嶺逼星河，乘輿此日過。", "野含時雨潤，山雜夏雲多。", "睿藻光巖穴，宸襟洽薜蘿。", "悠然小天下，歸路滿笙歌。"]'),
('70b4c979-d04e-4ab6-9864-803912a47060','奉和九月九日登慈恩寺浮屠應制','宋之問','唐','唐诗','tang','','[]','鳳剎侵雲半，虹旌倚日邊。',48,'全唐诗/poet.tang.3000.json','["鳳剎侵雲半，虹旌倚日邊。", "散花多寶塔，張樂布金田。", "時菊芳仙醞，秋蘭動睿篇。", "香街稍欲晚，清蹕扈歸天。"]'),
('436fd69c-b5f2-4379-88f8-27f2760cc23f','奉和九日幸臨渭亭登高應制得歡字','宋之問','唐','唐诗','tang','','[]','令節三秋晚，重陽九日歡。',48,'全唐诗/poet.tang.3000.json','["令節三秋晚，重陽九日歡。", "仙杯還泛菊，寶饌且調蘭。", "御氣雲霄近，乘高宇宙寬。", "今朝萬壽引，宜向曲中彈。"]'),
('e4dbc821-c5cf-48b3-ae56-48e9802c8790','奉和聖製閏九月九日登莊嚴總持二寺閣','宋之問','唐','唐诗','tang','','[]','閏月再重陽，仙輿歷寶坊。',48,'全唐诗/poet.tang.3000.json','["閏月再重陽，仙輿歷寶坊。", "帝歌雲稍白，御酒菊猶黃。", "風鐸喧行漏，天花拂舞行。", "豫游多景福，梵宇日生光。"]'),
('ed648402-a60f-4fcd-ba82-1c24e5540526','麟趾殿侍宴應制','宋之問','唐','唐诗','tang','','[]','北闕層城峻，西宮複道懸。',48,'全唐诗/poet.tang.3000.json','["北闕層城峻，西宮複道懸。", "乘輿歷萬戶，置酒望三川。", "花柳含丹日，山河入綺筵。", "欲知陪賞處，空外有飛煙。"]'),
('1fce09c9-08e4-4085-a0ac-8630f9802840','上陽宮侍宴應制得林字','宋之問','唐','唐诗','tang','','[]','廣樂張前殿，重裘感聖心。',48,'全唐诗/poet.tang.3000.json','["廣樂張前殿，重裘感聖心。", "砌蓂霜月盡，庭樹雪雲深。", "舊渥驂宸御，慈恩忝翰林。", "微臣一何幸，再得聽瑤琴。"]'),
('f8287884-50b0-43a2-a1b5-2543b190be9b','幸少林寺應制','宋之問','唐','唐诗','tang','','[]','紺宇橫天室，回鑾指帝休。',48,'全唐诗/poet.tang.3000.json','["紺宇橫天室，回鑾指帝休。", "曙陰迎日盡，春氣抱巖流。", "空樂繁行漏，香煙薄綵斿。", "玉膏從此泛，仙馭接浮丘。"]'),
('967a5bb8-16ac-4f3b-9231-23dcf2b191ac','幸嶽寺應制','宋之問','唐','唐诗','tang','','[]','蹔幸珠筵地，俱憐石瀨清。',48,'全唐诗/poet.tang.3000.json','["蹔幸珠筵地，俱憐石瀨清。", "泛流張翠幕，拂迥挂紅旌。", "雅曲龍調管，芳樽蟻汎觥。", "陪歡玉座晚，復得聽金聲。"]'),
('be7c4b8a-03e9-497c-9aab-7f53c3d9a404','扈從登封途中作','宋之問','唐','唐诗','tang','','[]','帳殿鬱崔嵬，仙遊實壯哉。',48,'全唐诗/poet.tang.3000.json','["帳殿鬱崔嵬，仙遊實壯哉。", "曉雲連幕捲，夜火雜星回。", "谷暗千旗出，山鳴萬乘來。", "扈從良可賦，終乏掞天才。"]'),
('67e07351-19eb-497e-ba4f-e0aa6968643c','扈從登封告成頌','宋之問','唐','唐诗','tang','','[]','複道開行殿，鉤陳列禁兵。',48,'全唐诗/poet.tang.3000.json','["複道開行殿，鉤陳列禁兵。", "和風吹鼓角，佳氣動旗旌。", "後騎迴天苑，前山入御營。", "萬方俱下拜，相與樂昇平。"]'),
('ea4a6624-3ca5-4f9d-8fbc-e4c5403ae805','松山嶺應制','宋之問','唐','唐诗','tang','','[]','翼翼高旌轉，鏘鏘鳳輦飛。',48,'全唐诗/poet.tang.3000.json','["翼翼高旌轉，鏘鏘鳳輦飛。", "塵銷清蹕路，雲濕從臣衣。", "白羽搖丹壑，天營逼翠微。", "芳聲耀今古，四海警宸威。"]'),
('0e4779b1-ff20-449b-bcb1-57d694326eea','緱山廟','宋之問','唐','唐诗','tang','','[]','王子賓仙去，飄颻笙鶴飛。',48,'全唐诗/poet.tang.3000.json','["王子賓仙去，飄颻笙鶴飛。", "徒聞滄海變，不見白雲歸。", "天路何其遠，人間此會稀。", "空歌日云暮，霜月漸微微。"]'),
('6c7a9c71-12a1-456a-aa49-aa8f149a3fec','奉和梁王宴龍泓應教得微字','宋之問','唐','唐诗','tang','','[]','水府淪幽壑，星軺下紫微。',48,'全唐诗/poet.tang.3000.json','["水府淪幽壑，星軺下紫微。", "鳥驚司僕馭，花落侍臣衣。", "芳樹搖春晚，晴雲繞座飛。", "淮王正留客，不醉莫言歸。"]'),
('7facafd1-7f08-4266-804f-7c80bbc47c46','壽陽王花燭圖','宋之問','唐','唐诗','tang','','[]','仙媛乘龍日，天孫捧雁來。',48,'全唐诗/poet.tang.3000.json','["仙媛乘龍日，天孫捧雁來。", "可憐桃李樹，更繞鳳皇臺。", "燭照香車入，花臨寶扇開。", "莫令銀箭曉，爲盡合歡杯。"]'),
('f3d6c397-167e-4480-866e-9b9de38718b8','江南曲','宋之問','唐','唐诗','tang','','[]','妾住越城南，離居不自堪。',48,'全唐诗/poet.tang.3000.json','["妾住越城南，離居不自堪。", "採花驚曙鳥，摘葉餧春蠶。", "懶結茱萸帶，愁安玳瑁簪。", "待君消瘦盡，日暮碧江潭。"]'),
('4689980b-6899-45b8-acfe-a7b2d0d4b083','牛女','宋之問','唐','唐诗','tang','','[]','粉席秋期緩，針樓別怨多。',48,'全唐诗/poet.tang.3000.json','["粉席秋期緩，針樓別怨多。", "奔龍爭渡月，飛鵲亂填河。", "失喜先臨鏡，含羞未解羅。", "誰能留夜色，來夕倍還梭。"]'),
('1b58f52a-47e4-42b2-b905-ebdc6de1cfad','冬夜寓直麟閣','宋之問','唐','唐诗','tang','','[]','直事披三省，重關閉七門。',48,'全唐诗/poet.tang.3000.json','["直事披三省，重關閉七門。", "廣庭憐雪淨，深屋喜爐溫。", "月幌花虛馥，風窗竹暗喧。", "東山白雲意，茲夕寄琴尊。"]'),
('f3891415-5171-4bd2-bd89-98a91e0d5e1e','登禪定寺閣','宋之問','唐','唐诗','tang','','[]','梵宇出三天，登臨望八川。',48,'全唐诗/poet.tang.3000.json','["梵宇出三天，登臨望八川。", "開襟坐霄漢，揮手拂雲煙。", "函谷青山外，昆池落日邊。", "東京楊柳陌，少別已經年。"]'),
('6ccbc19a-f663-44cd-869d-26da42ed7e5d','陸渾山莊','宋之問','唐','唐诗','tang','','["\u53d9\u4e8b", "\u5c71\u6c34", "\u7530\u56ed", "\u6292\u60c5"]','歸來物外情，負杖閱巖耕。',48,'全唐诗/poet.tang.3000.json','["歸來物外情，負杖閱巖耕。", "源水看花入，幽林採藥行。", "野人相問姓，山鳥自呼名。", "去去獨吾樂，無然愧此生。"]'),
('09f6b283-4c4b-4475-a60e-e6ffc774b9f0','藍田山莊','宋之問','唐','唐诗','tang','','[]','宦遊非吏隱，心事好幽偏。',48,'全唐诗/poet.tang.3000.json','["宦遊非吏隱，心事好幽偏。", "考室先依地，爲農且用天。", "輞川朝伐木，藍水暮澆田。", "獨與秦山老，相歡春酒前。"]'),
('c6d18c25-f490-438b-9860-e4f4b51d7509','春日山家','宋之問','唐','唐诗','tang','','[]','今日遊何處？春泉洗藥歸。',48,'全唐诗/poet.tang.3000.json','["今日遊何處？春泉洗藥歸。", "悠然紫芝曲，晝掩白雲扉。", "魚樂偏尋藻，人閑屢采薇。", "丘中無俗事，身世兩相違。"]'),
('b820d946-e56f-4f18-b95f-184e5cf4e616','春日宴宋主簿山亭得寒字','宋之問','唐','唐诗','tang','','[]','公子正邀歡，林亭春未蘭。',48,'全唐诗/poet.tang.3000.json','["公子正邀歡，林亭春未蘭。", "攀巖踐苔易，迷路出花難。", "窗覆垂楊煖，階侵瀑水寒。", "帝城歸路直，留興接鵷鸞。"]'),
('42940601-e7b6-44ef-8688-0cf49f1c0565','江亭晚望','宋之問','唐','唐诗','tang','','[]','浩渺浸雲根，煙嵐出遠村。',48,'全唐诗/poet.tang.3000.json','["浩渺浸雲根，煙嵐出遠村。", "鳥歸沙有跡，帆過浪無痕。", "望水知柔性，看山欲斷魂。", "縱情猶未已，回馬欲黃昏。"]'),
('20d53bba-a655-41a1-a9d8-c52e2e417d95','秋晚遊普耀寺','宋之問','唐','唐诗','tang','','[]','薄暮曲江頭，仁祠暫可留。',48,'全唐诗/poet.tang.3000.json','["薄暮曲江頭，仁祠暫可留。", "山形無隱霽，野色徧呈秋。", "荷覆香泉密，藤緣寶樹幽。", "平生厭塵事，過此忽悠悠。"]'),
('cb166eef-8ef1-4fc4-9851-c75db2c971b7','答李司戶夔','宋之問','唐','唐诗','tang','','[]','遠方來下客，輶軒攝使臣。',48,'全唐诗/poet.tang.3000.json','["遠方來下客，輶軒攝使臣。", "弄琴宜在夜，傾酒貴逢春。", "駟馬留孤館，雙魚贈故人。", "明朝散雲雨，遙仰德爲鄰。"]'),
('eb5b3ef0-e039-497f-92c1-4e879dc811e8','寄天台司馬道士','宋之問','唐','唐诗','tang','','[]','臥來生白髮，覽鏡忽成絲。',48,'全唐诗/poet.tang.3000.json','["臥來生白髮，覽鏡忽成絲。", "遠愧餐霞子，童顏且自持。", "舊遊惜疎曠，微尚日磷緇。", "不寄西山藥，何由東海期。"]'),
('e4e68a12-9696-4581-8dd6-9403335b7311','使往天平軍馬約與陳子昂新鄉爲期及還而不相遇','宋之問','唐','唐诗','tang','','[]','入衞期之子，吁嗟不少留。',48,'全唐诗/poet.tang.3000.json','["入衞期之子，吁嗟不少留。", "情人去何處？淇水日悠悠。", "恆碣青雲斷，衡漳白露秋。", "知君心許國，不是愛封侯。"]'),
('4f7b1259-d384-4bc1-a9e8-d07f52fc20e1','過函谷關','宋之問','唐','唐诗','tang','','[]','二百四十載，海內何紛紛。',48,'全唐诗/poet.tang.3000.json','["二百四十載，海內何紛紛。", "六國兵同合，七雄勢未分。", "從成拒秦帝，策決問蘇君。", "雞鳴將狗盜，論德不論勳。"]'),
('64380cdd-355f-4278-bca5-bcb1eef4e7e1','送朔方何侍郎','宋之問','唐','唐诗','tang','','[]','聞道雲中使，乘驄往復還。',48,'全唐诗/poet.tang.3000.json','["聞道雲中使，乘驄往復還。", "河兵守陽月，塞虜失陰山。", "拜職嘗隨驃，銘功不讓班。", "旋聞受降日，歌舞入蕭關。"]'),
('7164e6c5-eac7-498b-ba14-2a47abe083bb','送田道士使蜀投龍','宋之問','唐','唐诗','tang','','[]','風馭忽泠然，雲臺路幾千。',48,'全唐诗/poet.tang.3000.json','["風馭忽泠然，雲臺路幾千。", "蜀門峯勢斷，巴字水形連。", "人隔壺中地，龍遊洞裏天。", "贈言回馭日，圖畫彼山川。"]'),
('5a10ca3c-7c87-4513-b60b-281d18679845','送許州宋司馬赴任','宋之問','唐','唐诗','tang','','[]','潁郡水東流，荀陳兄弟遊。',48,'全唐诗/poet.tang.3000.json','["潁郡水東流，荀陳兄弟遊。", "偏傷茲日遠，獨向聚星州。", "河潤在明德，人康非外求。", "當聞力爲政，遙慰我心愁。"]'),
('96ee267a-9668-407f-8d84-6d3adeb5dff4','送趙司馬赴蜀州','宋之問','唐','唐诗','tang','','[]','餞子西南望，煙緜劒道微。',48,'全唐诗/poet.tang.3000.json','["餞子西南望，煙緜劒道微。", "橋寒金雁落，林曙碧雞飛。", "職拜輿方遠，仙成履會歸。", "定知和氏璧，遙掩玉輪輝。"]'),
('2bb21ead-7093-4ad9-8b3c-380421b7c337','送永昌蕭贊府','宋之問','唐','唐诗','tang','','[]','柳變曲江頭，送君函谷遊。',48,'全唐诗/poet.tang.3000.json','["柳變曲江頭，送君函谷遊。", "弄琴寬別意，酌醴醉春愁。", "戀本亦何極，贈言微所求。", "莫令金谷水，不入故園流。"]'),
('63293760-017c-4a71-9c72-dd734cfb22d5','送李侍御','宋之問','唐','唐诗','tang','','[]','行李戀庭闈，乘軺振綵衣。',48,'全唐诗/poet.tang.3000.json','["行李戀庭闈，乘軺振綵衣。", "南登指吳服，北走出秦畿。", "去國夏雲斷，還鄉秋雁飛。", "旋聞郡計入，更有使臣歸。"]'),
('af031885-268c-478a-93ec-fdb2c98bf6c3','餞湖州薛司馬','宋之問','唐','唐诗','tang','','[]','別駕促嚴程，離筵多故情。',48,'全唐诗/poet.tang.3000.json','["別駕促嚴程，離筵多故情。", "交深季作友，義重伯爲兄。", "鎮靜移吳俗，風流在漢京。", "會看陳仲舉，從此拜公卿。"]'),
('5dec8ec2-83f7-4f0e-b7f7-b63f3b1b621e','送杜審言','宋之問','唐','唐诗','tang','','[]','臥病人事絕，嗟君萬里行。',48,'全唐诗/poet.tang.3000.json','["臥病人事絕，嗟君萬里行。", "河橋不相送，江樹遠含情。", "別路追孫楚，維舟弔屈平。", "可惜龍泉劒，流落在豐城。"]'),
('1dccc6bb-e80c-4653-ba3c-03a07f4a2192','送武進鄭明府','宋之問','唐','唐诗','tang','','[]','弦歌試宰日，城闕賞心違。',48,'全唐诗/poet.tang.3000.json','["弦歌試宰日，城闕賞心違。", "北謝蒼龍去，南隨黃鵠飛。", "夏雲海中出，吳山江上微。", "甿謠豈云遠，從此慶緇衣。"]'),
('ec844021-ff60-446a-95b6-fd5eb7be28c8','送姚侍御出使江東','宋之問','唐','唐诗','tang','','[]','帝憂河朔郡，南發海陵倉。',48,'全唐诗/poet.tang.3000.json','["帝憂河朔郡，南發海陵倉。", "坐歎青春別，逶迤碧水長。", "飲冰朝受命，衣錦晝還鄉。", "爲問東山桂，無人何自芳。"]'),
('2c93605d-078d-4777-9ebf-b074a29fc678','留別之望舍弟','宋之問','唐','唐诗','tang','','[]','同氣有三人，分飛在此晨。',48,'全唐诗/poet.tang.3000.json','["同氣有三人，分飛在此晨。", "西馳巴嶺徼，東去洛陽濱。", "強飲離前酒，終傷別後神。", "誰憐散花蕚，獨赴日南春。"]'),
('d4c29355-b4e5-47b0-97bc-9a45419e7591','漢江宴別','宋之問','唐','唐诗','tang','','[]','漢廣不分天，舟移杳若仙。',48,'全唐诗/poet.tang.3000.json','["漢廣不分天，舟移杳若仙。", "秋虹暎晚日，江鶴弄晴煙。", "積水浮冠蓋，遙風逐管弦。", "嬉遊不可極，留恨此山川。"]'),
('2d4df854-57d4-4514-b9d5-3adeec13e351','初發荆府贈長史','宋之問','唐','唐诗','tang','','[]','□□□□□，□□□□□。',48,'全唐诗/poet.tang.3000.json','["□□□□□，□□□□□。", "仍隨五馬謫，載與兩禽奔。", "明主無由見，羣公莫與言。", "幸君逢聖日，何惜理虞翻。"]'),
('c9b9b9c3-84b7-4066-a538-4c176a0a523c','晚泊湘江','宋之問','唐','唐诗','tang','','["\u8861\u5c71"]','五嶺恓惶客，三湘顦顇顏。',48,'全唐诗/poet.tang.3000.json','["五嶺恓惶客，三湘顦顇顏。", "況復秋雨霽，表裏見衡山。", "路逐鵬南轉，心依雁北還。", "唯餘望鄉淚，更染竹成斑。"]'),
('6d31dc2b-0af9-47e1-a9da-50b80681cf53','過蠻洞','宋之問','唐','唐诗','tang','','[]','越嶺千重合，蠻谿十里斜。',48,'全唐诗/poet.tang.3000.json','["越嶺千重合，蠻谿十里斜。", "竹迷樵子徑，萍匝釣人家。", "林暗交楓葉，園香覆橘花。", "誰憐在荒外，孤賞足雲霞。"]'),
('723497ef-1a08-4a80-8926-91f3c9896376','經梧州','宋之問','唐','唐诗','tang','','["\u6292\u60c5"]','南國無霜霰，連年見物華。',48,'全唐诗/poet.tang.3000.json','["南國無霜霰，連年見物華。", "青林暗換葉，紅橤續開花。", "春去聞山鳥，秋來見海槎。", "流芳雖可悅，會自泣長沙。"]'),
('144a86f2-cd0d-4a70-9d00-3251df8cd5c8','渡吳江別王長史','宋之問','唐','唐诗','tang','','[]','倚櫂望茲川，銷魂獨黯然。',48,'全唐诗/poet.tang.3000.json','["倚櫂望茲川，銷魂獨黯然。", "鄉連江北樹，雲斷日南天。", "劒別龍初沒，書成雁不傳。", "離舟意無限，催渡復催年。"]'),
('d8bd0fc6-9b38-4570-afcf-e53bc85d4c8e','泛鏡湖南溪','宋之問','唐','唐诗','tang','','[]','乘興入幽棲，舟行日向低。',48,'全唐诗/poet.tang.3000.json','["乘興入幽棲，舟行日向低。", "巖花候冬發，谷鳥作春啼。", "沓嶂開天小，叢篁夾路迷。", "猶聞可憐處，更在若邪溪。"]'),
('46be27ea-afe5-4078-9175-59213f05ab5b','途中寒食題黃梅臨江驛寄崔融','宋之問','唐','唐诗','tang','','["\u6e05\u660e", "\u601d\u4e61", "\u5bd2\u98df\u8282"]','馬上逢寒食，愁中屬暮春。',48,'全唐诗/poet.tang.3000.json','["馬上逢寒食，愁中屬暮春。", "可憐江浦望，不見洛陽人。", "北極懷明主，南溟作逐臣。", "故園腸斷處，日夜柳條新。"]'),
('b5648eda-d6c5-420f-bda0-fec6e15867da','遊韶州廣界寺','宋之問','唐','唐诗','tang','','[]','影殿臨丹壑，香臺隱翠霞。',48,'全唐诗/poet.tang.3000.json','["影殿臨丹壑，香臺隱翠霞。", "巢飛銜象鳥，砌蹋雨空花。", "寶鐸搖初霽，金池暎晚沙。", "莫愁歸路遠，門外有三車。"]'),
('f14c55be-50b1-41b1-8063-51d1be9ae5bb','宿清遠峽山寺','宋之問','唐','唐诗','tang','','[]','香岫懸金剎，飛泉屆石門。',48,'全唐诗/poet.tang.3000.json','["香岫懸金剎，飛泉屆石門。", "空山唯習靜，中夜寂無喧。", "說法初聞鳥，看心欲定猿。", "寥寥隔塵市，何異武陵源。"]'),
('058db0d1-0656-4e8f-ac49-87622e16b19b','題大庾嶺北驛','宋之問','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7", "\u601d\u4e61", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','陽月南飛雁，傳聞至此回。',48,'全唐诗/poet.tang.3000.json','["陽月南飛雁，傳聞至此回。", "我行殊未已，何日復歸來？", "江靜潮初落，林昏瘴不開。", "明朝望鄉處，應見隴頭梅。"]'),
('f0001725-2228-45b4-bc4c-76fa5b455343','度大庾嶺','宋之問','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','度嶺方辭國，停軺一望家。',48,'全唐诗/poet.tang.3000.json','["度嶺方辭國，停軺一望家。", "魂隨南翥鳥，淚盡北枝花。", "山雨初含霽，江雲欲變霞。", "但令歸有日，不敢恨長沙。"]'),
('721463b7-2205-4306-b3e7-70f2b06631b9','端州別袁侍郎','宋之問','唐','唐诗','tang','','[]','合浦途未極，端溪行蹔臨。',48,'全唐诗/poet.tang.3000.json','["合浦途未極，端溪行蹔臨。", "淚來空泣臉，愁至不知心。", "客醉山月靜，猿啼江樹深。", "明朝共分手，之子愛千金。"]'),
('504ce895-589e-4db8-bb0a-9bab24f22d5b','過史正議宅','宋之問','唐','唐诗','tang','','[]','舊交此零落，雨泣訪遺塵。',48,'全唐诗/poet.tang.3000.json','["舊交此零落，雨泣訪遺塵。", "劒几傳好事，池臺傷故人。", "國香蘭已歇，里樹橘猶新。", "不見吳中隱，空餘江海濱。"]'),
('9dea4fd2-95e6-429f-941d-60f955b76718','梁宣王挽詞三首 一','宋之問','唐','唐诗','tang','','[]','貴藩堯母族，外戚漢家親。',48,'全唐诗/poet.tang.3000.json','["貴藩堯母族，外戚漢家親。", "業重興王際，功高復辟辰。", "愛賢唯報國，樂善不防身。", "今日衣冠送，空傷置醴人。"]'),
('e260f448-425a-4c27-a97c-ec17228abb30','梁宣王挽詞三首 二','宋之問','唐','唐诗','tang','','[]','金精何日閉，玉匣此時開。',48,'全唐诗/poet.tang.3000.json','["金精何日閉，玉匣此時開。", "東望連吾子，南瞻近帝臺。", "地形龜食報，墳土燕銜來。", "可歎虞歌夕，紛紛騎吹回。"]'),
('a98a3aae-1958-4833-86cb-2dda74da2773','梁宣王挽詞三首 三','宋之問','唐','唐诗','tang','','[]','像設千年在，平生萬事違。',36,'全唐诗/poet.tang.3000.json','["像設千年在，平生萬事違。", "綵旌翻葆吹，圭翣奠靈衣。", "壠日寒無影，郊雲凍不飛。"]'),
('949ae54d-39d8-4173-a4b2-343a9e6762ea','魯忠王挽詞三首 一','宋之問','唐','唐诗','tang','','[]','同盟會五月，歸葬出三條。',48,'全唐诗/poet.tang.3000.json','["同盟會五月，歸葬出三條。", "日慘咸陽樹，天寒渭水橋。", "稍看朱鷺轉，尚識紫騮驕。", "寂寂泉臺恨，從茲罷玉簫。"]'),
('591221b5-0dae-410b-9722-559443a166f2','魯忠王挽詞三首 二','宋之問','唐','唐诗','tang','','[]','邦家錫寵光，存沒貴忠良。',48,'全唐诗/poet.tang.3000.json','["邦家錫寵光，存沒貴忠良。", "遂裂山河地，追尊父子王。", "人悲槐里月，馬踏槿原霜。", "別向天京北，悠悠此路長。"]'),
('7ef415ed-3b5c-4217-9488-d20fc5aba38c','魯忠王挽詞三首 三','宋之問','唐','唐诗','tang','','[]','樹羽迎朝日，撞鐘望早霞。',48,'全唐诗/poet.tang.3000.json','["樹羽迎朝日，撞鐘望早霞。", "故人悲宿草，中使慘晨笳。", "氣有衝天劒，星無犯斗槎。", "唯餘孔公宅，長接魯王家。"]'),
('170bac88-fa66-4c49-ba43-3340921c913a','范陽王挽詞二首 一','宋之問','唐','唐诗','tang','','[]','賢相稱邦傑，清流舉代推。',48,'全唐诗/poet.tang.3000.json','["賢相稱邦傑，清流舉代推。", "公才掩諸夏，文體變當時。", "賓弔飜成鶴，人亡惜喻龜。", "洛陽今紙貴，猶寫太沖詞。"]'),
('b7d0d1dc-d225-45df-a916-e828ca37b79b','范陽王挽詞二首 二','宋之問','唐','唐诗','tang','','[]','贈秩徽章洽，求書秘草成。',48,'全唐诗/poet.tang.3000.json','["贈秩徽章洽，求書秘草成。", "客隨朝露盡，人逐夜舟驚。", "蒿里衣冠送，松門印綬迎。", "誰知楊伯起，今日重哀榮。"]'),
('69a7243f-3024-4922-98df-5841f56d6492','故趙王屬贈黃門侍郎上官公挽詞二首 一','宋之問','唐','唐诗','tang','','[]','韋門旌舊德，班氏業前書。',48,'全唐诗/poet.tang.3000.json','["韋門旌舊德，班氏業前書。", "謫去因丞相，歸來爲倢伃。", "周原烏相冢，越嶺雁隨車。", "冥漠辭昭代，空憐賦子虛。"]'),
('a6521193-75a6-4aaa-979e-82d7b3b13b6c','故趙王屬贈黃門侍郎上官公挽詞二首 二','宋之問','唐','唐诗','tang','','[]','綠車隨帝子，青瑣翊宸機。',48,'全唐诗/poet.tang.3000.json','["綠車隨帝子，青瑣翊宸機。", "昔枉朝歌騎，今虛夕拜闈。", "柳河悽挽曲，薤露濕靈衣。", "一厝窮泉閉，雙鸞遂不飛。"]'),
('1e4b4de9-1907-47f6-8ed8-3bba7bfc0a0c','藥','宋之問','唐','唐诗','tang','','[]','有卉祕神仙，君臣有禮焉。',48,'全唐诗/poet.tang.3000.json','["有卉祕神仙，君臣有禮焉。", "忻當苦口喻，不畏入腸偏。", "扁鵲功成日，神農定品年。", "丹成如可待，雞犬自聞天。"]'),
('7598f03c-92f0-43be-b9c7-7b414e5fd8aa','奉和九日登慈恩寺浮圖應制','宋之問','唐','唐诗','tang','','[]','瑞塔千尋起，仙輿九日來。',48,'全唐诗/poet.tang.3000.json','["瑞塔千尋起，仙輿九日來。", "萸房陳寶席，菊蘂散花臺。", "御氣鵬霄近，升高鳳野開。", "天歌將梵樂，空裏共裴回。"]'),
('3aa59244-2813-4551-9b1c-8e1d91b6831a','送沙門泓景道俊玄奘還荆州應制','宋之問','唐','唐诗','tang','','[]','三乘歸淨域，萬騎餞通莊。',48,'全唐诗/poet.tang.3000.json','["三乘歸淨域，萬騎餞通莊。", "就日離亭近，彌天別路長。", "荆南旋杖鉢，渭北限津梁。", "何日紆真果，還來入帝鄉。"]'),
('b27ab759-00d1-4e35-9bf5-f3860ccf873a','春日芙蓉園侍宴應制','宋之問','唐','唐诗','tang','','[]','年光竹裏遍，春色杏間遙。',48,'全唐诗/poet.tang.3000.json','["年光竹裏遍，春色杏間遙。", "煙氣籠青閣，流文蕩畫橋。", "飛花隨蝶舞，豔曲伴鶯嬌。", "今日陪歡豫，還疑陟紫霄。"]'),
('68377b20-f212-43eb-a581-dad642b27e92','詠笛','宋之問','唐','唐诗','tang','','[]','羌笛寫龍聲，長吟入夜清。',48,'全唐诗/poet.tang.3000.json','["羌笛寫龍聲，長吟入夜清。", "關山孤月下，來向隴頭鳴。", "逐吹梅花落，含春柳色驚。", "行觀向子賦，坐憶舊鄰情。"]'),
('d0821bd3-bae4-4693-824c-ca974c31da07','詠鍾','宋之問','唐','唐诗','tang','','[]','既接南鄰磬，還隨北里笙。',48,'全唐诗/poet.tang.3000.json','["既接南鄰磬，還隨北里笙。", "平陵通曙響，長樂警宵聲。", "秋至含霜動，春歸應律鳴。", "豈惟恆待扣，金簴有餘清。"]'),
('cf845483-2c08-46bf-94fb-3f3cd3263c52','花落','宋之問','唐','唐诗','tang','','[]','鐵騎幾時迴，金閨怨早梅。',48,'全唐诗/poet.tang.3000.json','["鐵騎幾時迴，金閨怨早梅。", "雪寒花已落，風暖葉還開。", "夕逐新春管，香迎小歲桮。", "盛時何足貴，書裏報輪臺。"]'),
('ccc02b26-b0d1-4081-b371-dd3391ba5e02','旅宿淮陽亭口號','宋之問','唐','唐诗','tang','','[]','日暮風亭上，悠悠旅思多。',48,'全唐诗/poet.tang.3000.json','["日暮風亭上，悠悠旅思多。", "故鄉臨桂水，今夜渺星河。", "暗草霜華發，空亭鴈影過。", "興來誰與語，勞者自爲歌。"]'),
('c2bbf7ba-9e76-40bf-b535-43306c88351b','內題賦得巫山雨','宋之問','唐','唐诗','tang','','[]','神女向高唐，巫山下夕陽。',48,'全唐诗/poet.tang.3000.json','["神女向高唐，巫山下夕陽。", "裴回作行雨，婉戀逐荆王。", "電影江前落，雷聲峽外長。", "霽雲無處所，臺館曉蒼蒼。"]'),
('60a6c06a-af0e-4b2a-96bf-3b8844b44b89','王昭君','宋之問','唐','唐诗','tang','','[]','非君惜鸞殿，非妾妬娥眉。',48,'全唐诗/poet.tang.3000.json','["非君惜鸞殿，非妾妬娥眉。", "薄命由驕虜，無情是畫師。", "嫁來胡地日，不竝漢宮時。", "辛苦無聊賴，何堪上馬辭。"]'),
('8f65e833-3266-42a2-9580-af89a6d1761d','銅雀臺','宋之問','唐','唐诗','tang','','[]','昔年分鼎地，今日望陵臺。',48,'全唐诗/poet.tang.3000.json','["昔年分鼎地，今日望陵臺。", "一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。", "恩共漳河水，東流無重回。"]'),
('331fa932-e09b-4c0f-b8f7-f4990a598879','巫山高','宋之問','唐','唐诗','tang','','[]','巫山峯十二，環合象昭回。',48,'全唐诗/poet.tang.3000.json','["巫山峯十二，環合象昭回。", "俯聽琵琶峽，平看雲雨臺。", "古槎天外落，瀑水日邊來。", "何忍猨啼夜，荆王枕席開。"]'),
('a0155d22-7644-4dcd-b67e-6739ccc389fb','望月有懷','宋之問','唐','唐诗','tang','','[]','天使下西樓，含光萬里秋。',48,'全唐诗/poet.tang.3000.json','["天使下西樓，含光萬里秋。", "臺前似挂鏡，簾外如懸鉤。", "張尹將眉學，班姬取扇儔。", "佳期應借問，爲報大刀頭。"]'),
('82741df3-0dde-45d4-8153-0c5ef638e018','駕出長安','宋之問','唐','唐诗','tang','','[]','聖德超千古，皇風扇九圍。',48,'全唐诗/poet.tang.3000.json','["聖德超千古，皇風扇九圍。", "天回萬象出，駕動六龍飛。", "淑氣來黃道，祥雲覆紫微。", "太平多扈從，文物有光輝。"]'),
('6bf379c1-d102-4d2b-bed6-52a2f2f60bba','餞中書侍郎來濟','宋之問','唐','唐诗','tang','','[]','曖曖去塵昏灞岸，飛飛輕蓋指河梁。',64,'全唐诗/poet.tang.3000.json','["曖曖去塵昏灞岸，飛飛輕蓋指河梁。", "雲峰衣結千重葉，雪岫花開幾樹粧。", "深悲黃鶴孤舟遠，獨對青山別路長。", "却將分手霑襟淚，還用持添離席觴。"]'),
('f7e86ab6-083e-441f-8713-f25a131941ce','奉和春初幸太平公主南莊應制','宋之問','唐','唐诗','tang','','[]','青門路接鳳凰臺，素滻宸遊龍騎來。',64,'全唐诗/poet.tang.3000.json','["青門路接鳳凰臺，素滻宸遊龍騎來。", "澗草自迎香輦合，巖花應待御筵開。", "文移北斗成天象，酒遞南山作壽杯。", "此日侍臣將石去，共歡明主賜金回。"]'),
('ff0bcc77-7bdf-46fc-905f-d6c6e940fc10','三陽宮侍宴應制得幽字','宋之問','唐','唐诗','tang','','[]','離宮祕苑勝瀛洲，別有仙人洞壑幽。',64,'全唐诗/poet.tang.3000.json','["離宮祕苑勝瀛洲，別有仙人洞壑幽。", "巖邊樹色含風冷，石上泉聲帶雨秋。", "鳥向歌筵來度曲，雲依帳殿結爲樓。", "微臣昔忝方明御，今日還陪八駿遊。"]'),
('f47be854-5b15-4b04-8021-3384b603b674','奉和晦日幸昆明池應制','宋之問','唐','唐诗','tang','','[]','春豫靈池會，滄波帳殿開。',72,'全唐诗/poet.tang.3000.json','["春豫靈池會，滄波帳殿開。", "舟淩石鯨度，槎拂斗牛回。", "節晦蓂全落，春遲柳暗催。", "象溟看浴景，燒劫辨沈灰。", "鎬飲周文樂，汾歌漢武才。", "不愁明月盡，自有夜珠來。"]'),
('a1624027-5337-4f85-b636-c28ea14deaf9','奉和幸大薦福寺','宋之問','唐','唐诗','tang','','[]','香剎中天起，宸遊滿路輝。',72,'全唐诗/poet.tang.3000.json','["香剎中天起，宸遊滿路輝。", "乘龍太子去，駕象法王歸。", "殿飾金人影，窗搖玉女扉。", "稍迷新草木，徧識舊庭闈。", "水入禪心定，雲從寶思飛。", "欲知皇劫遠，初拂六銖衣。"]'),
('7f786cb2-4edf-480e-850b-9b96e19561bc','奉和幸三會寺應制','宋之問','唐','唐诗','tang','','[]','六飛回玉輦，雙樹謁金仙。',72,'全唐诗/poet.tang.3000.json','["六飛回玉輦，雙樹謁金仙。", "瑞鳥呈書字，神龍吐浴泉。", "淨心遙證果，睿想獨超禪。", "塔湧香花地，山圍日月天。", "梵音迎漏徹，空樂倚雲懸。", "今日登仁壽，長看法鏡圓。"]'),
('08d49d18-7848-422a-8398-2843f565c485','奉和薦福寺應制','宋之問','唐','唐诗','tang','','[]','梵筵光聖邸，遊豫覽宏規。',72,'全唐诗/poet.tang.3000.json','["梵筵光聖邸，遊豫覽宏規。", "不改靈光殿，因開功德池。", "蓮生新步葉，桂長昔攀枝。", "湧塔庭中見，飛樓海上移。", "聞韶三月幸，觀象七星危。", "欲識龍歸處，朝朝雲氣隨。"]'),
('d7a40cbd-04ba-450f-a4a6-86d636082b37','奉和幸神皐亭應制','宋之問','唐','唐诗','tang','','[]','清蹕喧黃道，乘輿降紫宸。',72,'全唐诗/poet.tang.3000.json','["清蹕喧黃道，乘輿降紫宸。", "霜戈凝曉日，雲管發陽春。", "臺古全疑漢，林餘半識秦。", "宴酣詩布澤，節改令行仁。", "昔恃山河險，今依道德淳。", "多慙獻嘉頌，空累屬車塵。"]'),
('5cb0c7e7-99a7-4dad-9951-4f59b8ac2788','奉和幸長安故城未央宮應制','宋之問','唐','唐诗','tang','','[]','漢王未息戰，蕭相乃營宮。',72,'全唐诗/poet.tang.3000.json','["漢王未息戰，蕭相乃營宮。", "壯麗一朝盡，威靈千載空。", "皇明悵前跡，置酒宴羣公。", "寒輕綵仗外，春發幔城中。", "樂思回斜日，歌詞繼大風。", "今朝天子貴，不假叔孫通。"]'),
('adc370a5-b867-48e8-81a4-7994da5e9289','奉和幸韋嗣立山莊侍宴應制','宋之問','唐','唐诗','tang','','[]','樞掖調梅暇，林園藝槿初。',96,'全唐诗/poet.tang.3000.json','["樞掖調梅暇，林園藝槿初。", "入朝榮劒履，退食偶琴書。", "地隱東巖室，天回北斗車。", "旌門臨䆗窱，輦道屬扶疎。", "雲罕明丹壑，霜笳徹紫虛。", "水疑投石處，溪似釣璜餘。", "帝澤頒巵酒，人歡頌里閭。", "一承黃竹詠，長奉白茅居。"]'),
('e7e2540d-854b-4a0d-b7ec-6da22051d035','扈從登封告成頌應制','宋之問','唐','唐诗','tang','','[]','御路回中嶽，天營接下都。',96,'全唐诗/poet.tang.3000.json','["御路回中嶽，天營接下都。", "百靈無後至，萬國競前驅。", "文衞嚴清蹕，幽仙讀寶符。", "貝花明漢果，芝草入堯廚。", "濟濟衣冠會，喧喧夷夏俱。", "宗禋仰神理，刊木望川途。", "撫己貧非病，時來本不愚。", "願陪丹鳳輦，率舞白雲衢。"]'),
('2a1446a8-3f7b-4a57-8a28-1d4b2e123f67','宴安樂公主宅得空字','宋之問','唐','唐诗','tang','','[]','英藩築外館，愛主出王宮。',72,'全唐诗/poet.tang.3000.json','["英藩築外館，愛主出王宮。", "賓至星槎落，仙來月宇空。", "玳梁飜賀燕，金埒倚晴虹。", "簫奏秦臺裏，書開魯壁中。", "短歌能駐日，豔舞欲嬌風。", "聞有淹留處，山阿滿桂叢。"]'),
('eb69c424-e7c9-402d-ae43-966443ddb04c','春日鄭協律山亭陪宴餞鄭卿同用樓字','宋之問','唐','唐诗','tang','','[]','潘園枕郊郭，愛客坐相求。',72,'全唐诗/poet.tang.3000.json','["潘園枕郊郭，愛客坐相求。", "尊酒東城外，驂騑南陌頭。", "池平分洛水，林缺見嵩丘。", "暗竹侵山徑，垂楊拂妓樓。", "彩雲歌處斷，遲日舞前留。", "此地何年別，蘭芳空自幽。"]'),
('fe8ef8a4-959c-444e-8e1b-91ea921ddc6d','和姚給事寓直之作','宋之問','唐','唐诗','tang','','[]','清論滿朝陽，高才拜夕郎。',96,'全唐诗/poet.tang.3000.json','["清論滿朝陽，高才拜夕郎。", "還從避馬路，來接珥貂行。", "寵就黃扉日，威回白簡霜。", "柏臺遷鳥茂，蘭署得人芳。", "禁靜鐘初徹，更疎漏漸長。", "曉河低武庫，流火度文昌。", "寓直恩徽重，乘秋藻翰揚。", "暗投空欲報，下調不成章。"]'),
('0abfe385-6758-41b6-802c-0f37a93a4d9d','和庫部李員外秋夜寓直之作','宋之問','唐','唐诗','tang','','[]','相庭貽慶遠，才子拜郎初。',72,'全唐诗/poet.tang.3000.json','["相庭貽慶遠，才子拜郎初。", "起草徯仙閣，焚香臥直廬。", "更深河欲斷，節勁柳偏疎。", "氣耿凌雲筆，心搖待漏車。", "叨榮廁儔侶，省己恧空虛。", "徒裴陽春和，難參麗曲餘。"]'),
('0df23099-5d0d-4d73-9ea7-5b74ac61b4c6','酬李丹徒見贈之作','宋之問','唐','唐诗','tang','','[]','鎮吳稱奧里，試劇仰通才。',84,'全唐诗/poet.tang.3000.json','["鎮吳稱奧里，試劇仰通才。", "近挹人披霧，遙聞境震雷。", "一朝逢解榻，累日共銜杯。", "連轡登山盡，浮舟望海回。", "以予慙拙宦，期子遇良媒。", "贈曲南鳧斷，征途北雁催。", "更憐江上月，還入鏡中開。"]'),
('007fb333-4320-469e-8def-1425e465a68a','使過襄陽登鳳林寺閣','宋之問','唐','唐诗','tang','','[]','香閣臨清漢，丹梯隱翠微。',72,'全唐诗/poet.tang.3000.json','["香閣臨清漢，丹梯隱翠微。", "林篁天際密，人世谷中違。", "苔石銜仙洞，蓮舟泊釣磯。", "山雲浮棟起，江雨入庭飛。", "信美雖南國，嚴程限北歸。", "幽尋不可再，留步惜芳菲。"]'),
('58ac7401-65a5-408c-ac4b-44facc8a0293','宋公宅送甯諫議','宋之問','唐','唐诗','tang','','[]','宋公爰創宅，庾氏更誅茅。',72,'全唐诗/poet.tang.3000.json','["宋公爰創宅，庾氏更誅茅。", "間出人三秀，平臨楚四郊。", "漢臣來絳節，荆牧動金鐃。", "尊溢宜城酒，笙裁曲沃匏。", "露荷秋變節，風柳夕鳴梢。", "一散陽臺雨，方隨越鳥巢。"]'),
('ce472cf0-c154-4f69-bf9a-2abb3e807187','送合宮蘇明府頲','宋之問','唐','唐诗','tang','','[]','鉉府誕英規，公才天下知。',72,'全唐诗/poet.tang.3000.json','["鉉府誕英規，公才天下知。", "謂乘羔雁族，繼入鳳皇池。", "赤縣求人隱，青門起路岐。", "翟回車少別，鳧化舃遙馳。", "神哭周南境，童歌渭北垂。", "賢哉荀奉倩，衮職佇來儀。"]'),
('9dfb4a49-d507-428d-84bd-ccfd35da8b71','送楊六望赴金水','宋之問','唐','唐诗','tang','','[]','借問梁山道，嶔岑幾萬重。',72,'全唐诗/poet.tang.3000.json','["借問梁山道，嶔岑幾萬重。", "遙州刀作字，絕壁劒爲峰。", "惜別路窮此，留歡意不從。", "憂來生白髮，時晚愛青松。", "勿以西南遠，夷歌寢盛容。", "台階有高位，寧復久臨邛。"]'),
('d42ffc26-f0f9-41af-bc33-17f5101a422a','下桂江龍目灘','宋之問','唐','唐诗','tang','','[]','停午出灘險，輕舟容易前。',72,'全唐诗/poet.tang.3000.json','["停午出灘險，輕舟容易前。", "峰攢入雲樹，崖噴落江泉。", "巨石潛山怪，深篁隱洞仙。", "鳥遊溪寂寂，猿嘯嶺娟娟。", "揮袂日凡幾，我行途已千。", "暝投蒼梧郡，愁枕白雲眠。"]'),
('b2aa9cb4-0de8-49ce-9a69-774afafb9f2f','入瀧州江','宋之問','唐','唐诗','tang','','[]','孤舟泛盈盈，江流日縱橫。',156,'全唐诗/poet.tang.3000.json','["孤舟泛盈盈，江流日縱橫。", "夜雜蛟螭寢，晨披瘴癘行。", "潭蒸水沫起，山熱火雲生。", "猿躩時能嘯，鳶飛莫敢鳴。", "海窮南徼盡，鄉遠北魂驚。", "泣向文身國，悲看鑿齒氓。", "地偏多育蠱，風惡好相鯨。", "余本巖栖客，悠哉慕玉京。", "厚恩嘗願答，薄宦不祈成。", "違隱乖求志，披荒爲近名。", "鏡愁玄髮改，心負紫芝榮。", "運啓中興曆，時逢外域清。", "祗應保忠信，延促付神明。"]'),
('d8cff809-a000-45fb-878d-f8af4206f684','始安秋日','宋之問','唐','唐诗','tang','','["\u79cb\u5929", "\u666f\u70b9"]','桂林風景異，秋似洛陽春。',60,'全唐诗/poet.tang.3000.json','["桂林風景異，秋似洛陽春。", "晚霽江天好，分明愁殺人。", "卷雲山𧥄𧥄，碎石水磷磷。", "世業事黃老，妙年孤隱淪。", "歸歟臥滄海，何物貴吾身。"]'),
('61b60386-1d8c-42ed-8bf2-e7d34ab67096','桂州黃潭舜祠','宋之問','唐','唐诗','tang','','[]','虞世巡百越，相傳葬九疑。',72,'全唐诗/poet.tang.3000.json','["虞世巡百越，相傳葬九疑。", "精靈遊此地，祠樹日光輝。", "禋祭忽羣望，丹青圖二妃。", "神來獸率舞，仙去鳳還飛。", "日暝山氣落，江空潭靄微。", "帝鄉三萬里，乘彼白雲歸。"]'),
('c5a66103-ad71-4bca-9224-d44b616630a0','登粵王臺','宋之問','唐','唐诗','tang','','[]','江上粵王臺，登高望幾回。',72,'全唐诗/poet.tang.3000.json','["江上粵王臺，登高望幾回。", "南溟天外合，北戶日邊開。", "地濕煙嘗起，山晴雨半來。", "冬花採盧橘，夏果摘楊梅。", "跡類虞翻枉，人非賈誼才。", "歸心不可見，白髮重相催。"]'),
('8aeca15b-2c27-4947-a57d-5daab2082d8a','早發始興江口至虛氏村作','宋之問','唐','唐诗','tang','','["\u6292\u60c5", "\u5f52\u9690", "\u5199\u666f"]','候曉踰閩嶠，乘春望越臺。',96,'全唐诗/poet.tang.3000.json','["候曉踰閩嶠，乘春望越臺。", "宿雲鵬際落，殘月蚌中開。", "薜荔搖青氣，桄榔翳碧苔。", "桂香多露裛，石響細泉回。", "抱葉玄猿嘯，銜花翡翠來。", "南中雖可悅，北思日悠哉。", "鬒髮俄成素，丹心已作灰。", "何當首歸路，行剪故園萊。"]'),
('67404753-0e0b-4556-bffa-7409521c6790','發藤州','宋之問','唐','唐诗','tang','','[]','朝夕苦遄征，孤魂長自驚。',120,'全唐诗/poet.tang.3000.json','["朝夕苦遄征，孤魂長自驚。", "泛舟依雁渚，投館聽猿鳴。", "石髮緣溪蔓，林衣埽地輕。", "雲峰刻不似，苔蘚畫難成。", "露裛千花氣，泉和萬籟聲。", "攀幽紅處歇，躋險綠中行。", "戀切芝蘭砌，悲纏松柏塋。", "丹心江北死，白髮嶺南生。", "魑魅天邊國，窮愁海上城。", "勞歌意無限，今日爲誰明。"]'),
('11ea7447-a550-497c-9fd5-549b11bdbf60','遊稱心寺','宋之問','唐','唐诗','tang','','[]','釋事懷三隱，清襟謁四禪。',96,'全唐诗/poet.tang.3000.json','["釋事懷三隱，清襟謁四禪。", "江鳴潮未落，林曉日初懸。", "寶葉交香雨，金沙吐細泉。", "望諧舟客趣，思發海人煙。", "顧櫪仍留馬，乘杯久棄船。", "未憂龜負嶽，且識鳥耘田。", "理契都無象，心冥不寄筌。", "安期庶可揖，天地得齊年。"]'),
('d855d4fb-399f-45bf-85a6-1af6354a6b31','遊法華寺','宋之問','唐','唐诗','tang','','[]','高岫擬耆闍，真乘引妙車。',120,'全唐诗/poet.tang.3000.json','["高岫擬耆闍，真乘引妙車。", "空中結樓殿，意表出雲霞。", "後果纏三足，前因感六牙。", "宴林薰寶樹，水溜滴金沙。", "寒谷梅猶淺，溫庭橘未華。", "臺香紅藥亂，塔影綠篁遮。", "果漸輪王族，緣超梵帝家。", "晨行踏忍草，夜誦得靈花。", "江郡將何匹，天都亦未加。", "朝來沿泛所，應是逐仙槎。"]'),
('35d2629c-80eb-4f46-9754-f348af4eb59f','夜渡吳松江懷古','宋之問','唐','唐诗','tang','','[]','宿帆震澤口，曉渡松江濆。',72,'全唐诗/poet.tang.3000.json','["宿帆震澤口，曉渡松江濆。", "櫂發魚龍氣，舟衝鴻雁羣。", "寒潮頓覺滿，暗浦稍將分。", "氣出海生日，光清湖起雲。", "水鄉盡天衞，歎息爲吳君。", "謀士伏劒死，至今悲所聞。"]'),
('61986a30-e365-4940-bb94-98027bc4d35d','謁禹廟','宋之問','唐','唐诗','tang','','[]','夏王乘四載，茲地發金符。',240,'全唐诗/poet.tang.3000.json','["夏王乘四載，茲地發金符。", "峻命終不易，報功疇敢渝。", "先驅總昌會，後至伏靈誅。", "玉帛空天下，衣冠照海隅。", "旋聞厭黃屋，更道出蒼梧。", "林表祠轉茂，山阿井詎枯。", "舟遷龍負壑，田變鳥芸蕪。", "舊物森如在，天威肅未殊。", "玄夷屆瑤席，玉女侍清都。", "奕奕扃闈邃，軒軒杖衞趨。", "氣青連曙海，雲白洗春湖。", "猿嘯有時答，禽言常自呼。", "靈歆異蒸糈，至樂匪笙竽。", "茅殿今文襲，梅梁古製無。", "運遙日崇麗，業盛答昭蘇。", "伊昔力云盡，而今功尚敷。", "揆材非美箭，精享愧生芻。", "郡職昧爲理，邦空寧自誣。", "下車霰已積，攝事露行濡。", "人隱冀多祐，曷唯霑薄軀。"]'),
('51d7a182-2615-4dd2-9e59-457acb5e7a8f','遊禹穴回出若邪','宋之問','唐','唐诗','tang','','[]','禹穴今朝到，邪溪此路通。',72,'全唐诗/poet.tang.3000.json','["禹穴今朝到，邪溪此路通。", "著書聞太史，鍊藥有仙翁。", "鶴往籠猶掛，龍飛劒已空。", "石帆搖海上，天鏡落湖中。", "水低寒雲白，山邊墜葉紅。", "歸舟何慮晚，日暮使樵風。"]'),
('7a9473a5-286c-48e5-9ded-f80f5e40c179','靈隱寺”','宋之問','唐','唐诗','tang','','[]','鷲嶺鬱岧嶢，龍宮鎖寂寥。',84,'全唐诗/poet.tang.3000.json','["鷲嶺鬱岧嶢，龍宮鎖寂寥。", "樓觀滄海日，門對浙江潮。", "桂子月中落，天香雲外飄。", "捫蘿登墖遠，刳木取泉遙。", "霜薄花更發，冰輕葉未凋。", "夙齡尚遐異，搜對滌煩囂。", "待入天台路，看余度石橋。"]'),
('4908dd7f-5c8a-4818-a912-4a4109ad39a1','遊雲門寺','宋之問','唐','唐诗','tang','','[]','維舟探靜域，作禮事尊經。',132,'全唐诗/poet.tang.3000.json','["維舟探靜域，作禮事尊經。", "投跡一蕭散，爲心自杳冥。", "龕依大禹穴，樓倚少微星。", "沓嶂圍蘭若，回溪抱竹庭。", "覺花塗砌白，甘露洗山青。", "雁塔鶱金地，虹橋轉翠屏。", "人天宵現景，神鬼晝潛形。", "理勝常虛寂，緣空自感靈。", "入禪從鴿遶，說法有龍聽。", "劫累終期滅，塵躬且未寧。", "搖搖不安寐，待月詠巖扃。"]'),
('526d3ff1-9a30-418e-a017-f9629ee0c34d','早發韶州','宋之問','唐','唐诗','tang','','[]','炎徼行應盡，回瞻鄉路遙。',120,'全唐诗/poet.tang.3000.json','["炎徼行應盡，回瞻鄉路遙。", "珠厓天外郡，銅柱海南標。", "日夜清明少，春冬霧雨饒。", "身經大火熱，顏入瘴江消。", "觸影含沙怒，逢人女草搖。", "露濃看菌濕，風颶覺船飄。", "直禦魑將魅，寧論鴟與鴞。", "虞翻思報國，許靖願歸朝。", "綠樹秦京道，青雲洛水橋。", "故園長在目，魂去不須招。"]'),
('e553fe91-93f1-46a9-a46e-9c6346bc9394','早入清遠峽','宋之問','唐','唐诗','tang','','[]','傳聞峽山好，旭日櫂前沂。',132,'全唐诗/poet.tang.3000.json','["傳聞峽山好，旭日櫂前沂。", "雨色搖丹嶂，泉聲聒翠微。", "兩巖天作帶，萬壑樹披衣。", "秋菊迎霜序，春藤礙日輝。", "翳潭花似織，緣嶺竹成圍。", "寂歷環沙浦，蔥蘢轉石圻。", "露餘江未熱，風落瘴初稀。", "猿飲排虛上，禽驚掠水飛。", "榜童夷唱合，樵女越吟歸。", "良候斯爲美，邊愁自有違。", "誰言望鄉國，流涕失芳菲。"]'),
('13d2d1bb-c188-4a1c-a083-0cd47f5cc853','發端州初入西江','宋之問','唐','唐诗','tang','','[]','問我將何去？清晨泝越溪。',121,'全唐诗/poet.tang.3000.json','["問我將何去？清晨泝越溪。", "翠微縣宿雨，丹壑飲晴霓。", "樹影捎雲密，藤陰覆水低。", "潮回出浦駛，洲轉望鄉迷。", "人意長懷北，江行日向西。", "破顏看鵲喜，拭淚聽猿嗁/。", "骨肉初分愛，親朋忽解攜。", "路遙魂欲斷，身辱理能齊。", "疇日三山意，于茲萬緒暌。", "金陵有仙館，即事尋丹梯。"]'),
('eb9530d2-e4c7-4c34-9214-06c28ca586bf','渡漢江','宋之問','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u601d\u4e61", "\u6e21\u6c5f"]','嶺外音書斷，經冬復歷春。',24,'全唐诗/poet.tang.3000.json','["嶺外音書斷，經冬復歷春。", "近鄉情更怯，不敢問來人。"]'),
('00ba7cc1-7482-4aaa-8312-8b00ef30d567','嵩山夜還','宋之問','唐','唐诗','tang','','[]','家住嵩山下，好采舊山薇。',24,'全唐诗/poet.tang.3000.json','["家住嵩山下，好采舊山薇。", "自省遊泉石，何曾不夜歸。"]'),
('351e8172-26b4-4057-b873-77ce777f7f47','湖中別鑒上人','宋之問','唐','唐诗','tang','','[]','願與道林近，在意逍遙篇。',24,'全唐诗/poet.tang.3000.json','["願與道林近，在意逍遙篇。", "自有靈佳寺，何用沃洲禪。"]'),
('3e649ebb-b819-4b66-871e-d5bfcd5b2782','題鑒上人房二首 一','宋之問','唐','唐诗','tang','','[]','落花雙樹積，芳草一庭春。',24,'全唐诗/poet.tang.3000.json','["落花雙樹積，芳草一庭春。", "玩之堪興異，何必見幽人。"]'),
('7b41486f-13da-4561-9dcc-da72979e7556','題鑒上人房二首 二','宋之問','唐','唐诗','tang','','[]','晚入應真理，經行尚未回。',24,'全唐诗/poet.tang.3000.json','["晚入應真理，經行尚未回。", "房中無俗物，林下有青苔。"]'),
('7251108e-2dda-49e4-94cb-faa0033f5320','答田徵君','宋之問','唐','唐诗','tang','','[]','出遊杳何處？遲回伊洛間。',24,'全唐诗/poet.tang.3000.json','["出遊杳何處？遲回伊洛間。", "歸寢忽成夢，宛在嵩丘山。"]'),
('cf18b593-adc4-416c-9ec7-3d77b2437692','傷曹娘二首 一','宋之問','唐','唐诗','tang','','[]','鳳飛樓伎絕，鸞死鏡臺空。',24,'全唐诗/poet.tang.3000.json','["鳳飛樓伎絕，鸞死鏡臺空。", "獨憐脂粉氣，猶著舞衣中。"]'),
('8f1412bd-f54f-4931-83b0-833a70b77233','傷曹娘二首 二','宋之問','唐','唐诗','tang','','["\u9ec4\u6cb3"]','河伯憐嬌態，馮夷要姝妓。',24,'全唐诗/poet.tang.3000.json','["河伯憐嬌態，馮夷要姝妓。", "寄言遊戲人，莫弄黃河水。"]'),
('93fac48d-d564-4359-8953-6d49af89ecb5','河陽','宋之問','唐','唐诗','tang','','[]','昔日河陽縣，氛氳香氣多。',24,'全唐诗/poet.tang.3000.json','["昔日河陽縣，氛氳香氣多。", "曹娘嬌態盡，春樹不堪過。"]'),
('f4fa7902-0797-41ac-a97e-dda1f68c5471','燕巢軍幕','宋之問','唐','唐诗','tang','','[]','北關憐翠幕，不是厭朱樓。',24,'全唐诗/poet.tang.3000.json','["北關憐翠幕，不是厭朱樓。", "故來呈燕頷，報道欲封侯。"]'),
('40336126-4c18-4de6-92a9-c73919cd8829','苑中遇雪應制','宋之問','唐','唐诗','tang','','["\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','紫禁仙輿詰旦來，青旂遙倚望春臺。',32,'全唐诗/poet.tang.3000.json','["紫禁仙輿詰旦來，青旂遙倚望春臺。", "不知庭霰今朝落，疑是林花昨夜開。"]'),
('5ea215df-4774-4510-8e1f-65e31354d19a','送司馬道士遊天台','宋之問','唐','唐诗','tang','','[]','羽客笙歌此地違，離筵數處白雲飛。',32,'全唐诗/poet.tang.3000.json','["羽客笙歌此地違，離筵數處白雲飛。", "蓬萊闕下長相憶，桐柏山頭去不歸。"]'),
('3e5ada7d-b0a4-45f6-8454-d8a4ef231824','登逍遙樓','宋之問','唐','唐诗','tang','','[]','逍遙樓上望鄉關，綠水泓澄雲霧間。',32,'全唐诗/poet.tang.3000.json','["逍遙樓上望鄉關，綠水泓澄雲霧間。", "北去衡陽二千里，無因雁足繫書還。"]'),
('77751a08-31d2-442b-87d2-e74107e96640','奉和春日玩雪應制','宋之問','唐','唐诗','tang','','[]','北闕彤雲掩曙霞，東風吹雪舞山家。',32,'全唐诗/poet.tang.3000.json','["北闕彤雲掩曙霞，東風吹雪舞山家。", "瓊章定少千人和，銀樹長芳六出花。"]'),
('eb1fbfbf-5eb7-40cf-ae94-66b7afa11913','傷曹娘二首 一','宋之問','唐','唐诗','tang','','[]','可憐冥漠去何之，獨立丰茸無見期。',32,'全唐诗/poet.tang.3000.json','["可憐冥漠去何之，獨立丰茸無見期。", "君看水上芙蓉色，恰似生前歌舞時。"]'),
('e562b576-1601-42f5-a67a-58a7f93c33c5','傷曹娘二首 二','宋之問','唐','唐诗','tang','','[]','前溪妙舞今應盡，子夜新歌遂不傳。',32,'全唐诗/poet.tang.3000.json','["前溪妙舞今應盡，子夜新歌遂不傳。", "無復綺羅嬌白日，直將珠玉閉黃泉。"]'),
('a751a97f-a92c-423d-85ea-4357f7ab4798','郡宅中齋','宋之問','唐','唐诗','tang','','[]','郡宅枕層嶺，春湖繞芳甸。',216,'全唐诗/poet.tang.3000.json','["郡宅枕層嶺，春湖繞芳甸。", "雲甍出萬家，臥覽皆已徧。", "漁商汗成雨，廨邑明若練。", "越俗鏡中行，夏祠雲表見。", "茲都信盤鬱，英遠常棲眄。", "王子事黃老，獨樂恣遊衍。", "謝公念蒼生，同憂感推薦。", "靈越多秀士，運闊無由面。", "神理翳青山，風流滿黃卷。", "揆予謬承獎，自惜從纓弁。", "瑤水執仙羈，金閨負時選。", "晨趨博望苑，夜直明光殿。", "一朝罷臺閣，萬里違鄉縣。", "風土足慰心，況悅年芳變。", "淮廩佇滋實，沂歌非所羨。", "訟寢歸四明，齡頹親九轉。", "微尚本江海，少留豈交戰。", "唯餘後凋色，竊比東南箭。"]'),
('3bc7692b-bd15-43ad-ac4c-7bb86d97d25a','稱心寺','宋之問','唐','唐诗','tang','','[]','步陟招提宮，北極山海觀。',96,'全唐诗/poet.tang.3000.json','["步陟招提宮，北極山海觀。", "千巖遞縈繞，萬壑殊悠漫。", "喬木轉夕陽，文軒劃清渙。", "泄雲多表裏，驚潮每昏旦。", "問予金門客，何事滄洲畔。", "謬以三署資，來刺百城半。", "人隱尚未弭，歲華豈兼玩。", "東山桂枝芳，明發坐盈歎。"]'),
('368fc6bb-1636-419e-8ddb-cdc1dd07a1ca','新年作','宋之問','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7", "\u6625\u8282", "\u601d\u4e61"]','鄉心新歲切，天畔獨澘然。',48,'全唐诗/poet.tang.3000.json','["鄉心新歲切，天畔獨澘然。", "老至居人下，春歸在客先。", "嶺猨同旦暮，江柳共風煙。", "已似長沙傅，從今又幾年。"]'),
('e95ada9f-e092-49a9-847d-a535158838ed','剪綵','宋之問','唐','唐诗','tang','','[]','駐想持金錯，居然作管灰。',48,'全唐诗/poet.tang.3000.json','["駐想持金錯，居然作管灰。", "綺羅纖手製，桃李向春開。", "拾藻蜂初泊，銜花鳥未回。", "不言將巧笑，飜逐美人來。"]'),
('b32afc30-867f-4732-aa23-f56b89414aef','七夕','宋之問','唐','唐诗','tang','','[]','傳道仙星媛，年年會水隅。',48,'全唐诗/poet.tang.3000.json','["傳道仙星媛，年年會水隅。", "停梭借蟋蟀，留巧付蜘蛛。", "去晝從雲請，歸輪竚日輸。", "莫言相見闊，天上日應殊。"]'),
('e9a822e4-fffa-4886-9ac6-d7369f8f6407','桂州陪王都督晦日宴逍遙樓','宋之問','唐','唐诗','tang','','[]','晦節高樓望，山川一半春。',48,'全唐诗/poet.tang.3000.json','["晦節高樓望，山川一半春。", "意隨蓂葉盡，愁共柳條新。", "投刺登龍日，開懷納鳥晨。", "兀然心似醉，不覺有吾身。"]'),
('4ab0826a-73b5-45a6-b24d-2971633ec7af','和趙員外桂陽橋遇佳人','宋之問','唐','唐诗','tang','','[]','江雨朝飛浥細塵，陽橋花柳不勝春。',64,'全唐诗/poet.tang.3000.json','["江雨朝飛浥細塵，陽橋花柳不勝春。", "金鞍白馬來從趙，玉面紅妝本姓秦。", "妬女猶憐鏡中髮，侍兒堪感路傍人。", "蕩舟爲樂非吾事，自歎空閨夢寐頻。"]'),
('a7135ccc-8edb-46e3-9709-eecef6496118','函谷關','宋之問','唐','唐诗','tang','','[]','至人□□識仙風，瑞靄丹光遠鬱蔥。',64,'全唐诗/poet.tang.3000.json','["至人□□識仙風，瑞靄丹光遠鬱蔥。", "靈跡才辭周柱下，祥氛已入函關中。", "不從紫氣臺端候，何得青華觀裏逢。", "欲訪乘牛求寶籙，願隨鶴駕徧瑤空。"]'),
('52f23aff-2d5b-47be-aa3d-5e1d745f3a85','詠省壁畫鶴','宋之問','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','粉壁圖仙鶴，昂藏真氣多。',24,'全唐诗/poet.tang.3000.json','["粉壁圖仙鶴，昂藏真氣多。", "鶱飛竟不去，當是戀恩波。"]'),
('69ab265b-f508-433f-90ea-dfc1d9cf2edc','廣州朱長史座觀妓','宋之問','唐','唐诗','tang','','[]','歌舞須連夜，神仙莫放歸。',24,'全唐诗/poet.tang.3000.json','["歌舞須連夜，神仙莫放歸。", "參差隨暮雨，前路濕人衣。"]'),
('7fe8887e-2239-44a7-807d-7328609e3104','謁二妃廟','宋之問','唐','唐诗','tang','','[]','還以金屋貴，留茲寶席尊。',24,'全唐诗/poet.tang.3000.json','["還以金屋貴，留茲寶席尊。", "江鳧嘯風雨，山鬼泣朝昏。"]'),
('8100eca2-fc61-48c6-834b-d9e654cc741b','贈嚴侍御','宋之問','唐','唐诗','tang','','[]','受脤清邊服，乘驄歷塞塵。',24,'全唐诗/poet.tang.3000.json','["受脤清邊服，乘驄歷塞塵。", "當聞漢雪恥，羞共虜和親。"]'),
('c790d955-dd59-4f5e-bc34-af137f0e4ec5','在荆州重赴嶺南','宋之問','唐','唐诗','tang','','[]','夢澤三秋日，蒼梧一片雲。',24,'全唐诗/poet.tang.3000.json','["夢澤三秋日，蒼梧一片雲。", "還將鵷鷺羽，重入鷓鴣羣。"]'),
('3d94a2ea-6307-42fb-a73f-3c0a558d728a','則天皇后挽歌','宋之問','唐','唐诗','tang','','[]','象物行周禮，衣冠集漢都。',24,'全唐诗/poet.tang.3000.json','["象物行周禮，衣冠集漢都。", "誰憐事虞舜，下里泣蒼梧。"]'),
('ded249cc-2194-4788-a429-04997aadce9f','鄧國太夫人挽歌','宋之問','唐','唐诗','tang','','[]','鸞死鉛妝歇，人亡錦字空。',24,'全唐诗/poet.tang.3000.json','["鸞死鉛妝歇，人亡錦字空。", "悲端若能減，渭水亦應窮。"]'),
('caaac61c-34aa-4488-88fa-47475740435a','楊將軍挽歌','宋之問','唐','唐诗','tang','','[]','亭寒照苦月，隴暗積愁雲。',24,'全唐诗/poet.tang.3000.json','["亭寒照苦月，隴暗積愁雲。", "今日山門樹，何處有將軍。"]'),
('41d91271-f7da-4561-94fc-af8fef298918','塞垣行','崔湜','唐','唐诗','tang','','["\u9ec4\u6cb3"]','疾風卷溟海，萬里揚砂礫。',132,'全唐诗/poet.tang.3000.json','["疾風卷溟海，萬里揚砂礫。", "仰望不見天，昏昏竟朝夕。", "是時軍兩進，東拒復西敵。", "蔽山張旗鼓，間道潛鋒鏑。", "精騎突曉圍，奇兵襲暗壁。", "十月邊塞寒，四山沍陰積。", "雨雪鴈南飛，風塵景西迫。", "昔我事討論，未嘗怠經籍。", "一朝棄筆硯，十年操矛戟。", "豈要黃河誓，須勒燕然石。", "可嗟牧羊臣，海上久爲客。"]'),
('eaed4e1f-e6e3-47de-bac5-42c37f84d666','送梁卿王郎中使東蕃弔冊','崔湜','唐','唐诗','tang','','[]','梁侯上卿秀，王子中臺傑。',72,'全唐诗/poet.tang.3000.json','["梁侯上卿秀，王子中臺傑。", "贈冊綏九夷，旌旃下雙闕。", "西堂禮樂送，南陌軒車別。", "征路入海雲，行舟泝江月。", "茲邦久欽化，歷載歸朝謁。", "皇心諒所嘉，寄爾宣風烈。"]'),
('65f0369a-f41b-4901-b11d-6e6bc9d2709c','餞唐州高使君赴任','崔湜','唐','唐诗','tang','','[]','芳春桃李時，京都物華好。',48,'全唐诗/poet.tang.3000.json','["芳春桃李時，京都物華好。", "爲岳豈不貴，所悲涉遠道。", "遠道不可思，宿昔夢見之。", "贈君雙佩刀，日夕視來期。"]'),
('102a9d8c-3ed1-4f24-b6f7-32ede2a814f2','冀北春望','崔湜','唐','唐诗','tang','','[]','迴首覽燕趙，春生兩河間。',48,'全唐诗/poet.tang.3000.json','["迴首覽燕趙，春生兩河間。", "曠然萬里餘，際海不見山。", "雨歇青林潤，煙空綠野閑。", "問鄉何處所，目送白雲還。"]'),
('495d3ae4-4bc2-46f3-a2bd-1fda9353283f','景龍二年余自門下平章事削階授江州員外司馬尋拜襄州刺史春日赴襄陽途中言志','崔湜','唐','唐诗','tang','','[]','余本燕趙人，秉心愚且直。',240,'全唐诗/poet.tang.3000.json','["余本燕趙人，秉心愚且直。", "羣籍備所見，孤貞每自飭。", "徇祿期代耕，受任亦量力。", "幸逢休明時，朝野兩薦推。", "一朝趨金門，十載奉瑤墀。", "入掌遷固筆，出參枚馬詞。", "吏部既三踐，中書亦五期。", "進無負鼎說，退慙補衮詩。", "常恐嬰悔吝，不得少酬私。", "嗷嗷路傍子，納謗紛無已。", "上動明主疑，下貽大臣恥。", "毫髮顧無累，冰壺邈自持。", "天道何期平，幽冤終見明。", "始佐廬陵郡，尋牧襄陽城。", "彤幃荷新寵，朱黻蒙舊榮。", "力薄慙任重，恩深知命輕。", "飭徒留前路，行子悲且慕。", "猶聞長樂鐘，尚辨青門樹。", "慈親不忍訣，昆弟默相顧。", "去去勿重陳，川長日云暮。"]'),
('557ff1f6-8ed9-4c9d-80ea-2d0ea82f54de','大漠行','崔湜','唐','唐诗','tang','','[]','單于犯薊堧，驃騎略蕭邊。',288,'全唐诗/poet.tang.3000.json','["單于犯薊堧，驃騎略蕭邊。", "南山木葉飛下地，北海蓬根亂上天。", "科斗連營太原道，魚麗合陣武威川。", "三軍遙倚杖，萬里相馳逐。", "旌斾悠悠靜瀚源，鼙鼓喧喧動盧谷。", "窮徼上幽陵，吁嗟倦寢興。", "馬蹄凍溜石，胡毳暖生冰。", "雲沙泱漭天光閉，河塞陰沈海色凝。", "崆峒異國誰能托，蕭索邊心常不樂。", "近見行人畏白龍，遙聞公主愁黃鶴。", "陽春半，岐路間。", "瑤臺苑，玉門關。", "百花芳樹紅將歇，二月蘭皐綠未還。", "陣雲不散魚龍水，雨雪猶飛鴻鴈山。", "山嶂連緜不可極，路遠辛勤夢顏色。", "北堂萱草不寄來，東園桃李長相憶。", "漢將紛紜攻戰盈，胡寇蕭條幽朔清。", "韓君拜節偏知遠，鄭吉驅旌坐見迎。", "火絕煙沈右西極，谷靜山空左北平。", "但使將軍能百戰，不須天子築長城。"]'),
('67b35d86-5ac2-4c72-aaf3-d112392f999e','奉和登驪山高頂寓目應制','崔湜','唐','唐诗','tang','','[]','名山何壯哉，玄覽一徘徊。',48,'全唐诗/poet.tang.3000.json','["名山何壯哉，玄覽一徘徊。", "御路穿林轉，旌門倚石開。", "煙霞肘後發，河塞掌中來。", "不學蓬壺遠，經年猶未迴。"]'),
('a8fdbfa3-921a-4d20-a25f-e7a81b18e928','侍宴長寧公主東莊應制','崔湜','唐','唐诗','tang','','[]','沁園東郭外，鸞駕一遊盤。',48,'全唐诗/poet.tang.3000.json','["沁園東郭外，鸞駕一遊盤。", "水榭宜時陟，山樓向晚看。", "席臨天女貴，杯接近臣歡。", "聖藻懸宸象，微臣竊仰觀。"]'),
('c038f3b7-f5e0-41a7-841d-7a00592ed751','奉和送金城公主適西蕃應制','崔湜','唐','唐诗','tang','','[]','懷戎前策備，降女舊因修。',48,'全唐诗/poet.tang.3000.json','["懷戎前策備，降女舊因修。", "簫鼓辭家怨，旌旃出塞愁。", "尚孩中念切，方遠御慈留。", "顧乏謀臣用，仍勞聖主憂。"]'),
('b93786a3-98e5-4f85-9e0a-1e580187a660','幸白鹿觀應制','崔湜','唐','唐诗','tang','','[]','御旗探紫籙，仙杖闢丹丘。',48,'全唐诗/poet.tang.3000.json','["御旗探紫籙，仙杖闢丹丘。", "捧藥芝童下，焚香桂女留。", "鸞歌無歲月，鶴語記春秋。", "臣朔真何幸，常陪漢武遊。"]'),
('9140947f-72ac-49e2-90f9-42f04f3bc302','幸梨園亭觀打毬應制','崔湜','唐','唐诗','tang','','[]','年光陌上發，香輦禁中遊。',48,'全唐诗/poet.tang.3000.json','["年光陌上發，香輦禁中遊。", "草綠鴛鴦殿，花明翡翠樓。", "寶杯承露酌，仙管雜風流。", "今日陪歡豫，皇恩不可酬。"]'),
('d0f005e8-33d2-41da-b44b-55654e121f20','慈恩寺九日應制','崔湜','唐','唐诗','tang','','[]','帝里重陽節，香園萬乘來。',48,'全唐诗/poet.tang.3000.json','["帝里重陽節，香園萬乘來。", "却邪萸結佩，獻壽菊傳杯。", "塔類承天湧，門疑待佛開。", "睿詞懸日月，長得仰昭回。"]'),
('c1442648-fc60-4566-a97a-ca92f87af08f','折楊柳','崔湜','唐','唐诗','tang','','[]','二月風光半，三邊戍不還。',48,'全唐诗/poet.tang.3000.json','["二月風光半，三邊戍不還。", "年華妾自惜，楊柳爲君攀。", "落絮縈衫袖，垂條拂髻鬟。", "那堪音信斷，流涕望陽關。"]'),
('566f5337-3b5a-450c-9f88-26bc86ed4f0f','邊愁','崔湜','唐','唐诗','tang','','[]','九月蓬根斷，三邊草葉腓。',48,'全唐诗/poet.tang.3000.json','["九月蓬根斷，三邊草葉腓。", "風塵馬變色，霜雪劒生衣。", "客思愁陰晚，邊書驛騎歸。", "殷勤鳳樓上，還袂及春暉。"]'),
('2211c73d-27d4-4232-a437-1e314f37234b','婕妤怨','崔湜','唐','唐诗','tang','','[]','不分君恩斷，新妝視鏡中。',48,'全唐诗/poet.tang.3000.json','["不分君恩斷，新妝視鏡中。", "容華尚春日，嬌愛已秋風。", "枕席臨窗曉，帷屏向月空。", "年年後庭樹，榮落在深宮。"]'),
('95969eff-695e-4eca-884a-677b8596a385','酬杜麟臺春思','崔湜','唐','唐诗','tang','','[]','春還上林苑，花滿洛陽城。',48,'全唐诗/poet.tang.3000.json','["春還上林苑，花滿洛陽城。", "鴛衾夜凝思，龍鏡曉含情。", "憶夢殘燈落，離魂暗馬驚。", "可憐朝與暮，樓上獨盈盈。"]'),
('375fef6a-8fdf-4728-8ec1-02f1467bcad7','寄天台司馬先生','崔湜','唐','唐诗','tang','','[]','聞有三元客，祈仙九轉成。',48,'全唐诗/poet.tang.3000.json','["聞有三元客，祈仙九轉成。", "人間白雲返，天上赤龍迎。", "尚惜金芝晚，仍攀琪樹榮。", "何年緱嶺上，一謝洛陽城。"]'),
('6c782ff7-202f-4c0f-8e8e-cbcd922e3dff','唐都尉山池','崔湜','唐','唐诗','tang','','[]','曲渚颺輕舟，前谿釣晚流。',48,'全唐诗/poet.tang.3000.json','["曲渚颺輕舟，前谿釣晚流。", "鴈翻蒲葉起，魚撥荇花遊。", "金子懸湘柚，珠房折海榴。", "幽尋惜未已，清月半西樓。"]'),
('b75a1a8f-0e5f-44f6-849a-ca8032ef04ad','江樓夕望','崔湜','唐','唐诗','tang','','[]','試陟江樓望，悠悠去國情。',36,'全唐诗/poet.tang.3000.json','["試陟江樓望，悠悠去國情。", "楚山霞外斷，漢水月中平。", "公子留遺邑，夫人有舊城。"]'),
('fe978521-5853-4eac-916a-a46ab192914c','襄城即事','崔湜','唐','唐诗','tang','','[]','子牟懷魏闕，元凱滯襄城。',36,'全唐诗/poet.tang.3000.json','["子牟懷魏闕，元凱滯襄城。", "冠蓋仍爲里，沙臺尚識名。", "山光晴後綠，江色晚來清。"]'),
('6ee5eb3d-c967-496e-a456-47bf7b4cfaa2','秦州薛都督挽詞','崔湜','唐','唐诗','tang','','[]','十里絳山幽，千年汾水流。',48,'全唐诗/poet.tang.3000.json','["十里絳山幽，千年汾水流。", "碑傳門客見，劒是故人留。", "隴樹煙含夕，山門月照秋。", "古來鐘鼎盛，共盡一嵩丘。"]'),
('ed09bc3f-c8fb-46b8-9e97-1f01efd60dfc','奉和春日幸望春宮','崔湜','唐','唐诗','tang','','[]','澹蕩春光滿曉空，逍遙御輦入離宮。',64,'全唐诗/poet.tang.3000.json','["澹蕩春光滿曉空，逍遙御輦入離宮。", "山河眺望雲天外，臺榭參差煙霧中。", "庭際花飛錦繡合，枝間鳥囀管弦同。", "即此歡娛齊鎬宴，唯應率舞樂薰風。"]'),
('4436fa66-3d89-46ef-a1d5-60382ad35ac5','奉和幸韋嗣立山莊侍宴應制','崔湜','唐','唐诗','tang','','[]','丞相登前府，尚書啓舊林。',96,'全唐诗/poet.tang.3000.json','["丞相登前府，尚書啓舊林。", "式閭明主睿，榮族聖嬪心。", "川狹旌門抵，巖高蔽帳臨。", "閑窗憑柳暗，小徑入松深。", "雲卷千峰色，泉和萬籟吟。", "蘭迎天女佩，竹礙侍臣簪。", "宸翰三光燭，朝榮四海欽。", "還嗟絕機叟，白首漢川陰。"]'),
('2bbde0ae-0e7c-41b1-819b-2854346b93c2','同李員外春閨','崔湜','唐','唐诗','tang','','[]','落日啼連夜，孤燈坐徹明。',72,'全唐诗/poet.tang.3000.json','["落日啼連夜，孤燈坐徹明。", "捲簾雙燕入，披幌百花驚。", "隴上寒應晚，閨中織未成。", "管弦愁不意，梳洗懶無情。", "去歲聞西伐，今年送北征。", "容顏離別盡，流恨滿長城。"]'),
('46e42c8d-4bc4-4517-96e9-b72fe359c296','襄陽早秋寄岑侍郎','崔湜','唐','唐诗','tang','','[]','江城秋氣早，旭旦坐南闈。',72,'全唐诗/poet.tang.3000.json','["江城秋氣早，旭旦坐南闈。", "落葉驚衰鬢，清霜換旅衣。", "時來矜早達，事往覺前非。", "體道徒推理，防身終昧微。", "故人金華省，肅穆秉天機。", "誰念江漢廣，蹉跎心事違。"]'),
('70ee0407-6eb0-4f97-ba38-f3b755088467','贈蘇少府赴任江南余時還京','崔湜','唐','唐诗','tang','','[]','丈夫不歎別，達士自安卑。',72,'全唐诗/poet.tang.3000.json','["丈夫不歎別，達士自安卑。", "攬泣固無趣，銜杯空爾爲。", "流雲春窈窕，去水暮逶迤。", "行舟忽東泛，歸騎亦西馳。", "秦地多芳草，江潭有桂枝。", "誰言阻遐闊，所貴在相知。"]'),
('f32574bf-7764-44ea-8d8c-b452873142d2','登總持寺閣','崔湜','唐','唐诗','tang','','[]','宿雨清龍界，晨暉滿鳳城。',72,'全唐诗/poet.tang.3000.json','["宿雨清龍界，晨暉滿鳳城。", "升攀重閣迥，憑覽四郊明。", "井邑周秦地，山河今古情。", "紆餘一水合，寥落五陵平。", "處處風煙起，欣欣草木榮。", "故人不可見，冠蓋滿東京。"]'),
('a132bab1-1809-4f43-b8d5-373952635083','早春邊城懷歸','崔湜','唐','唐诗','tang','','[]','大漠羽書飛，長城未解圍。',72,'全唐诗/poet.tang.3000.json','["大漠羽書飛，長城未解圍。", "山川凌玉嶂，旌節下金微。", "路向南庭遠，書因北鴈稀。", "鄉關搖別思，風雪散戎衣。", "歲盡仍爲客，春還尚未歸。", "明年征騎返，歌舞及芳菲。"]'),
('733604f9-89e9-4f48-a246-44d3ba77129d','至桃林塞作','崔湜','唐','唐诗','tang','','[]','去國未千里，離家已再旬。',120,'全唐诗/poet.tang.3000.json','["去國未千里，離家已再旬。", "丹心恆戀闕，白首更辭親。", "懷璧常貽訓，捐金詎得鄰。", "抱冤非忤物，罹謗豈由人。", "不濫辭終辨，無瑕理竟伸。", "黻還中省舊，符與外臺新。", "塞上同遷客，江潭異逐臣。", "淚垂非屬峴，腸斷固由秦。", "歲月行遒盡，山川難重陳。", "始知亭伯去，還是拙謀身。"]'),
('23b9bdae-4258-425f-9a77-a77297bc4e6a','襄陽作','崔湜','唐','唐诗','tang','','[]','廟堂初解印，郡邸忽腰章。',120,'全唐诗/poet.tang.3000.json','["廟堂初解印，郡邸忽腰章。", "按節巡河右，鳴騶入漢陽。", "城臨南峴出，樹繞北津長。", "好學風猶扇，誇才俗未忘。", "江山跨七澤，煙雨接三湘。", "蛟浦菱荷淨，漁舟橘柚香。", "醉中求習氏，夢裏憶襄王。", "宅壞仍思鳳，碑存更憶羊。", "下車慙政美，閉閣幸時康。", "多謝南征術，于今尚不亡。"]'),
('98fc8978-fa5f-4064-8df3-a6cd9ddc0b4f','喜入長安','崔湜','唐','唐诗','tang','','[]','雲日能催曉，風光不惜年。',24,'全唐诗/poet.tang.3000.json','["雲日能催曉，風光不惜年。", "賴逢征客盡，歸在落花前。"]'),
('4b0be1ca-b0fa-435b-8e7c-0c804daf7afd','奉和幸韋嗣立山莊應制','崔湜','唐','唐诗','tang','','[]','竹徑桃源本出塵，松軒茅棟別驚新。',32,'全唐诗/poet.tang.3000.json','["竹徑桃源本出塵，松軒茅棟別驚新。", "御蹕何須林下駐，山公不是俗中人。"]'),
('ed4922d1-0dc1-4e89-9abb-59d9e1fdeb7f','踏歌詞二首 一','崔液','唐','唐诗','tang','','[]','綵女迎金屋，仙姬出畫堂。',36,'全唐诗/poet.tang.3000.json','["綵女迎金屋，仙姬出畫堂。", "鴛鴦裁錦袖，翡翠貼花黃。", "歌響舞分行，豔色動流光。"]'),
('08d57185-e426-4c15-bf32-851a865e8f1d','踏歌詞二首 二','崔液','唐','唐诗','tang','','[]','庭際花微落，樓前漢已橫。',36,'全唐诗/poet.tang.3000.json','["庭際花微落，樓前漢已橫。", "金臺催夜盡，羅袖拂寒輕。", "樂笑暢歡情，未半著天明。"]'),
('cf500489-3156-4261-87d8-d3e3b0d1bc62','代春閨','崔液','唐','唐诗','tang','','[]','江南日暖鴻始來，柳條初碧葉半開。',80,'全唐诗/poet.tang.3000.json','["江南日暖鴻始來，柳條初碧葉半開。", "玉關遙遙戍未迴，金閨日夕生綠苔。", "寂寂春花煙色暮，簷燕雙雙落花度。", "青樓明鏡晝無光，紅帳羅衣徒自香。", "妾恨十年長獨守，君情萬里在漁陽。"]'),
('c190c99b-4dca-499d-9946-0c86b15b2384','上元夜六首 一','崔液','唐','唐诗','tang','','[]','玉漏銀壺且莫催，鐵關金鎖徹明開。',32,'全唐诗/poet.tang.3000.json','["玉漏銀壺且莫催，鐵關金鎖徹明開。", "誰家見月能閒坐，何處聞燈不看来。"]'),
('a69d67cc-b295-47ce-b55a-c37641f19bc8','上元夜六首 二','崔液','唐','唐诗','tang','','[]','神燈佛火百輪張，刻像圖形七寶裝。',32,'全唐诗/poet.tang.3000.json','["神燈佛火百輪張，刻像圖形七寶裝。", "影裏如聞金口說，空中似散玉毫光。"]'),
('47507272-4baa-4590-89f0-519c044865a6','上元夜六首 三','崔液','唐','唐诗','tang','','[]','今年春色勝常年，此夜風光最可憐。',32,'全唐诗/poet.tang.3000.json','["今年春色勝常年，此夜風光最可憐。", "鳷鵲樓前新月滿，鳳皇臺上寶燈燃。"]'),
('aaf10198-98c3-40da-89cb-71e9c9bb6f32','上元夜六首 四','崔液','唐','唐诗','tang','','[]','金勒銀鞍控紫騮，玉輪珠幰駕青牛。',32,'全唐诗/poet.tang.3000.json','["金勒銀鞍控紫騮，玉輪珠幰駕青牛。", "驂驔始散東城曲，倏忽還來南陌頭。"]'),
('4d7761c4-5488-4585-895e-9fb2d904329e','上元夜六首 五','崔液','唐','唐诗','tang','','[]','公子王孫意氣驕，不論相識也相邀。',32,'全唐诗/poet.tang.3000.json','["公子王孫意氣驕，不論相識也相邀。", "最憐長袖風前弱，更賞新弦暗裏調。"]'),
('179bb9e7-363c-47e3-8285-c79653ecdb62','上元夜六首 六','崔液','唐','唐诗','tang','','[]','星移漢轉日將微，露灑煙飄燈漸稀。',32,'全唐诗/poet.tang.3000.json','["星移漢轉日將微，露灑煙飄燈漸稀。", "猶惜路傍歌舞處，躊躕相顧不能歸。"]'),
('821997f5-b3ba-4c3c-b41e-0c343c960d1f','冀北春望','崔液','唐','唐诗','tang','','[]','迴首覽燕趙，春生兩河間。',48,'全唐诗/poet.tang.3000.json','["迴首覽燕趙，春生兩河間。", "曠然餘萬里，際海不見山。", "雨歇青林潤，煙空綠野閑。", "問鄉無處所，目送白雲關。"]'),
('bf76a945-5999-49b2-a421-dabc3390f512','擬古神女宛轉歌二首 一','崔液','唐','唐诗','tang','','[]','風已清，月朗琴復明。',44,'全唐诗/poet.tang.3000.json','["風已清，月朗琴復明。", "掩抑悲千態，殷勤是一聲。", "歌宛轉，宛轉和更長。", "願爲雙鴻鵠，比翼共翱翔。"]'),
('bb186930-154b-479e-8d6f-108b6aeb8e1c','擬古神女宛轉歌二首 二','崔液','唐','唐诗','tang','','[]','日已暮，長簷鳥應度。',50,'全唐诗/poet.tang.3000.json','["日已暮，長簷鳥應度。", "此時望君君不來，此時思君君不顧。", "歌宛轉，宛轉那能異棲宿。", "願爲形與影，出入恆相逐。"]'),
('6640be9f-5f63-4307-a324-d71833ed2641','望韓公堆','崔滌','唐','唐诗','tang','','[]','韓公堆上望秦川，渺渺關山西接連。',32,'全唐诗/poet.tang.3000.json','["韓公堆上望秦川，渺渺關山西接連。", "孤客一身千里外，未知歸日是何年。"]'),
('ca416e26-96be-49ca-ab46-5c91d4ff42a1','倬彼我系 一','王勃','唐','唐诗','tang','','[]','倬彼我系，出自有周。',40,'全唐诗/poet.tang.3000.json','["倬彼我系，出自有周。", "分疆錫社，派別支流。", "居衞仕宋，臣嬴相劉。", "廼武廼文，或公或侯。"]'),
('113ed00f-61c6-49e3-8898-7f13441c3a2b','倬彼我系 二','王勃','唐','唐诗','tang','','[]','晉曆崩坼，衣冠擾弊。',40,'全唐诗/poet.tang.3000.json','["晉曆崩坼，衣冠擾弊。", "粵自太原，播徂江澨。", "禮喪賢隱，時屯道閉。", "王室如燬，生人多殪。"]'),
('4514bc5b-b6b6-4fe4-8341-6951a73ba76f','倬彼我系 三','王勃','唐','唐诗','tang','','[]','伊我有器，思逢其主。',40,'全唐诗/poet.tang.3000.json','["伊我有器，思逢其主。", "自東施西，擇木開宇。", "田彼河曲，家乎汾浦。", "天未厭亂，吾將誰輔。"]'),
('3757a306-bb29-4354-a8c5-171649777e80','倬彼我系 四','王勃','唐','唐诗','tang','','[]','伊我祖德，思濟九埏。',40,'全唐诗/poet.tang.3000.json','["伊我祖德，思濟九埏。", "不常厥所，于茲五遷。", "欲及時也，夫豈願焉。", "其位雖屈，其言則傳。"]'),
('46a0bd86-6784-43ed-bcf6-3d75028768aa','倬彼我系 五','王勃','唐','唐诗','tang','','[]','爰述帝制，大蒐王道。',40,'全唐诗/poet.tang.3000.json','["爰述帝制，大蒐王道。", "曰天曰人，是祖是考。", "禮樂咸若，詩書具草。", "貽厥孫謀，永爲家寶。"]'),
('f7156f64-3797-4f4c-a5ac-f6314ba08155','倬彼我系 六','王勃','唐','唐诗','tang','','[]','伊余小子，信慙明哲。',40,'全唐诗/poet.tang.3000.json','["伊余小子，信慙明哲。", "彼網有條，彼車有轍。", "思屏人事，克終前烈。", "于嗟代網，卒余來絏。"]'),
('469f2d52-ff14-45c2-a8b9-e958e05c38dd','倬彼我系 七','王勃','唐','唐诗','tang','','[]','來絏伊何，謂余曰仕。',40,'全唐诗/poet.tang.3000.json','["來絏伊何，謂余曰仕。", "我瞻先達，三十方起。", "夫豈不懷，高山仰止。", "願言毓德，啜菽飲水。"]'),
('b534cfc1-e3de-405e-836d-c1d56b812bd9','倬彼我系 八','王勃','唐','唐诗','tang','','[]','有鳥反哺，其聲嗷嗷。',40,'全唐诗/poet.tang.3000.json','["有鳥反哺，其聲嗷嗷。", "言念舊德，憂心忉忉。", "今我不養，歲月其滔。", "僶俛從役，豈敢告勞。"]'),
('ea64690f-de70-4759-81e4-01e782adfc41','倬彼我系 九','王勃','唐','唐诗','tang','','[]','從役伊何，薄求卑位。',40,'全唐诗/poet.tang.3000.json','["從役伊何，薄求卑位。", "告勞伊何，來參卿事。", "名存實爽，負信愆義。", "靜言遐思，中心是愧。"]'),
('eb5d1d42-f2d5-49ff-aa3e-c5743800c3a2','上巳浮江宴韻得阯字','王勃','唐','唐诗','tang','','[]','披觀玉京路，駐賞金臺阯。',48,'全唐诗/poet.tang.3000.json','["披觀玉京路，駐賞金臺阯。", "逸興懷九仙，良辰傾四美。", "松吟白雲際，桂馥青溪裏。", "別有江海心，日暮情何已。"]'),
('931f1f81-3209-4a11-9984-9138dd07a97b','春日宴樂遊園賦韻得接字','王勃','唐','唐诗','tang','','[]','帝里寒光盡，神臯春望浹。',48,'全唐诗/poet.tang.3000.json','["帝里寒光盡，神臯春望浹。", "梅郊落晚英，柳甸驚初葉。", "流水抽奇弄，崩雲灑芳牒。", "清尊湛不空，暫喜平生接。"]'),
('74b7e4a8-af8e-4845-8e8c-7290b0a650c8','山亭夜宴','王勃','唐','唐诗','tang','','[]','桂宇幽襟積，山亭涼夜永。',48,'全唐诗/poet.tang.3000.json','["桂宇幽襟積，山亭涼夜永。", "森沈野徑寒，肅穆巖扉靜。", "竹晦南汀色，荷翻北潭影。", "清興殊未闌，林端照初景。"]'),
('98c8b8e6-005b-4164-9099-f1a7e4d0d51d','詠風','王勃','唐','唐诗','tang','','[]','肅肅涼景生，加我林壑清。',48,'全唐诗/poet.tang.3000.json','["肅肅涼景生，加我林壑清。", "驅煙尋磵戶，卷霧出山楹。", "去來固無跡，動息如有情。", "日落山水靜，爲君起松聲。"]'),
('3c40dd19-7c9f-4d54-820f-3e219872de74','懷仙','王勃','唐','唐诗','tang','','[]','鶴岑有奇徑，麟洲富仙家。',72,'全唐诗/poet.tang.3000.json','["鶴岑有奇徑，麟洲富仙家。", "紫泉漱珠液，玄巖列丹葩。", "常希披塵網，眇然登雲車。", "鸞情極霄漢，鳳想疲煙霞。", "道存蓬瀛近，意愜朝市賒。", "無爲坐惆悵，虛此江上華。"]'),
('3554a29f-272a-4828-8437-4b3823468690','忽夢遊仙','王勃','唐','唐诗','tang','','[]','僕本江上客，牽跡在方內。',96,'全唐诗/poet.tang.3000.json','["僕本江上客，牽跡在方內。", "寤寐霄漢間，居然有靈對。", "翕爾登霞首，依然躡雲背。", "電策驅龍光，煙途儼鸞態。", "乘月披金帔，連星解瓊珮。", "浮識俄易歸，真遊邈難再。", "寥廓沈遐想，周遑奉遺誨。", "流俗非我鄉，何當釋塵昧。"]'),
('756d6122-bd88-4235-9adb-3ec5c2700b27','雜曲','王勃','唐','唐诗','tang','','[]','智瓊神女，來訪文君。',44,'全唐诗/poet.tang.3000.json','["智瓊神女，來訪文君。", "蛾眉始約，羅袖初薰。", "歌齊曲韻，舞亂行紛。", "若向陽臺薦枕，何啻得勝朝雲。"]'),
('0f9f294b-1b9b-4cb5-ac3a-a6d847405d33','秋夜長','王勃','唐','唐诗','tang','','[]','秋夜長，殊未央。',120,'全唐诗/poet.tang.3000.json','["秋夜長，殊未央。", "月明白露澄清光，層城綺閣遙相望。", "遙相望，川無梁。", "北風受節南雁翔，崇蘭委質時菊芳。", "鳴環曳履出長廊，爲君秋夜擣衣裳。", "纖羅對鳳皇，丹綺雙鴛鴦。", "調砧亂杵思自傷，思自傷，征夫萬里戍他鄉。", "鶴關音信斷，龍門道路長。", "君在天一方，寒衣徒自香。"]'),
('0820a352-463f-4da9-a96a-8dd3dcc56c5f','採蓮曲','王勃','唐','唐诗','tang','','[]','採蓮歸，綠水芙蓉衣。',244,'全唐诗/poet.tang.3000.json','["採蓮歸，綠水芙蓉衣。", "秋風起浪鳧雁飛，桂櫂蘭橈下長浦。", "羅裙玉腕輕搖櫓，葉嶼花潭極望平。", "江謳越吹相思苦，相思苦，佳期不可駐。", "塞外征夫猶未還，江南採蓮今已暮。", "今已暮，採蓮花，渠今那必盡娼家。", "官道城南把桑葉，何如江上採蓮花。", "蓮花復蓮花，花葉何稠疊。", "葉翠本羞眉，花紅強如頰。", "佳人不在茲，悵望別離時。", "牽花憐共蒂，折藕愛連絲。", "故情無處所，新物從華滋。", "不惜西津交佩解，還羞北海雁書遲。", "採蓮歌有節，採蓮夜未歇。", "正逢浩蕩江上風，又值裴回江上月。", "裴回蓮浦夜相逢，吳姬越女何丰茸。", "共問寒江千里外，征客關山路幾重。"]'),
('d7040e3b-0326-4ad0-a23c-411c4ff51c76','臨高臺','王勃','唐','唐诗','tang','','[]','臨高臺，高臺迢遰絕浮埃。',282,'全唐诗/poet.tang.3000.json','["臨高臺，高臺迢遰絕浮埃。", "瑤軒綺構何崔嵬，鸞歌鳳吹清且哀。", "俯瞰長安道，萋萋御溝草。", "斜對甘泉路，蒼蒼茂陵樹。", "高臺四望同，帝鄉佳氣鬱蔥蔥。", "紫閣丹樓紛照耀，璧房錦殿相玲瓏。", "東彌長樂觀，西指未央宮。", "赤城映朝日，綠樹搖春風。", "旗亭百隧開新市，甲第千甍分戚里。", "朱輪翠蓋不勝春，疊榭層楹相對起。", "復有青樓大道中，繡戶文窗雕綺櫳。", "錦衾夜不襞，羅帷晝未空。", "歌屏朝揜翠，妝鏡晚窺紅。", "爲君安寶髻，蛾眉罷花叢。", "塵間狹路黯將暮，雲間月色明如素。", "鴛鴦池上兩兩飛，鳳凰樓下雙雙度。", "物色正如此，佳期那不顧。", "銀鞍繡轂盛繁華，可憐今夜宿娼家。", "娼家少婦不須顰，東園桃李片時春。", "君看舊日高臺處，柏梁銅雀生黃塵。"]'),
('9f023a30-3a31-4262-9ee7-ade9e4e591c8','滕王閣','王勃','唐','唐诗','tang','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','滕王高閣臨江渚，珮玉鳴鸞罷歌舞。',64,'全唐诗/poet.tang.3000.json','["滕王高閣臨江渚，珮玉鳴鸞罷歌舞。", "畫棟朝飛南浦雲，珠簾暮捲西山雨。", "閑雲潭影日悠悠，物換星移幾度秋。", "閣中帝子今何在？檻外長江空自流。"]'),
('387f7a5f-6abb-48f9-9ecb-0be7b27428f8','江南弄','王勃','唐','唐诗','tang','','[]','江南弄，巫山連楚夢，行雨行雲幾相送。',66,'全唐诗/poet.tang.3000.json','["江南弄，巫山連楚夢，行雨行雲幾相送。", "瑤軒金谷上春時，玉童仙女無見期。", "紫露香煙渺難託，清風明月遙相思。", "遙相思，草徒綠，爲聽雙飛鳳凰曲。"]'),
('051ff52b-2c24-44ef-a0b9-37659e0fe680','聖泉宴','王勃','唐','唐诗','tang','','[]','披襟乘石磴，列籍俯春泉。',48,'全唐诗/poet.tang.3000.json','["披襟乘石磴，列籍俯春泉。", "蘭氣熏山酌，松聲韻野弦。", "影飄垂葉外，香度落花前。", "興洽林塘晚，重巖起夕煙。"]'),
('7565a1fd-cb08-488b-b456-01ff54330636','尋道觀','王勃','唐','唐诗','tang','','[]','芝廛光分野，蓬闕盛規模。',48,'全唐诗/poet.tang.3000.json','["芝廛光分野，蓬闕盛規模。", "碧壇清桂閾，丹洞肅松樞。", "玉笈三山記，金箱五嶽圖。", "蒼虬不可得，空望白雲衢。"]'),
('5bed2740-0644-4ffc-9661-77173b742ef3','散關晨度','王勃','唐','唐诗','tang','','[]','關山凌旦開，石路無塵埃。',48,'全唐诗/poet.tang.3000.json','["關山凌旦開，石路無塵埃。", "白馬高譚去，青牛真氣來。", "重門臨巨壑，連棟起崇隈。", "即今揚策度，非是棄繻回。"]'),
('56cf7e31-5924-43f8-9c1a-0a4e556fc13b','別薛華','王勃','唐','唐诗','tang','','["\u9001\u522b", "\u76f8\u601d"]','送送多窮路，遑遑獨問津。',48,'全唐诗/poet.tang.3000.json','["送送多窮路，遑遑獨問津。", "悲涼千里道，悽斷百年身。", "心事同漂泊，生涯共苦辛。", "無論去與住，俱是夢中人。"]'),
('7c0439ad-bbc9-408c-801f-de7c948631b7','重別薛華','王勃','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','明月沈珠浦，秋風濯錦川。',48,'全唐诗/poet.tang.3000.json','["明月沈珠浦，秋風濯錦川。", "樓臺臨絕岸，洲渚亙長天。", "旅泊成千里，棲遑共百年。", "窮途唯有淚，還望獨潸然。"]'),
('f8d04bd9-0163-4f26-ae0a-f380469488ad','遊梵宇三覺寺','王勃','唐','唐诗','tang','','[]','杏閣披青磴，琱臺控紫岑。',48,'全唐诗/poet.tang.3000.json','["杏閣披青磴，琱臺控紫岑。", "葉齊山路狹，花積野壇深。", "蘿幌棲禪影，松門聽梵音。", "遽忻陪妙躅，延賞滌煩襟。"]'),
('58794d4f-58da-49cb-95cd-e827daf10a61','麻平晚行','王勃','唐','唐诗','tang','','["\u6292\u60c5", "\u7f81\u65c5", "\u601d\u4e61", "\u5199\u666f"]','百年懷土望，千里倦遊情。',48,'全唐诗/poet.tang.3000.json','["百年懷土望，千里倦遊情。", "高低尋戍道，遠近聽泉聲。", "磵葉纔分色，山花不辨名。", "羈心何處盡？風急暮猨清。"]'),
('f4254f08-9b3f-4717-b8e1-30808345afeb','送盧主簿','王勃','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','窮途非所恨，虛室自相依。',48,'全唐诗/poet.tang.3000.json','["窮途非所恨，虛室自相依。", "城闕居年滿，琴尊俗事稀。", "開襟方未已，分袂忽多違。", "東巖富松竹，歲暮幸同歸。"]'),
('a20c4064-a898-4265-bc47-d41d8e0c9fd6','餞韋兵曹','王勃','唐','唐诗','tang','','[]','征驂臨野次，別袂慘江垂。',48,'全唐诗/poet.tang.3000.json','["征驂臨野次，別袂慘江垂。", "川霽浮煙歛，山明落照移。", "鷹風凋晚葉，蟬露泣秋枝。", "亭臯分遠望，延想間雲涯。"]'),
('4c01b049-07ab-4898-8963-920c7c66c266','白下驛餞唐少府','王勃','唐','唐诗','tang','','[]','下驛窮交日，昌亭旅食年。',48,'全唐诗/poet.tang.3000.json','["下驛窮交日，昌亭旅食年。", "相知何用早，懷抱即依然。", "浦樓低晚照，鄉路隔風煙。", "去去如何道，長安在日邊。"]'),
('fe6f4b72-855c-43b9-8883-8b3fe3cd8bd4','杜少府之任蜀州','王勃','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u53cb\u60c5", "\u9001\u522b", "\u521d\u4e2d\u53e4\u8bd7", "\u4e94\u8a00\u5f8b\u8bd7"]','城闕輔三秦，風煙望五津。',48,'全唐诗/poet.tang.3000.json','["城闕輔三秦，風煙望五津。", "與君離別意，同是宦遊人。", "海內存知己，天涯若比隣。", "無爲在岐路，兒女共霑巾。"]'),
('6dd6cd60-5ecb-4b13-86ba-f05f9789e62c','仲春郊外','王勃','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u60c5", "\u90ca\u5916"]','東園垂柳徑，西堰落花津。',36,'全唐诗/poet.tang.3000.json','["東園垂柳徑，西堰落花津。", "物色連三月，風光絕四隣。", "鳥飛村覺曙，魚戲水知春。"]'),
('3f33c79f-8e0c-4817-8a2b-edea6ad23208','郊興','王勃','唐','唐诗','tang','','[]','空園歌獨酌，春日賦閑居。',48,'全唐诗/poet.tang.3000.json','["空園歌獨酌，春日賦閑居。", "澤蘭侵小徑，河柳覆長渠。", "雨去花光濕，風歸葉影疎。", "山人不惜醉，唯畏綠尊虛。"]'),
('b014596b-1c6a-4bb5-8631-0c37866d340b','郊園即事','王勃','唐','唐诗','tang','','[]','煙霞春旦賞，松竹故年心。',48,'全唐诗/poet.tang.3000.json','["煙霞春旦賞，松竹故年心。", "斷山疑畫障，縣溜瀉鳴琴。", "草徧南亭合，花開北院深。", "閑居饒酒賦，隨興欲抽簪。"]'),
('92a707aa-a8dd-4fbf-9b4a-91797e03d525','觀佛跡寺','王勃','唐','唐诗','tang','','[]','蓮座神容儼，松崖聖趾餘。',48,'全唐诗/poet.tang.3000.json','["蓮座神容儼，松崖聖趾餘。", "年長金跡淺，地久石文疎。", "頹華臨曲磴，傾影赴前除。", "共嗟陵谷遠，俄視化城虛。"]'),
('654d2706-43c2-4df0-a952-20d97de421f2','山居晚眺贈王道士','王勃','唐','唐诗','tang','','[]','金壇疎俗宇，玉洞侶仙羣。',48,'全唐诗/poet.tang.3000.json','["金壇疎俗宇，玉洞侶仙羣。", "花枝棲晚露，峰葉度晴雲。", "斜照移山影，回沙擁籀文。", "琴尊方待興，竹樹已迎曛。"]'),
('8f53618f-7d8c-4df3-969f-a53963594ea7','八仙逕','王勃','唐','唐诗','tang','','[]','柰園欣八正，松巖訪九仙。',48,'全唐诗/poet.tang.3000.json','["柰園欣八正，松巖訪九仙。", "援蘿窺霧術，攀林俯雲烟。", "代北鸞驂至，遼西鶴騎旋。", "終希脫塵網，連翼下芝田。"]'),
('1b8464f8-3be3-40ad-b632-6b7027f8edcc','春日還郊','王勃','唐','唐诗','tang','','[]','閑情兼嘿語，攜杖赴巖泉。',48,'全唐诗/poet.tang.3000.json','["閑情兼嘿語，攜杖赴巖泉。", "草綠縈新帶，榆青綴古錢。", "魚牀侵岸水，鳥路入山煙。", "還題平子賦，花樹滿春田。"]'),
('286d31c9-8d14-408e-a339-cdd05a4d36b2','對酒春園作','王勃','唐','唐诗','tang','','[]','投簪下山閣，攜酒對河梁。',48,'全唐诗/poet.tang.3000.json','["投簪下山閣，攜酒對河梁。", "狹水牽長鏡，高花送斷香。", "繁鶯歌似曲，疎蝶舞成行。", "自然催一醉，非但閱年光。"]'),
('f05ef11d-52d9-4684-a9c4-c6b7c7c92352','觀內懷仙','王勃','唐','唐诗','tang','','[]','玉架殘書隱，金壇舊跡迷。',48,'全唐诗/poet.tang.3000.json','["玉架殘書隱，金壇舊跡迷。", "牽花尋紫澗，步葉下清谿。", "瓊漿猶類乳，石髓尚如泥。", "自能成羽翼，何必仰雲梯。"]'),
('1107ead7-1271-44d9-9354-4ea61a605cdc','秋日別王長史','王勃','唐','唐诗','tang','','[]','別路餘千里，深恩重百年。',48,'全唐诗/poet.tang.3000.json','["別路餘千里，深恩重百年。", "正悲西候日，更動北梁篇。", "野色籠寒霧，山光歛暮煙。", "終知難再奉，懷德自潸然。"]'),
('118a90d5-3a84-47d0-8261-5d92fb2da00a','上巳浮江宴韻得遙字','王勃','唐','唐诗','tang','','[]','上巳年光促，中川興緒遙。',48,'全唐诗/poet.tang.3000.json','["上巳年光促，中川興緒遙。", "綠齊山葉滿，紅洩片花銷。", "泉聲喧後澗，虹影照前橋。", "遽悲春望遠，江路積波潮。"]'),
('c78f0ab8-ba60-4844-ae25-6b5f4a7e4cca','長柳','王勃','唐','唐诗','tang','','[]','晨征犯煙磴，夕憩在雲關。',48,'全唐诗/poet.tang.3000.json','["晨征犯煙磴，夕憩在雲關。", "晚風清近壑，新月照澄灣。", "郊童樵唱返，津叟釣歌還。", "客行無與晤，賴此釋愁顏。"]'),
('82fca041-925c-4dff-ac4d-4c9020c34624','銅雀妓二首 一','王勃','唐','唐诗','tang','','[]','金鳳隣銅雀，漳河望鄴城。',48,'全唐诗/poet.tang.3000.json','["金鳳隣銅雀，漳河望鄴城。", "君王無處所，臺榭若平生。", "舞席紛何就，歌梁儼未傾。", "西陵松檟冷，誰見綺羅情。"]'),
('ef84f609-2fad-4a57-8adf-6a78b1d23130','銅雀妓二首 二','王勃','唐','唐诗','tang','','[]','妾本深宮妓，層城閉九重。',48,'全唐诗/poet.tang.3000.json','["妾本深宮妓，層城閉九重。", "君王歡愛盡，歌舞爲誰容。", "錦衾不復襞，羅衣誰再縫。", "高臺西北望，流涕向青松。"]'),
('123842a3-3c92-4df0-91fa-b266cb60ab70','羈遊餞別','王勃','唐','唐诗','tang','','[]','客心懸隴路，遊子倦江干。',48,'全唐诗/poet.tang.3000.json','["客心懸隴路，遊子倦江干。", "槿豐朝砌靜，篠密夜窗寒。", "琴聲銷別恨，風景駐離歡。", "寧覺山川遠，悠悠旅思難。"]'),
('112d4450-e99b-40e9-9240-2394ca67fdf0','易陽早發','王勃','唐','唐诗','tang','','[]','飭裝侵曉月，奔策候殘星。',48,'全唐诗/poet.tang.3000.json','["飭裝侵曉月，奔策候殘星。", "危閣尋丹障，回梁屬翠屏。", "雲間迷樹影，霧裏失峰形。", "復此涼飆至，空山飛夜螢。"]'),
('4b578bf5-9e4e-43e7-8338-ca5415237316','焦岸早行和陸四','王勃','唐','唐诗','tang','','[]','侵星違旅館，乘月戒征儔。',48,'全唐诗/poet.tang.3000.json','["侵星違旅館，乘月戒征儔。", "複嶂迷晴色，虛巖辨暗流。", "猿吟山漏曉，螢散野風秋。", "故人渺何際，鄉關雲霧浮。"]'),
('86ff7450-35ec-4af2-b942-6b4db15ca262','深灣夜宿','王勃','唐','唐诗','tang','','[]','津塗臨巨壑，村宇架危岑。',48,'全唐诗/poet.tang.3000.json','["津塗臨巨壑，村宇架危岑。", "堰絕灘聲隱，風交樹影深。", "江童暮理楫，山女夜調砧。", "此時故鄉遠，寧知遊子心。"]'),
('79640c79-b07a-49c2-a4a3-f37b4e501646','傷裴錄事喪子','王勃','唐','唐诗','tang','','[]','蘭階霜候早，松露穸臺深。',48,'全唐诗/poet.tang.3000.json','["蘭階霜候早，松露穸臺深。", "魄散珠胎沒，芳銷玉樹沈。", "露文晞宿草，煙照慘平林。", "芝焚空歡息，流恨滿籝金。"]'),
('cc836dc1-04ee-4d2c-837c-c7d3e8ba0e21','泥谿','王勃','唐','唐诗','tang','','[]','弭櫂凌奔壑，低鞭躡峻岐。',72,'全唐诗/poet.tang.3000.json','["弭櫂凌奔壑，低鞭躡峻岐。", "江濤出岸險，峰磴入雲危。", "溜急船文亂，巖斜騎影移。", "水煙籠翠渚，山照落丹崖。", "風生蘋浦葉，露泣竹潭枝。", "泛水雖云美，勞歌誰復知。"]'),
('67a82adc-0139-4386-bd11-09c4ac4a0a6d','三月曲水宴得煙字','王勃','唐','唐诗','tang','','[]','彭澤官初去，河陽賦始傳。',120,'全唐诗/poet.tang.3000.json','["彭澤官初去，河陽賦始傳。", "田園歸舊國，詩酒間長筵。", "列室窺丹洞，分樓瞰紫煙。", "縈回亙津渡，出沒控郊鄽。", "鳳琴調上客，龍轡儼羣仙。", "松石偏宜古，藤蘿不記年。", "重簷交密樹，複磴擁危泉。", "抗石晞南嶺，乘沙眇北川。", "傅巖來築處，磻谿入釣前。", "日斜真趣遠，幽思夢涼蟬。"]'),
('3111901b-f614-494c-a769-1885fd1e0176','秋日仙遊觀贈道士','王勃','唐','唐诗','tang','','[]','石圖分帝宇，銀牒洞靈宮。',72,'全唐诗/poet.tang.3000.json','["石圖分帝宇，銀牒洞靈宮。", "回丹縈岫室，複翠上巖櫳。", "霧濃金竈靜，雲暗玉壇空。", "野花常捧露，山葉自吟風。", "林泉明月在，詩酒故人同。", "待余逢石髓，從爾命飛鴻。"]'),
('77543371-3de1-4684-814a-3f3b5a132eb6','晚留鳳州','王勃','唐','唐诗','tang','','[]','寶雞辭舊役，仙鳳歷遺墟。',24,'全唐诗/poet.tang.3000.json','["寶雞辭舊役，仙鳳歷遺墟。", "去此近城闕，青山明月初。"]'),
('91cc3eca-d031-43bf-bbbd-4a48954453a7','羈春','王勃','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u4f24\u6000"]','客心千里倦，春事一朝歸。',24,'全唐诗/poet.tang.3000.json','["客心千里倦，春事一朝歸。", "還傷北園裏，重見落花飛。"]'),
('94022239-90f0-406b-a62a-3edfdbbe7ada','林塘懷友','王勃','唐','唐诗','tang','','[]','芳屏畫春草，仙杼織朝霞。',24,'全唐诗/poet.tang.3000.json','["芳屏畫春草，仙杼織朝霞。", "何如山水路，對面即飛花。"]'),
('4c5b2983-2eb6-4928-b442-8c706ed3652a','山扉夜坐','王勃','唐','唐诗','tang','','[]','抱琴開野室，攜酒對情人。',24,'全唐诗/poet.tang.3000.json','["抱琴開野室，攜酒對情人。", "林塘花月下，別似一家春。"]'),
('3a9c7db2-1ad2-41ef-b966-8eb981c8d58e','春莊','王勃','唐','唐诗','tang','','["\u7530\u56ed", "\u6292\u60c5", "\u501f\u666f\u6292\u60c5"]','山中蘭葉徑，城外李桃園。',24,'全唐诗/poet.tang.3000.json','["山中蘭葉徑，城外李桃園。", "豈知人事靜，不覺鳥聲喧。"]'),
('74e2c332-55d9-4955-8045-adbad8a66851','春遊','王勃','唐','唐诗','tang','','[]','客念紛無極，春淚倍成行。',24,'全唐诗/poet.tang.3000.json','["客念紛無極，春淚倍成行。", "今朝花樹下，不覺戀年光。"]'),
('e7ac2288-f018-4b60-975b-029396f304a4','春園','王勃','唐','唐诗','tang','','[]','山泉兩處晚，花柳一園春。',24,'全唐诗/poet.tang.3000.json','["山泉兩處晚，花柳一園春。", "還持千日醉，共作百年人。"]'),
('df5055a0-1521-437c-9a6e-ae3df8c1d153','林泉獨飲','王勃','唐','唐诗','tang','','[]','丘壑經塗賞，花柳遇時春。',24,'全唐诗/poet.tang.3000.json','["丘壑經塗賞，花柳遇時春。", "相逢今不醉，物色自輕人。"]'),
('3f765cfa-622b-4c8d-b9f3-f13440de01de','登城春望','王勃','唐','唐诗','tang','','[]','物外山川近，晴初景靄新。',24,'全唐诗/poet.tang.3000.json','["物外山川近，晴初景靄新。", "芳郊花柳遍，何處不宜春。"]'),
('358c696a-cc60-46d0-9aaf-96c0d08e5e9e','他鄉敘興','王勃','唐','唐诗','tang','','[]','綴葉歸煙晚，乘花落照春。',24,'全唐诗/poet.tang.3000.json','["綴葉歸煙晚，乘花落照春。", "邊城琴酒處，俱是越鄉人。"]'),
('d9b7ad02-abcc-4a88-ac7f-f1c1204f994b','夜興','王勃','唐','唐诗','tang','','[]','野煙含夕渚，山月照秋林。',24,'全唐诗/poet.tang.3000.json','["野煙含夕渚，山月照秋林。", "還將中散興，來偶步兵琴。"]'),
('501f2ee5-f8ba-469f-9a59-45c6be0bb91d','臨江二首 一','王勃','唐','唐诗','tang','','[]','泛泛東流水，飛飛北上塵。',24,'全唐诗/poet.tang.3000.json','["泛泛東流水，飛飛北上塵。", "歸驂將別櫂，俱是倦遊人。"]'),
('e369ad64-e4aa-48b2-94fa-8909ff3b9e0f','臨江二首 二','王勃','唐','唐诗','tang','','[]','去驂嘶別路，歸櫂隱寒洲。',24,'全唐诗/poet.tang.3000.json','["去驂嘶別路，歸櫂隱寒洲。", "江臯木葉下，應想故城秋。"]'),
('578be3ae-14e8-40ad-83b3-0164a3317373','江亭夜月送別二首 一','王勃','唐','唐诗','tang','','[]','江送巴南水，山橫塞北雲。',24,'全唐诗/poet.tang.3000.json','["江送巴南水，山橫塞北雲。", "津亭秋月夜，誰見泣離羣。"]'),
('5fbe30ba-00aa-4f75-ae59-29d303e71ef4','江亭夜月送別二首 二','王勃','唐','唐诗','tang','','[]','亂煙籠碧砌，飛月向南端。',24,'全唐诗/poet.tang.3000.json','["亂煙籠碧砌，飛月向南端。", "寂寂離亭掩，江山此夜寒。"]'),
('49b5b38a-d039-4ad1-a75e-dcae900e9dbe','別人四首 一','王勃','唐','唐诗','tang','','[]','久客逢餘閏，他鄉別故人。',24,'全唐诗/poet.tang.3000.json','["久客逢餘閏，他鄉別故人。", "自然堪下淚，誰忍望征塵。"]'),
('e76c634e-4174-4cf1-80f3-c61f8c96b541','別人四首 二','王勃','唐','唐诗','tang','','[]','江上風煙積，山幽雲霧多。',24,'全唐诗/poet.tang.3000.json','["江上風煙積，山幽雲霧多。", "送君南浦外，還望將如何。"]'),
('c8d6e176-904e-405b-a98c-7043314a33c3','別人四首 三','王勃','唐','唐诗','tang','','[]','桂軺雖不駐，蘭筵幸未開。',24,'全唐诗/poet.tang.3000.json','["桂軺雖不駐，蘭筵幸未開。", "林塘風月賞，還待故人來。"]'),
('5704085a-1f6b-4812-98de-4c01adda584f','別人四首 四','王勃','唐','唐诗','tang','','[]','霜華淨天末，霧色籠江際。',24,'全唐诗/poet.tang.3000.json','["霜華淨天末，霧色籠江際。", "客子常畏人，何爲久留滯。"]'),
('3d629eb3-160f-4d7c-8cd9-6e1b46b26d6a','贈李十四四首 一','王勃','唐','唐诗','tang','','[]','野客思茅宇，山人愛竹林。',24,'全唐诗/poet.tang.3000.json','["野客思茅宇，山人愛竹林。", "琴尊唯待處，風月自相尋。"]'),
('58378cfd-0162-4e68-9c99-d1b54158ce62','贈李十四四首 二','王勃','唐','唐诗','tang','','[]','小徑偏宜草，空庭不厭花。',24,'全唐诗/poet.tang.3000.json','["小徑偏宜草，空庭不厭花。", "平生詩與酒，自得會仙家。"]'),
('c77888f7-108b-49df-b80c-76ade79ba0e8','贈李十四四首 三','王勃','唐','唐诗','tang','','[]','亂竹開三徑，飛花滿四鄰。',24,'全唐诗/poet.tang.3000.json','["亂竹開三徑，飛花滿四鄰。", "從來揚子宅，別有尚玄人。"]'),
('a3d2eb67-d9ba-49a8-b1ec-20e573372744','贈李十四四首 四','王勃','唐','唐诗','tang','','[]','風筵調桂軫，月徑引藤杯。',24,'全唐诗/poet.tang.3000.json','["風筵調桂軫，月徑引藤杯。", "直當花院裏，書齋望曉開。"]'),
('8529e91c-0ece-4d64-8e96-2211d69e7d72','早春野望','王勃','唐','唐诗','tang','','["\u6292\u60c5", "\u6292\u60c5\u601d\u4e61", "\u7f81\u65c5", "\u5199\u666f"]','江曠春潮白，山長曉岫青。',24,'全唐诗/poet.tang.3000.json','["江曠春潮白，山長曉岫青。", "他鄉臨睨極，花柳映邊亭。"]'),
('463e1ff1-7a19-4fe0-a5c5-51908a0762a7','山中','王勃','唐','唐诗','tang','','["\u957f\u6c5f", "\u601d\u4e61", "\u5c71\u6c34"]','長江悲已滯，萬里念將歸。',24,'全唐诗/poet.tang.3000.json','["長江悲已滯，萬里念將歸。", "況屬高風晚，山山黃葉飛。"]'),
('32db4913-daec-4876-99a7-be5aca59f036','冬郊行望','王勃','唐','唐诗','tang','','[]','桂密巖花白，梨疎林葉紅。',24,'全唐诗/poet.tang.3000.json','["桂密巖花白，梨疎林葉紅。", "江臯寒望盡，歸念斷征篷。"]'),
('7bafe8f0-4495-43ad-ae2d-6396736f7d71','寒夜思友三首 一','王勃','唐','唐诗','tang','','[]','久別侵懷抱，他鄉變容色。',24,'全唐诗/poet.tang.3000.json','["久別侵懷抱，他鄉變容色。", "月下調鳴琴，相思此何極。"]'),
('b6a82d61-a77d-4561-afd4-37fa8309278a','寒夜思友三首 二','王勃','唐','唐诗','tang','','[]','雲間征思斷，月下歸愁切。',24,'全唐诗/poet.tang.3000.json','["雲間征思斷，月下歸愁切。", "鴻雁西南飛，如何故人別。"]'),
('b567b237-5a30-4794-9842-f0089386da68','寒夜思友三首 三','王勃','唐','唐诗','tang','','[]','朝朝翠山下，夜夜蒼江曲。',24,'全唐诗/poet.tang.3000.json','["朝朝翠山下，夜夜蒼江曲。", "復此遙相思，清尊湛芳綠。"]'),
('3ca4310e-22e4-442f-bae3-e0d169dcdc88','始平晚息','王勃','唐','唐诗','tang','','[]','觀闕長安近，江山蜀路賒。',24,'全唐诗/poet.tang.3000.json','["觀闕長安近，江山蜀路賒。", "客行朝復夕，無處是鄉家。"]'),
('7753d7f2-10d6-4fd4-a5d0-9d48d026fbf4','扶風晝屆離京浸遠','王勃','唐','唐诗','tang','','[]','帝里金莖去，扶風石柱來。',24,'全唐诗/poet.tang.3000.json','["帝里金莖去，扶風石柱來。", "山川殊未已，行路方悠哉。"]'),
('cbfe3479-e867-4d6a-90e2-f9f11ecb5be3','普安建陰題壁','王勃','唐','唐诗','tang','','[]','江漢深無極，梁岷不可攀。',24,'全唐诗/poet.tang.3000.json','["江漢深無極，梁岷不可攀。", "山川雲霧裏，遊子幾時還。"]'),
('f8829209-71a5-40d8-9c6b-c444f4d5ab48','九日','王勃','唐','唐诗','tang','','[]','九日重陽節，開門有菊花。',24,'全唐诗/poet.tang.3000.json','["九日重陽節，開門有菊花。", "不知來送酒，若箇是陶家。"]'),
('d89a5f6c-27c6-48fb-9204-1fafb7a7e4e1','秋江送別二首 一','王勃','唐','唐诗','tang','','[]','早是他鄉值早秋，江亭明月帶江流。',32,'全唐诗/poet.tang.3000.json','["早是他鄉值早秋，江亭明月帶江流。", "已覺逝川傷別念，復看津樹隱離舟。"]'),
('14d385f5-268a-4d8b-818c-cc4d84563be3','秋江送別二首 二','王勃','唐','唐诗','tang','','[]','歸舟歸騎儼成行，江南江北互相望。',32,'全唐诗/poet.tang.3000.json','["歸舟歸騎儼成行，江南江北互相望。", "誰謂波瀾纔一水，已覺山川是兩鄉。"]'),
('b3d9312f-1c3b-4234-b66e-1163a08c82fa','蜀中九日','王勃','唐','唐诗','tang','','["\u601d\u4e61", "\u91cd\u9633\u8282", "\u91cd\u9633"]','九月九日望鄉臺，他席他鄉送客杯。',32,'全唐诗/poet.tang.3000.json','["九月九日望鄉臺，他席他鄉送客杯。", "人情已厭南中苦，鴻雁那從北地來。"]'),
('c378da46-b638-4e25-9f2c-09ca7e4d04cd','寒夜懷友雜體二首 一','王勃','唐','唐诗','tang','','[]','北山煙霧始茫茫，南津霜月正蒼蒼。',32,'全唐诗/poet.tang.3000.json','["北山煙霧始茫茫，南津霜月正蒼蒼。", "秋深客思紛無已，復值征鴻中夜起。"]'),
('11c281c6-bae3-42d3-9ec8-170d627b158f','寒夜懷友雜體二首 二','王勃','唐','唐诗','tang','','[]','複閣重樓向浦開，秋風明月度江來。',32,'全唐诗/poet.tang.3000.json','["複閣重樓向浦開，秋風明月度江來。", "故人故情懷故宴，相望相思不相見。"]'),
('eba1605b-fbab-43b6-af79-c40f7f28fcf9','落花落','王勃','唐','唐诗','tang','','["\u6625\u5929", "\u4f24\u6000", "\u9752\u6625", "\u82b1", "\u5199\u82b1"]','落花落，落花紛漠漠。',140,'全唐诗/poet.tang.3000.json','["落花落，落花紛漠漠。", "綠葉青跗映丹萼，與君裴回上金閣。", "影拂粧階玳瑁筵，香飄舞館茱萸幙。", "落花飛，撩亂入中帷。", "落花春正滿，春人歸不歸。", "落花度，氛氳遶高樹。", "落花春已繁，春人春不顧。", "綺閣青臺靜且閑，羅袂紅巾復往還。", "盛年不再得，高枝難重攀。", "試復旦遊落花裏，暮宿落花間。", "與君落花院，臺上起雙鬟。"]'),
('3b3fc205-5d00-4e15-96cf-476ccb4a3b9b','九日懷封元寂','王勃','唐','唐诗','tang','','[]','九日郊原望，平野遍霜威。',48,'全唐诗/poet.tang.3000.json','["九日郊原望，平野遍霜威。", "蘭氣添新酌，花香染別衣。", "九秋良會少，千里故人稀。", "今日龍山外，當憶雁書歸。"]'),
('3e36b53f-264d-403d-8cd4-fb941c395269','出境遊山二首 一','王勃','唐','唐诗','tang','','[]','源水終無路，山阿若有人。',72,'全唐诗/poet.tang.3000.json','["源水終無路，山阿若有人。", "驅羊先動石，走兔欲投巾。", "洞晚秋泉冷，巖朝古樹新。", "峰斜連鳥翅，磴疊上魚鱗。", "化鶴千齡早，元龜六代春。", "浮雲今可駕，滄海自成塵。"]'),
('6b5379c3-6035-4744-977b-190900ec42f0','出境遊山二首 二','王勃','唐','唐诗','tang','','[]','振翮凌霜吹，正月佇天潯。',83,'全唐诗/poet.tang.3000.json','["振翮凌霜吹，正月佇天潯。", "回鑣凌翠壑，飛軫控青岑。", "巖深靈竈沒，澗毀石渠沈。", "宮闕雲間近，江山物外臨。", "玉壇棲暮夜，珠洞結秋陰。", "蕭蕭離俗影，擾擾望鄉心。", "誰意山遊好屢傷人事侵。"]'),
('19724209-4e31-4e6f-ad5c-df587abd403e','河陽橋代竇郎中佳人答楊中舍','王勃','唐','唐诗','tang','','[]','披風聽鳥長河路，臨津織女遙相妬。',32,'全唐诗/poet.tang.3000.json','["披風聽鳥長河路，臨津織女遙相妬。", "判知秋夕帶啼還，那及春朝攜手度。"]'),
('335f1ed5-c9d8-4cfb-a36e-26bfd12d17ab','晦日宴高氏林亭同用華字','王勔','唐','唐诗','tang','','[]','上序披林館，中京視物華。',48,'全唐诗/poet.tang.3000.json','["上序披林館，中京視物華。", "竹窗低露葉，梅逕起風花。", "景落春臺霧，池侵舊渚沙。", "綺筵歌吹晚，暮雨泛香車。"]'),
('78a53054-7cc2-4aca-b6da-94a906ce6943','奉教追赴九成宮途中口號','李嶠','唐','唐诗','tang','','[]','委質承仙翰，衹命遄遙策。',84,'全唐诗/poet.tang.3000.json','["委質承仙翰，衹命遄遙策。", "事偶從梁遊，人非背淮客。", "長驅歷川阜，迥眺窮原澤。", "鬱鬱桑柘繁，油油禾黍積。", "雨餘林氣靜，日下山光夕。", "未攀叢桂巖，猶倦飄蓬陌。", "行當奉麾蓋，慰此勞行役。"]'),
('df61c665-a241-4f93-ba1c-1e18e72dea57','秋山望月酬李騎曹','李嶠','唐','唐诗','tang','','[]','愁客坐山隈，懷抱自悠哉。',96,'全唐诗/poet.tang.3000.json','["愁客坐山隈，懷抱自悠哉。", "況復高秋夕，明月正裴回。", "亭亭出迥岫，皎皎映層臺。", "色帶銀河滿，光含玉露開。", "淡雲籠影度，虛暈抱輪回。", "谷邃涼陰靜，山空夜響哀。", "寒催數雁過，風送一螢來。", "獨軫離居恨，遙想故人杯。"]'),
('35fd0090-a805-41be-8086-41eaa191aff4','和同府李祭酒休沐田居','李嶠','唐','唐诗','tang','','[]','列位簪纓序，隱居林野躅。',120,'全唐诗/poet.tang.3000.json','["列位簪纓序，隱居林野躅。", "徇物爽全直，棲真昧均俗。", "若人兼吏隱，率性夷榮辱。", "地藉朱邸基，家在青山足。", "暫弭西園蓋，言事東臯粟。", "築室俯澗濱，開扉面巖曲。", "庭幽引夕霧，簷迥通晨旭。", "迎秋谷黍黃，含露園葵綠。", "勝情狎蘭杜，雅韻鏘金玉。", "伊我懷丘園，願心從所欲。"]'),
('e90e59e8-8270-4ff1-9ee8-ffce5a1bcc34','扈從還洛呈侍從羣官','李嶠','唐','唐诗','tang','','[]','四海帝王家，兩都周漢室。',288,'全唐诗/poet.tang.3000.json','["四海帝王家，兩都周漢室。", "觀風昔來幸，御氣今旋蹕。", "雷奮六合開，天行萬乘出。", "玄冥奉時駕，白拒參戎律。", "後隊咽笳簫，前驅嚴罕罼。", "輝光射東井，禁令橫西秩。", "帳殿別陽秋，旌門臨甲乙。", "將交洛城雨，稍遠長安日。", "邙鞏雲外來，咸秦霧中失。", "孟冬霜霰下，是月農功畢。", "天道向歸餘，皇情美陰隲。", "行存名嶽禮，逓問高年疾。", "祝鳥既開羅，調人更張瑟。", "登原采謳誦，俯谷求才術。", "邑罕懸磬貧，山無挂瓢逸。", "施恩浹寰宇，展義該文質。", "德澤盛軒遊，哀矜深禹恤。", "申歌地廬駭，獻壽衢尊溢。", "瑞色抱氤氳，寒光變蕭飋。", "宗枝旦奭輔，侍從王劉匹。", "竝輯蛟龍書，同簪鳳皇筆。", "陶甄荷吹萬，頌歎歸明一。", "歡與道路長，顧隨談笑密。", "叨承廊廟選，謬齒夔龍弼。"]'),
('6589cbe8-a115-4fd3-ab1d-d1f3d7b2f446','奉使築朔方六州城率爾而作','李嶠','唐','唐诗','tang','','[]','奉詔受邊服，總徒築朔方。',192,'全唐诗/poet.tang.3000.json','["奉詔受邊服，總徒築朔方。", "驅彼犬羊族，正此戎夏疆。", "子來多悅豫，王事寧怠遑。", "三旬無愆期，百雉鬱相望。", "雄視沙漠垂，有截北海陽。", "二庭已頓顙，五嶺盡來王。", "驅車登崇墉，顧眄凌大荒。", "千里何蕭條，草木自悲涼。", "憑軾訊古今，慨焉感興亡。", "漢障緣河遠，秦城入海長。", "顧無廟堂策，貽此中夏殃。", "道隱前業衰，運開今化昌。", "制爲百王式，舉合千載防。", "馬牛被路隅，鋒鏑銷戰場。", "豈不懷賢勞，所圖在永康。", "王事何爲者，稱代陳頌章。"]'),
('bc92d6eb-f194-40f1-a5a7-26ec7a527bfc','早發苦竹館','李嶠','唐','唐诗','tang','','[]','合沓巖嶂深，朦朧煙霧曉。',120,'全唐诗/poet.tang.3000.json','["合沓巖嶂深，朦朧煙霧曉。", "荒阡下樵客，野猿驚山鳥。", "開門聽潺湲，入徑尋窈窕。", "棲鼯抱寒木，流螢飛暗篠。", "早霞稍霏霏，殘月猶皎皎。", "行看遠星稀，漸覺遊氛少。", "我行撫軺傳，兼得傍林沼。", "貪玩水石奇，不知川路渺。", "徒憐野心曠，詎惻浮年小。", "方解寵辱情，永託累塵表。"]'),
('f79d5adb-0fd2-4ca3-a6a9-48fedfeb1804','安輯嶺表事平罷歸','李嶠','唐','唐诗','tang','','[]','雲端想京縣，帝鄉如可見。',240,'全唐诗/poet.tang.3000.json','["雲端想京縣，帝鄉如可見。", "天涯望越臺，海路幾悠哉。", "六月飛鵬去，三年瑞雉來。", "境遙銅柱出，山險石門開。", "自我違瀍洛，瞻途屢揮霍。", "朝朝寒路多，夜夜征衣薄。", "白簡承朝憲，朱方撫夷落。", "既弘天覆廣，且諭皇恩博。", "皇恩溢外區，憬俗詠來蘇。", "聲朔臣天子，壇場拜老夫。", "降宮韜將略，黃石寢兵符。", "返斾收龍虎，空營集鳥烏。", "日落澄氛靄，憑高視襟帶。", "東甌抗於越，南斗臨吳會。", "春色繞邊陲，飛花出荒外。", "卉服紛如積，長川思遊客。", "風生丹桂晚，雲起蒼梧夕。", "去舳艤清江，歸軒趨紫陌。", "衣裳會百蠻，琛賮委重關。", "不學金刀使，空持寶劒還。"]'),
('a947bd17-9765-4ca7-919e-8de26cb89824','鷓鴣','李嶠','唐','唐诗','tang','','[]','可憐鷓鴣飛，飛向樹南枝。',84,'全唐诗/poet.tang.3000.json','["可憐鷓鴣飛，飛向樹南枝。", "南枝日照暖，北枝霜露滋。", "露滋不堪棲，使我常夜啼。", "願逢雲中鶴，銜我向寥廓。", "願作城上烏，一年生九雛。", "何不舊巢住，枝弱不得去。", "何意道苦辛，客子常畏人。"]'),
('8d23adbb-2751-4d4a-b607-f7aa13d1eb95','清明日龍門遊泛','李嶠','唐','唐诗','tang','','[]','晴曉國門通，都門藹將發。',72,'全唐诗/poet.tang.3000.json','["晴曉國門通，都門藹將發。", "紛紛洛陽道，南望伊川闕。", "衍漾乘和風，清明送芬月。", "林窺二山動，水見千龕越。", "羅袂罥楊絲，香橈犯苔髮。", "羣心行樂未，唯恐流芳歇。"]'),
('3e7c7697-beed-47e7-b0df-0ba27f744fa2','雲','李嶠','唐','唐诗','tang','','[]','大梁白雲起，氛氳殊未歇。',48,'全唐诗/poet.tang.3000.json','["大梁白雲起，氛氳殊未歇。", "錦文觸石來，蓋影凌天發。", "煙煴萬年樹，掩映三秋月。", "會入大風歌，從龍赴圓闕。"]'),
('fba190c6-e609-4ba2-bda2-1ca828b71bc0','擬古東飛伯勞西飛燕','李嶠','唐','唐诗','tang','','[]','傳書青鳥迎簫鳳，巫嶺荆臺數通夢。',80,'全唐诗/poet.tang.3000.json','["傳書青鳥迎簫鳳，巫嶺荆臺數通夢。", "誰家窈窕住園樓，五馬千金照陌頭。", "羅裙玉珮當軒出，點翠施紅競春日。", "佳人二八盛舞歌，羞將百萬呈雙蛾。", "庭前芳樹朝夕改，空駐妍華欲誰待。"]'),
('8e88ad76-f833-462a-9795-8b4b998d85d7','寶劒篇','李嶠','唐','唐诗','tang','','[]','吳山開，越溪涸，三金合冶成寶鍔。',176,'全唐诗/poet.tang.3000.json','["吳山開，越溪涸，三金合冶成寶鍔。", "淬綠水，鑒紅雲，五采焰起光氛氳。", "背上銘爲萬年字，胸前點作七星文。", "龜甲參差白虹色，轆轤宛轉黃金飾。", "駭犀中斷寧方利，駿馬羣騑未擬直。", "風霜凜凜匣上清，精氣遙遙斗間明。", "避災朝穿晉帝屋，逃亂夜入楚王城。", "一朝運偶逢大仙，虎吼龍鳴騰上天。", "東皇提昇紫微座，西皇佩下赤城田。", "承平久息干戈事，僥幸得充文武備。", "除災辟患宜君王，益壽延齡後天地。"]'),
('dca19e8f-f8ce-40ce-a7f9-be985ba6d438','汾陰行','李嶠','唐','唐诗','tang','','[]','君不見昔日西京全盛時，汾陰后土親祭祠。',339,'全唐诗/poet.tang.3000.json','["君不見昔日西京全盛時，汾陰后土親祭祠。", "齋宮宿寢設儲供，撞鐘鳴鼓樹羽旂。", "漢家五葉才且雄，賓延萬靈朝九戎。", "栢梁賦詩高宴罷，詔書法駕幸河東。", "河東太守親掃除，奉迎至尊導鑾輿。", "五營夾道列容衞，三河縱觀空里閭。", "回旌駐蹕降靈場，焚香奠醑邀百祥。", "金鼎發色正焜煌，靈祇煒燁攄景光。", "埋玉陳牲禮神畢，舉麾上馬乘輿出。", "彼汾之曲嘉可遊，木蘭爲楫桂爲舟。", "櫂歌微吟綵鷁浮，簫鼓哀鳴白雲秋。", "歡娛宴洽賜羣后，家家復除戶牛酒。", "聲明動天樂無有，千秋萬歲南山壽。", "自從天子向秦關，玉輦金車不復還。", "珠簾羽扇長寂寞，鼎湖龍髯安可攀。", "千齡人事一朝空，四海爲家此路窮。", "豪雄意氣今何在，壇場宮館盡蒿篷。", "路逢故老長歎息，世事回環不可測。", "昔時青樓對歌舞，今日黃埃聚荆棘。", "山川滿目淚沾衣，富貴榮華能幾時。", "不見秪今汾水上，唯有年年秋雁飛。"]'),
('02c1a865-1cbf-48b0-aefd-4285bd77b47c','中宗降誕日長寧公主滿月侍宴應制','李嶠','唐','唐诗','tang','','[]','神龍見像日，仙鳳養雛年。',48,'全唐诗/poet.tang.3000.json','["神龍見像日，仙鳳養雛年。", "大火乘天正，明珠對月圓。", "作新金篋裏，歌奏玉筐前。", "今日宜孫慶，還參祝壽篇。"]'),
('5bad3565-fdda-4c12-a919-f2e68eccf285','奉和送金城公主適西蕃應制','李嶠','唐','唐诗','tang','','[]','漢帝撫戎臣，絲言命錦輪。',48,'全唐诗/poet.tang.3000.json','["漢帝撫戎臣，絲言命錦輪。", "還將弄機女，遠嫁織皮人。", "曲怨關山月，妝消道路塵。", "所嗟穠李樹，空對小榆春。"]'),
('cab413fe-a5b5-439b-8065-6fc0a4ca5ea1','侍宴長寧公主東莊應制','李嶠','唐','唐诗','tang','','[]','別業臨青甸，鳴鑾降紫霄。',48,'全唐诗/poet.tang.3000.json','["別業臨青甸，鳴鑾降紫霄。", "長筵鵷鷺集，仙管鳳皇調。", "樹接南山近，煙含北渚遙。", "承恩咸已醉，戀賞未還鑣。"]'),
('861e4eb6-926b-40a2-bf90-7307c462f092','立春日侍宴內殿出剪綵花應制','李嶠','唐','唐诗','tang','','[]','早聞年欲至，剪綵學芳辰。',48,'全唐诗/poet.tang.3000.json','["早聞年欲至，剪綵學芳辰。", "綴綠奇能似，裁紅巧逼真。", "花從篋裏發，葉向手中春。", "不與時光競，何名天上人。"]'),
('b8e4e120-548e-44df-8fec-df4ee2c5d575','奉和人日清暉閣宴羣臣遇雪應制','李嶠','唐','唐诗','tang','','[]','三陽偏勝節，七日最靈辰。',48,'全唐诗/poet.tang.3000.json','["三陽偏勝節，七日最靈辰。", "行慶傳芳蟻，升高綴綵人。", "階前蓂候月，樓上雪驚春。", "今日銜天造，還疑上漢津。"]'),
('f774630e-0941-4652-aa31-5a72a42d2f7e','奉和春日遊苑喜雨應制','李嶠','唐','唐诗','tang','','[]','仙蹕九成臺，香筵萬壽杯。',48,'全唐诗/poet.tang.3000.json','["仙蹕九成臺，香筵萬壽杯。", "一旬初降雨，二月早聞雷。", "葉向朝隮密，花含宿潤開。", "幸承天澤豫，無使日光催。"]'),
('e3e06bae-060c-4d38-b3df-d7ccfbb2f921','春日侍宴幸芙蓉園應制','李嶠','唐','唐诗','tang','','[]','年光竹裏遍，春色杏間遙。',48,'全唐诗/poet.tang.3000.json','["年光竹裏遍，春色杏間遙。", "煙氣籠青閣，流文蕩畫橋。", "飛花隨蝶舞，豔曲伴鸎嬌。", "今日陪歡豫，還疑陟紫霄。"]'),
('257cdf45-5dc4-4c49-91b9-eec1c7ca19f4','甘露殿侍宴應制','李嶠','唐','唐诗','tang','','[]','月宇臨丹地，雲窗網碧紗。',48,'全唐诗/poet.tang.3000.json','["月宇臨丹地，雲窗網碧紗。", "御筵陳桂醑，天酒酌榴花。", "水向浮橋直，城連禁苑斜。", "承恩恣歡賞，歸路滿煙霞。"]'),
('64d4a78b-bd8a-4e7f-a318-ff3247a1463d','奉和七夕兩儀殿會宴應制','李嶠','唐','唐诗','tang','','[]','靈匹三秋會，仙期七夕過。',48,'全唐诗/poet.tang.3000.json','["靈匹三秋會，仙期七夕過。", "查來人泛海，橋渡鵲填河。", "帝縷升銀閣，天機罷玉梭。", "誰言七襄詠，重入五弦歌。"]'),
('8bcb4b16-cfc5-41f2-9b76-d97691ddf526','奉和九月九日登慈恩寺浮圖應制','李嶠','唐','唐诗','tang','','[]','瑞塔千尋起，仙輿九日來。',48,'全唐诗/poet.tang.3000.json','["瑞塔千尋起，仙輿九日來。", "萸房陳寶席，菊橤散花臺。", "御氣鵬霄近，升高鳳野開。", "天歌將梵樂，空裏共裴回。"]'),
('6dde6faf-6d1e-4df6-ad52-1a892bf48f0c','閏九月九日幸總持寺登浮圖應制','李嶠','唐','唐诗','tang','','[]','閏節開重九，真遊下大千。',48,'全唐诗/poet.tang.3000.json','["閏節開重九，真遊下大千。", "花寒仍薦菊，座晚更披蓮。", "剎鳳回雕輦，帆虹間綵旃。", "還將西梵曲，助入南薰弦。"]'),
('9bad29f0-8b21-4bb4-80cf-6670e004b5ec','奉和驪山高頂寓目應制','李嶠','唐','唐诗','tang','','["\u534e\u5c71"]','步輦陟山巔，山高入紫煙。',48,'全唐诗/poet.tang.3000.json','["步輦陟山巔，山高入紫煙。", "忠臣還捧日，聖后欲捫天。", "迥識平陵樹，低看華嶽蓮。", "帝鄉應不遠，空見白雲懸。"]'),
('fa99a2ab-bb6e-4e8c-ad08-0fcc2bfa840a','遊禁苑陪幸臨渭亭遇雪應制','李嶠','唐','唐诗','tang','','[]','同雲接野煙，飛雪暗長天。',48,'全唐诗/poet.tang.3000.json','["同雲接野煙，飛雪暗長天。", "拂樹添梅色，過樓助粉妍。", "光含班女扇，韻入楚王弦。", "六出迎仙藻，千箱荅瑞年。"]'),
('8501300f-e169-44da-9f2e-cc04cf778bd3','幸白鹿觀應制','李嶠','唐','唐诗','tang','','[]','駐蹕三天路，回旃萬仞谿。',48,'全唐诗/poet.tang.3000.json','["駐蹕三天路，回旃萬仞谿。", "真庭羣帝饗，洞府百靈棲。", "玉酒仙壚釀，金方暗壁題。", "佇看青鳥入，還陟紫雲梯。"]'),
('80cf1172-9318-4cf0-8741-6dc63a19d038','送沙門弘景道俊玄奘還荆州應制','李嶠','唐','唐诗','tang','','[]','三乘歸淨域，萬騎餞通莊。',48,'全唐诗/poet.tang.3000.json','["三乘歸淨域，萬騎餞通莊。", "就日離亭近，彌天別路長。", "荆南旋杖鉢，渭北限津梁。", "何日紆真果，還來入帝鄉。"]'),
('a1c288ba-f606-4a59-a850-e7df1ebe42be','酬杜五弟晴朝獨坐見贈','李嶠','唐','唐诗','tang','','[]','平明坐虛館，曠望幾悠哉。',48,'全唐诗/poet.tang.3000.json','["平明坐虛館，曠望幾悠哉。", "宿霧分空盡，朝光度隙來。", "影低藤架密，香動藥闌開。", "未展山陽會，空留池上杯。"]'),
('ffac2fd4-e154-4eeb-ada3-3cc1735bea48','同賦山居七夕','李嶠','唐','唐诗','tang','','["\u5c71", "\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u63cf\u5199\u5c71", "\u5199\u5c71"]','明月青山夜，高天白露秋。',48,'全唐诗/poet.tang.3000.json','["明月青山夜，高天白露秋。", "花庭開粉席，雲岫敞針樓。", "石類支機影，池似泛槎流。", "暫驚河女鵲，終狎野人鷗。"]'),
('19987413-f4a9-43da-a091-327aebde5c73','送崔主簿赴滄州','李嶠','唐','唐诗','tang','','[]','紫陌追隨日，青門相見時。',48,'全唐诗/poet.tang.3000.json','["紫陌追隨日，青門相見時。", "宦遊從此去，離別幾年期。", "芳桂尊中酒，幽蘭下調詞。", "他鄉有明月，千里照相思。"]'),
('e7a91fc6-d915-414f-b66b-a2e7f3485026','寒食清明日早赴王門率成','李嶠','唐','唐诗','tang','','[]','遊客趨梁邸，朝光入楚臺。',48,'全唐诗/poet.tang.3000.json','["遊客趨梁邸，朝光入楚臺。", "槐煙乘曉散，榆火應春開。", "日帶晴虹上，花隨早蝶來。", "雄風乘令節，餘吹拂輕灰。"]'),
('6ef951ff-84bb-4221-b9ef-21978e8ececa','和周記室從駕曉發合璧宮','李嶠','唐','唐诗','tang','','[]','濯龍春苑曙，翠鳳曉旗舒。',48,'全唐诗/poet.tang.3000.json','["濯龍春苑曙，翠鳳曉旗舒。", "野色開煙後，山光澹月餘。", "風長笳響咽，川迥騎行疎。", "珠履陪仙駕，金聲振屬車。"]'),
('7611627b-e638-44c1-90ff-df0a944989bb','和杜侍御太清臺宿直旦有懷','李嶠','唐','唐诗','tang','','[]','貂冠朝彩振，烏署曉光分。',48,'全唐诗/poet.tang.3000.json','["貂冠朝彩振，烏署曉光分。", "欲嘯遷喬侶，先飛擲地文。", "庭虛麥雨潤，林靜蕙風薰。", "嵇駕終難仰，梁鳧且自羣。"]'),
('c5697d96-9c66-41cb-838d-11214b237e7a','和杜學士江南初霽羈懷','李嶠','唐','唐诗','tang','','[]','大江開宿雨，征櫂下春流。',48,'全唐诗/poet.tang.3000.json','["大江開宿雨，征櫂下春流。", "霧卷晴山出，風恬晚浪收。", "岸花明水樹，川鳥亂沙洲。", "羈眺傷千里，勞歌動四愁。"]'),
('c0b41c44-e9c8-4729-936f-4bb2b9f22dd1','晚景悵然簡二三子','李嶠','唐','唐诗','tang','','[]','楚客秋悲動，梁臺夕望賒。',48,'全唐诗/poet.tang.3000.json','["楚客秋悲動，梁臺夕望賒。", "梧桐稍下葉，山桂欲開花。", "氣引迎寒露，光收向晚霞。", "長歌白水曲，空對綠池華。"]'),
('2024129c-f316-45ba-9804-f5ef95b019f1','送李邕','李嶠','唐','唐诗','tang','','[]','落日荒郊外，風景正淒淒。',48,'全唐诗/poet.tang.3000.json','["落日荒郊外，風景正淒淒。", "離人席上起，征馬路傍嘶。", "別酒傾壺贈，行書掩淚題。", "殷勤御溝水，從此各東西。"]'),
('2eba40c5-1327-4592-abd3-eb22bfa16b1c','又送別','李嶠','唐','唐诗','tang','','["\u9ec4\u6cb3"]','岐路方爲客，芳尊暫解顏。',48,'全唐诗/poet.tang.3000.json','["岐路方爲客，芳尊暫解顏。", "人隨轉蓬去，春伴落梅還。", "白雲度汾水，黃河遶晉關。", "離心不可問，宿昔鬢成斑。"]'),
('2d9c9f88-bcc3-4149-8ae0-60c2e182465b','餞駱四二首 一','李嶠','唐','唐诗','tang','','[]','平生何以樂，斗酒夜相逢。',48,'全唐诗/poet.tang.3000.json','["平生何以樂，斗酒夜相逢。", "曲中驚別緒，醉裏失愁容。", "星月懸秋漢，風霜入曙鐘。", "明日臨溝水，青山幾萬重。"]'),
('db2da569-09f8-42ad-bd3a-996529f5b1b7','餞駱四二首 二','李嶠','唐','唐诗','tang','','[]','甲第驅車入，良宵秉燭遊。',48,'全唐诗/poet.tang.3000.json','["甲第驅車入，良宵秉燭遊。", "人追竹林會，酒獻菊花秋。", "霜吹飄無已，星河漫不流。", "重嗟歡賞地，翻召別離憂。"]'),
('d9a8ab76-a369-4b8e-a6b9-1770b8018d6e','春日遊苑喜雨應詔','李嶠','唐','唐诗','tang','','[]','園樓春正歸，入苑弄芳菲。',48,'全唐诗/poet.tang.3000.json','["園樓春正歸，入苑弄芳菲。", "密雨迎僊步，低雲拂御衣。", "危花霑易落，度鳥濕難飛。", "膏澤登千庾，歡情徧九圍。"]'),
('95702f89-19a0-448b-a0fe-cc656f44a783','九日應制得歡字','李嶠','唐','唐诗','tang','','[]','令節三秋晚，重陽九日歡。',48,'全唐诗/poet.tang.3000.json','["令節三秋晚，重陽九日歡。", "仙杯還泛菊，寶饌且調蘭。", "御氣雲霄近，乘高宇宙寬。", "今朝萬壽引，宜向曲中彈。"]'),
('d0e0af00-bcf4-4b3b-92e5-02a6fb564296','二月奉教作','李嶠','唐','唐诗','tang','','[]','柳陌鸎初囀，梅梁燕始歸。',48,'全唐诗/poet.tang.3000.json','["柳陌鸎初囀，梅梁燕始歸。", "和風泛紫若，柔露濯青薇。", "日豔臨花影，霞翻入浪暉。", "乘春重遊豫，淹賞玩芳菲。"]'),
('072c18d5-eac6-4a4d-a788-8655a0358639','三月奉教作','李嶠','唐','唐诗','tang','','[]','銀井桐花發，金堂草色齊。',48,'全唐诗/poet.tang.3000.json','["銀井桐花發，金堂草色齊。", "韶光愛日宇，淑氣滿風蹊。", "蝶影將花亂，虹文向水低。", "芳春隨意晚，佳賞日無暌。"]'),
('71061eb6-20eb-4e17-91df-cef021034b8e','四月奉教作','李嶠','唐','唐诗','tang','','[]','暄籥三春謝，炎鍾九夏初。',48,'全唐诗/poet.tang.3000.json','["暄籥三春謝，炎鍾九夏初。", "潤浮梅雨夕，涼散麥風餘。", "葉暗庭幃滿，花殘院錦疎。", "勝情多賞託，尊酒狎林箊。"]'),
('a3b5afe9-9af2-4597-ab55-31db2e3ad545','五月奉教作','李嶠','唐','唐诗','tang','','[]','綠樹炎氛滿，朱樓夏景長。',48,'全唐诗/poet.tang.3000.json','["綠樹炎氛滿，朱樓夏景長。", "池含凍雨氣，山映火雲光。", "果院新櫻熟，花庭曙槿芳。", "欲逃三伏暑，還泛十旬觴。"]'),
('516fe641-8a97-40eb-b164-4e44b9128dc7','六月奉教作','李嶠','唐','唐诗','tang','','[]','養日暫裴回，畏景尚悠哉。',48,'全唐诗/poet.tang.3000.json','["養日暫裴回，畏景尚悠哉。", "避暑移琴席，追涼□□□。", "竹風依扇動，桂酒溢壺開。", "勞餌□飛雪，自可□□□。"]'),
('afc65b07-68d3-4ff6-9fd6-a53e1ee89ba0','八月奉教作','李嶠','唐','唐诗','tang','','[]','黃葉秋風起，蒼葭曉露團。',48,'全唐诗/poet.tang.3000.json','["黃葉秋風起，蒼葭曉露團。", "鶴鳴初警候，雁上欲凌寒。", "月鏡如開匣，雲纓似綴冠。", "清尊對旻序，高宴有餘歡。"]'),
('7f383c99-e796-4e52-84d5-ff71677c9761','九月奉教作','李嶠','唐','唐诗','tang','','[]','曲池朝下雁，幽砌夕吟蛩。',48,'全唐诗/poet.tang.3000.json','["曲池朝下雁，幽砌夕吟蛩。", "葉徑蘭芳盡，花潭菊氣濃。", "寒催四序律，霜度九秋鐘。", "還當明月夜，飛蓋遠相從。"]'),
('930b9d56-1168-4035-936f-01e03b082803','十月奉教作','李嶠','唐','唐诗','tang','','[]','白藏初送節，玄律始迎冬。',48,'全唐诗/poet.tang.3000.json','["白藏初送節，玄律始迎冬。", "林枯黃葉盡，水耗綠池空。", "霜待臨庭月，寒隨入牖風。", "別有歡娛地，歌舞應絲桐。"]'),
('1f5738cb-d473-4ce1-9437-7c2bd18b83da','十一月奉教作','李嶠','唐','唐诗','tang','','[]','凝陰結暮序，嚴氣肅長飆。',48,'全唐诗/poet.tang.3000.json','["凝陰結暮序，嚴氣肅長飆。", "霜犯狐裘夕，寒侵獸火朝。", "冰深遙架浦，雪凍近封條。", "平原已從獵，日暮整還鑣。"]'),
('9f36a8c6-04ac-4cfd-9974-0b84358a32ed','十二月奉教作','李嶠','唐','唐诗','tang','','[]','玉燭年行盡，銅史漏猶長。',48,'全唐诗/poet.tang.3000.json','["玉燭年行盡，銅史漏猶長。", "池冷凝宵凍，庭寒積曙霜。", "蘭心未動色，梅館欲含芳。", "裴回臨歲晚，顧步佇春光。"]'),
('7af8ce3e-3a5b-4ed5-9ce3-fa1bc19fd69e','和麴典設扈從東郊憶弟使往安西冬至日恨不得同申拜慶','李嶠','唐','唐诗','tang','','[]','玉關方叱馭，桂苑正陪輿。',48,'全唐诗/poet.tang.3000.json','["玉關方叱馭，桂苑正陪輿。", "桓嶺嗟分翼，姜川限饋魚。", "雪花含□晚，雲葉帶荆舒。", "重此西流詠，彌傷南至初。"]'),
('5d0d13d4-83a6-4177-aa0e-5e588f78f796','馬武騎挽歌二首 一','李嶠','唐','唐诗','tang','','[]','五日皆休沐，三泉獨不歸。',48,'全唐诗/poet.tang.3000.json','["五日皆休沐，三泉獨不歸。", "池臺金闕是，尊酒玳筵非。", "巷靜遊禽入，門閑過客稀。", "唯餘昔年鳳，尚繞故樓飛。"]'),
('064ab8b3-6898-4e84-aa78-408fe2be7ac9','馬武騎挽歌二首 二','李嶠','唐','唐诗','tang','','[]','昔下天津館，嘗過帝子家。',48,'全唐诗/poet.tang.3000.json','["昔下天津館，嘗過帝子家。", "夜傾金屋酒，春舞玉臺花。", "試馬依紅埒，吹簫弄紫霞。", "誰言東郭路，翻枉北門車。"]'),
('3239b301-a418-45b5-87b8-00492651e264','武三思挽歌','李嶠','唐','唐诗','tang','','[]','玉匣金爲縷，銀鉤石作銘。',48,'全唐诗/poet.tang.3000.json','["玉匣金爲縷，銀鉤石作銘。", "短歌傷薤曲，長暮泣松扃。", "事往昏朝霧，人亡折夜星。", "忠賢良可惜，圖畫入丹青。"]'),
('3607ff5a-e037-4337-a24d-24f1e1759221','天官崔侍郎夫人吳氏挽歌','李嶠','唐','唐诗','tang','','[]','寵服當年盛，芳魂此地窮。',48,'全唐诗/poet.tang.3000.json','["寵服當年盛，芳魂此地窮。", "劒飛龍匣在，人去鵲巢空。", "簟愴孤生竹，琴哀半死桐。", "唯當青史上，千載仰嬪風。"]'),
('d1364291-6d58-466c-b46f-faae0adf59aa','日','李嶠','唐','唐诗','tang','','[]','旦出扶桑路，遙升若木枝。',48,'全唐诗/poet.tang.3000.json','["旦出扶桑路，遙升若木枝。", "雲間五色滿，霞際九光披。", "東陸蒼龍駕，南郊赤羽馳。", "傾心比葵藿，朝夕奉光曦。"]'),
('d0485ad4-b598-4e69-99ca-bcce11ca3832','月','李嶠','唐','唐诗','tang','','[]','桂滿三五夕，蓂開二八時。',48,'全唐诗/poet.tang.3000.json','["桂滿三五夕，蓂開二八時。", "清輝飛鵲鑑，新影學蛾眉。", "皎潔臨疎牖，玲瓏鑒薄帷。", "願言從愛客，清夜幸同嬉。"]'),
('7afa7030-e4d8-4ce0-a3ae-540aef6b119d','星','李嶠','唐','唐诗','tang','','[]','蜀郡靈槎轉，豐城寶劒新。',48,'全唐诗/poet.tang.3000.json','["蜀郡靈槎轉，豐城寶劒新。", "將軍臨北塞，天子入西秦。", "未作三台輔，寧爲五老臣。", "今宵潁川曲，誰識聚賢人。"]'),
('e3d0326f-748b-47ef-b48f-7f919dc51fca','風','李嶠','唐','唐诗','tang','','[]','落日生蘋末，搖揚徧遠林。',48,'全唐诗/poet.tang.3000.json','["落日生蘋末，搖揚徧遠林。", "帶花疑鳳舞，向竹似龍吟。", "月動臨秋扇，松清入夜琴。", "若至蘭臺下，還拂楚王襟。"]'),
('9fc3e743-366e-48da-b287-47f1377afdea','雲','李嶠','唐','唐诗','tang','','[]','英英大梁國，郁郁秘書臺。',48,'全唐诗/poet.tang.3000.json','["英英大梁國，郁郁秘書臺。", "碧落從龍起，青山觸石來。", "官名光邃古，蓋影耿輕埃。", "飛感高歌發，威加四海回。"]'),
('36b348f8-723b-46ac-ad1f-718975d7c9b3','煙','李嶠','唐','唐诗','tang','','[]','瑞氣凌青閣，空濛上翠微。',48,'全唐诗/poet.tang.3000.json','["瑞氣凌青閣，空濛上翠微。", "迥浮雙闕路，遙拂九仙衣。", "桑柘迎寒色，松篁暗晚暉。", "還當紫霄上，時接彩鸞飛。"]'),
('b9beca84-e112-4d0e-ad6d-38bdf19cb73c','露','李嶠','唐','唐诗','tang','','[]','滴瀝明花苑，葳蕤泫竹叢。',48,'全唐诗/poet.tang.3000.json','["滴瀝明花苑，葳蕤泫竹叢。", "玉垂丹棘上，珠湛綠荷中。", "夜警千年鶴，朝零七月風。", "願凝仙掌內，長奉未央宮。"]'),
('14c5e015-a89f-4d2e-940e-6a6f5a73a5e1','霧','李嶠','唐','唐诗','tang','','[]','曹公迷楚澤，漢帝出平城。',48,'全唐诗/poet.tang.3000.json','["曹公迷楚澤，漢帝出平城。", "涿鹿妖氛靜，丹山霽色明。", "類煙飛稍重，方雨散還輕。", "倘入非熊兆，寧思玄豹情。"]'),
('d75523f4-e43d-4058-9ab5-fd687da6eeaf','雨','李嶠','唐','唐诗','tang','','[]','西北雲膚起，東南雨足來。',48,'全唐诗/poet.tang.3000.json','["西北雲膚起，東南雨足來。", "靈童出海見，神女向臺回。", "斜影風前合，圓文水上開。", "十旬無破塊，九土信康哉。"]'),
('8b64674e-d343-4280-aa6a-7f627a3199f0','雪','李嶠','唐','唐诗','tang','','[]','瑞雪驚千里，同雲暗九霄。',48,'全唐诗/poet.tang.3000.json','["瑞雪驚千里，同雲暗九霄。", "地疑明月夜，山似白雲朝。", "逐舞花光動，臨歌扇影飄。", "大周天闕路，今日海神朝。"]'),
('fa89d51f-0825-4ca4-b1bf-2ba82f6df85f','山','李嶠','唐','唐诗','tang','','[]','地鎮標神秀，峩峩上翠氛。',48,'全唐诗/poet.tang.3000.json','["地鎮標神秀，峩峩上翠氛。", "泉飛一道帶，峰出半天雲。", "古壁丹青色，新花綺繡紋。", "已開封禪所，希謁聖明君。"]'),
('e35050b4-a0a9-4139-9cef-988035c989b7','石','李嶠','唐','唐诗','tang','','[]','宗子維城固，將軍飲羽威。',48,'全唐诗/poet.tang.3000.json','["宗子維城固，將軍飲羽威。", "巖花鑑裏發，雲葉錦中飛。", "入宋星初隕，過湘燕早歸。", "倘因持補極，寧復想支機。"]'),
('0517344d-0a33-4886-b6ef-8500130c0843','原','李嶠','唐','唐诗','tang','','[]','王粲銷憂日，江淹起恨年。',48,'全唐诗/poet.tang.3000.json','["王粲銷憂日，江淹起恨年。", "帶川遙綺錯，分隰迥阡眠。", "□□橫周甸，莓苔闕晉田。", "方知急難響，長在脊令篇。"]'),
('d4ca0c33-b893-44d1-8595-7843bb245d6b','野','李嶠','唐','唐诗','tang','','[]','鳳出秦郊迥，鶉飛楚塞空。',48,'全唐诗/poet.tang.3000.json','["鳳出秦郊迥，鶉飛楚塞空。", "蒼梧雲影去，涿鹿霧光通。", "草暗少原綠，花明入蜀紅。", "誰言版築士，猶處傅巖中。"]'),
('ff79eefc-5a5c-47ad-8ff8-4ca20623c199','田','李嶠','唐','唐诗','tang','','[]','貢禹懷書日，張衡作賦辰。',48,'全唐诗/poet.tang.3000.json','["貢禹懷書日，張衡作賦辰。", "杏花開鳳軫，菖葉布龍鱗。", "瑞麥兩岐秀，嘉禾同穎新。", "寧知帝王力，擊壤自安貧。"]'),
('4ec0acdd-6c4a-44bc-b3c4-b747333038e8','道','李嶠','唐','唐诗','tang','','[]','銅駝分鞏洛，劒閣低臨邛。',48,'全唐诗/poet.tang.3000.json','["銅駝分鞏洛，劒閣低臨邛。", "紫徼三千里，青樓十二重。", "玉關塵似雪，金穴馬如龍。", "今日中衢上，堯尊更可逢。"]'),
('449c1e29-4d2f-4c39-844f-ed9c871fe86b','海','李嶠','唐','唐诗','tang','','[]','習坎疏丹壑，朝宗合紫微。',48,'全唐诗/poet.tang.3000.json','["習坎疏丹壑，朝宗合紫微。", "三山巨鰲湧，萬里大鵬飛。", "樓寫春雲色，珠含明月輝。", "會因添霧露，方逐衆川歸。"]'),
('d781f001-b6ff-4295-a46e-29549cd91b3a','江','李嶠','唐','唐诗','tang','','[]','日夕三江望，靈潮萬里回。',48,'全唐诗/poet.tang.3000.json','["日夕三江望，靈潮萬里回。", "霞津錦浪動，月浦練花開。", "湍似黃牛去，濤從白馬來。", "英靈已傑出，誰識卿雲才。"]'),
('2f3275bc-c175-405d-b572-283f14ee0393','河','李嶠','唐','唐诗','tang','','[]','源出崑崙中，長波接漢空。',48,'全唐诗/poet.tang.3000.json','["源出崑崙中，長波接漢空。", "桃花來馬頰，竹箭入龍宮。", "德水千年變，榮光五色通。", "若披蘭葉檢，□□□□□。"]'),
('4948865b-2700-46bc-9db5-3d99ec79887d','洛','李嶠','唐','唐诗','tang','','[]','九洛韶光媚，三川物候新。',48,'全唐诗/poet.tang.3000.json','["九洛韶光媚，三川物候新。", "花明丹鳳浦，日映玉雞津。", "元禮期仙客，陳王覩麗人。", "神龜方錫瑞，綠字重來臻。"]'),
('2ac89ae6-497f-4c7f-9f72-b394e87da15f','城','李嶠','唐','唐诗','tang','','[]','四塞稱天府，三河建洛都。',48,'全唐诗/poet.tang.3000.json','["四塞稱天府，三河建洛都。", "飛雲靄層闕，白日麗南隅。", "獨下仙人鳳，羣驚御史烏。", "何辭一萬里，邊徼捍匈奴。"]'),
('58adb9ca-7b50-420b-8216-a08ac25142b8','門','李嶠','唐','唐诗','tang','','[]','奕奕彤闈下，煌煌紫禁隈。',48,'全唐诗/poet.tang.3000.json','["奕奕彤闈下，煌煌紫禁隈。", "阿房萬戶列，閶闔九重開。", "疏廣遺榮去，于公待駟來。", "詎知金馬側，方朔有奇才。"]'),
('5c8547d4-2957-40a2-b8a7-641533a0dfd5','市','李嶠','唐','唐诗','tang','','[]','闤闠開三市，旗亭起百尋。',50,'全唐诗/poet.tang.3000.json','["闤闠開三市，旗亭起百尋。", "漸離初擊筑，司馬正彈琴。", "細柳龍鱗映，長槐兔月陰。", "徒知觀衞玉，詎肯挂秦[金]。"]'),
('2eec472e-c0a4-4f1b-acfa-fc7c70bfa613','井','李嶠','唐','唐诗','tang','','[]','玉甃談仙客，銅臺賞魏君。',48,'全唐诗/poet.tang.3000.json','["玉甃談仙客，銅臺賞魏君。", "蜀都宵映火，杞國旦生雲。", "向日蓮花淨，含風李樹薰。", "已開千里國，還聚五星文。"]'),
('b8a983e7-7949-46b4-850a-0ee9bd8b1dc5','宅','李嶠','唐','唐诗','tang','','[]','寂寞蓬蒿徑，喧喧湫隘廬。',48,'全唐诗/poet.tang.3000.json','["寂寞蓬蒿徑，喧喧湫隘廬。", "屢逢長者轍，時引故人車。", "孟母遷鄰罷，將軍辭第初。", "誰憐草玄處，獨對一牀書。"]'),
('2a90fe0d-cdca-4791-a39d-2f7267de596a','池','李嶠','唐','唐诗','tang','','[]','綵櫂浮太液，清觸醉習家。',48,'全唐诗/poet.tang.3000.json','["綵櫂浮太液，清觸醉習家。", "詩情對明月，雲曲拂流霞。", "煙散龍形淨，波含鳳影斜。", "安仁動秋興，魚鳥思空賒。"]'),
('643e4251-5f95-42f7-a47b-3cd8f22a5788','樓','李嶠','唐','唐诗','tang','','[]','百尺重城際，千尋大道隈。',48,'全唐诗/poet.tang.3000.json','["百尺重城際，千尋大道隈。", "漢宮井幹起，吳國落星開。", "笛怨綠珠去，簫隨弄玉來。", "銷憂聊暇日，誰識仲宣才。"]'),
('88e4583d-fed2-475f-94b3-a84942ca27e5','橋','李嶠','唐','唐诗','tang','','[]','烏鵲填應滿，黃公去不歸。',48,'全唐诗/poet.tang.3000.json','["烏鵲填應滿，黃公去不歸。", "勢疑虹始見，形似雁初飛。", "妙應七星制，高分半月輝。", "秦王空構石，仙島遠難依。"]'),
('84c62f31-3a77-4034-92f0-20969583331b','經','李嶠','唐','唐诗','tang','','[]','漢室鴻儒盛，鄒堂大義明。',48,'全唐诗/poet.tang.3000.json','["漢室鴻儒盛，鄒堂大義明。", "五千道德闡，三百禮儀成。", "青紫方拾芥，黃金徒滿籝。", "誰知懷逸辯，重席冠羣英。"]'),
('57dc272c-0712-4be2-b101-039370e751d8','史','李嶠','唐','唐诗','tang','','[]','馬記天官設，班圖地里新。',48,'全唐诗/poet.tang.3000.json','["馬記天官設，班圖地里新。", "善談方亹亹，青簡見彬彬。", "方朔初聞漢，荆軻昔向秦。", "正辭堪載筆，終翼作良臣。"]'),
('7e8a2600-17dc-42a7-877f-a9bd9903fbc8','詩','李嶠','唐','唐诗','tang','','[]','都尉仙鳧遠，梁王駟馬來。',48,'全唐诗/poet.tang.3000.json','["都尉仙鳧遠，梁王駟馬來。", "扇中紈素製，機上錦紋回。", "天子三章傳，陳王七步才。", "緇衣久擅美，祖德信悠哉。"]'),
('2c9991b7-27bc-475d-ab9b-0bd823a3a262','賦','李嶠','唐','唐诗','tang','','[]','布義孫卿子，登高楚屈平。',48,'全唐诗/poet.tang.3000.json','["布義孫卿子，登高楚屈平。", "銅臺初下筆，樂觀正飛纓。", "乍有凌雲勢，時聞擲地聲。", "造端長體物，無復大夫名。"]'),
('f94dca29-03ac-46b6-819f-735420ba9e15','書','李嶠','唐','唐诗','tang','','[]','削簡龍文見，臨池鳥跡舒。',48,'全唐诗/poet.tang.3000.json','["削簡龍文見，臨池鳥跡舒。", "河圖八卦出，洛範九疇初。", "垂露春光滿，崩雲骨氣餘。", "請君看入木，一寸乃非虛。"]'),
('6264d50d-694c-4bc9-ba05-478b7112b38b','檄','李嶠','唐','唐诗','tang','','[]','羽檄本宣明，由來□木聲。',48,'全唐诗/poet.tang.3000.json','["羽檄本宣明，由來□木聲。", "聯翩至漢國，迢遞入燕營。", "毛義持書去，張儀韞璧行。", "曹風雖覺愈，陳草始知名。"]'),
('78336beb-4303-44ee-9bdb-a73a60d10632','紙','李嶠','唐','唐诗','tang','','[]','妙跡蔡侯施，芳名左伯馳。',48,'全唐诗/poet.tang.3000.json','["妙跡蔡侯施，芳名左伯馳。", "雲飛錦綺落，花發縹紅披。", "舒卷隨幽顯，廉方合軌儀。", "莫驚反掌字，當取葛洪規。"]'),
('49ff9409-dfa1-453f-bda0-99338c887827','筆','李嶠','唐','唐诗','tang','','[]','握管門庭側，含毫山水隈。',48,'全唐诗/poet.tang.3000.json','["握管門庭側，含毫山水隈。", "霜輝簡上發，錦字夢中開。", "鸚鵡摛文至，麒麟絕句來。", "何當遇良史，左右振奇才。"]'),
('aaa3bb77-c811-4b28-9f52-7483ae920a58','硯','李嶠','唐','唐诗','tang','','[]','左思裁賦日，王充作論年。',48,'全唐诗/poet.tang.3000.json','["左思裁賦日，王充作論年。", "光隨錦文發，形帶石巖圓。", "積潤循毫裏，開池小學前。", "君苗徒見爇，誰詠士衡篇。"]'),
('e63a4bef-7dd3-4b75-bdda-864a939129e2','墨','李嶠','唐','唐诗','tang','','[]','長安分石炭，上黨結松心。',48,'全唐诗/poet.tang.3000.json','["長安分石炭，上黨結松心。", "遶畫蠅初落，含滋綬更深。", "悲絲光易染，疊素彩還沈。", "別有張芝學，書池幸見臨。"]'),
('7957a3ac-59fb-4e4b-9077-a7235a312295','劒','李嶠','唐','唐诗','tang','','[]','我有昆吾劒，求趨夫子庭。',48,'全唐诗/poet.tang.3000.json','["我有昆吾劒，求趨夫子庭。", "白虹時切玉，紫氣夜干星。", "鍔上芙蓉動，匣中霜雪明。", "倚天持報國，畫地取雄名。"]'),
('84bc68a8-84c6-46a6-a266-318f3806426a','刀','李嶠','唐','唐诗','tang','','[]','列辟鳴鸞至，惟良佩犢旋。',48,'全唐诗/poet.tang.3000.json','["列辟鳴鸞至，惟良佩犢旋。", "帶環疑寫月，引鑑似含泉。", "入夢華梁上，含鋒彩筆前。", "莫驚開百鍊，特擬定三邊。"]'),
('03cc350a-cb78-45b5-b965-2d68e098b9fa','箭','李嶠','唐','唐诗','tang','','[]','漢甸初收羽，燕城忽解圍。',48,'全唐诗/poet.tang.3000.json','["漢甸初收羽，燕城忽解圍。", "影隨流水急，光帶落星飛。", "夏列三成範，堯沈九日輝。", "斷蛟雲夢澤，希爲識忘歸。"]'),
('cfd16646-8adb-4141-9611-cd1676ceaaf0','彈','李嶠','唐','唐诗','tang','','[]','俠客持蘇合，佳遊滿帝鄉。',48,'全唐诗/poet.tang.3000.json','["俠客持蘇合，佳遊滿帝鄉。", "避丸深可誚，求炙遂難忘。", "金迸疑星落，珠沈似月光。", "誰知少孺子，將此見吳王。"]'),
('941b344e-9012-4f27-8e13-8794df431dc4','弩','李嶠','唐','唐诗','tang','','[]','挺質本軒皇，申威振遠方。',48,'全唐诗/poet.tang.3000.json','["挺質本軒皇，申威振遠方。", "機張驚雉雊，玉彩耀星芒。", "高鳥行應盡，清猿坐見傷。", "蘇秦六百步，持此說韓王。"]'),
('2fc25265-ce6b-4c35-9045-4bc74c6c9435','旗','李嶠','唐','唐诗','tang','','[]','桂影承宵月，虹輝接曙雲。',48,'全唐诗/poet.tang.3000.json','["桂影承宵月，虹輝接曙雲。", "縱橫齊八陣，舒卷引三軍。", "日薄蛟龍影，風翻鳥隼文。", "誰知懷勇志，蟠地幾繽紛。"]'),
('43cc3e5d-0580-449f-89dc-2286e97384f5','旌','李嶠','唐','唐诗','tang','','[]','告善康莊側，求賢市肆中。',48,'全唐诗/poet.tang.3000.json','["告善康莊側，求賢市肆中。", "擁麾分彩雉，持節曳丹虹。", "影麗天山雪，光搖朔塞風。", "方知美周政，抗斾賦車攻。"]'),
('4d441de9-4d5b-4adb-89de-8278f360645d','戈','李嶠','唐','唐诗','tang','','[]','富父舂喉日，殷辛漂杵年。',48,'全唐诗/poet.tang.3000.json','["富父舂喉日，殷辛漂杵年。", "曉霜含白刃，落影駐雕鋋。", "夕擯金門側，朝提玉塞前。", "願隨龍影度，橫□陣雲邊。"]'),
('d6eed09b-5530-419e-871a-53f46e97aa20','鼓','李嶠','唐','唐诗','tang','','[]','舜日諧鼗響，堯年韻土聲。',48,'全唐诗/poet.tang.3000.json','["舜日諧鼗響，堯年韻土聲。", "向樓疑吹擊，震谷似雷驚。", "仙鶴排門起，靈鼉帶水鳴。", "樂云行已奏，禮曰冀相成。"]'),
('4a45418e-84c6-4d19-abdf-77cace7ed5d6','弓','李嶠','唐','唐诗','tang','','[]','桃文稱辟惡，桑質表初生。',48,'全唐诗/poet.tang.3000.json','["桃文稱辟惡，桑質表初生。", "宛轉雕鞬際，依稀半月明。", "遙彎落雁影，虛引怯猿聲。", "徒切烏號思，攀龍遂不成。"]'),
('7c3f21a1-9339-41ed-b1e3-be98739609b1','琴','李嶠','唐','唐诗','tang','','[]','名士竹林隈，鳴琴寶匣開。',48,'全唐诗/poet.tang.3000.json','["名士竹林隈，鳴琴寶匣開。", "風前中散至，月下步兵來。", "淮海多爲室，梁岷舊作臺。", "子期如可聽，山水響餘哀。"]'),
('3e74207a-974e-402e-9f3b-6ee6cd3f8800','琴','李嶠','唐','唐诗','tang','','[]','隱士竹林隈，英聲寳匣開。',48,'全唐诗/poet.tang.3000.json','["隱士竹林隈，英聲寳匣開。", "風前緑綺弄，月下白雲來。", "淮海多為室，梁岷舊作臺。", "子期如可聴，山水響餘哀。"]'),
('985a9b93-e0e1-413f-870b-de79f53da0e2','瑟','李嶠','唐','唐诗','tang','','[]','伏羲初製法，素女昔傳名。',48,'全唐诗/poet.tang.3000.json','["伏羲初製法，素女昔傳名。", "流水嘉魚躍，叢臺舞鳳驚。", "嘉賓飲未極，君子娛俱幷。", "倘入丘之戶，應知由也情。"]'),
('82711625-5102-4f21-9239-8eebc9080ea4','琵琶','李嶠','唐','唐诗','tang','','[]','朱絲聞岱谷，鑠質本多端。',48,'全唐诗/poet.tang.3000.json','["朱絲聞岱谷，鑠質本多端。", "半月分弦出，叢花拂面安。", "將軍曾制曲，司馬屢陪觀。", "本是胡中樂，希君馬上彈。"]'),
('00ca9ba7-1c54-487b-b0dd-27cc35401090','箏','李嶠','唐','唐诗','tang','','[]','蒙恬芳軌設，遊楚妙彈開。',48,'全唐诗/poet.tang.3000.json','["蒙恬芳軌設，遊楚妙彈開。", "新曲帳中發，清音指下來。", "鈿裝模六律，柱列配三才。", "莫聽西秦奏，箏箏有剩哀。"]'),
('d011903c-7ae4-45fd-9527-88afd7ee11cb','鐘','李嶠','唐','唐诗','tang','','[]','既接南鄰磬，還隨北里笙。',48,'全唐诗/poet.tang.3000.json','["既接南鄰磬，還隨北里笙。", "平陵通曙響，長樂警宵聲。", "秋至含霜動，春歸應律鳴。", "欲知常待扣，金簴有餘清。"]'),
('fac4ec75-dc9e-40eb-a6ad-6a64a9ef79c6','簫','李嶠','唐','唐诗','tang','','[]','虞舜調清管，王襃賦雅音。',48,'全唐诗/poet.tang.3000.json','["虞舜調清管，王襃賦雅音。", "參差橫鳳翼，搜索動人心。", "□□□□□，□□□□□。", "□□□□□，□□□□□。"]'),
('8daf87ab-507b-4749-9990-6b32efeaa7cc','笛','李嶠','唐','唐诗','tang','','[]','羗笛寫龍聲，長吟入夜清。',48,'全唐诗/poet.tang.3000.json','["羗笛寫龍聲，長吟入夜清。", "關山孤月下，來向隴頭鳴。", "逐吹梅花落，含春柳色驚。", "行觀向子賦，坐憶舊鄰情。"]'),
('f9d34d79-392b-497b-839b-ace1e4f80dd5','笙','李嶠','唐','唐诗','tang','','[]','懸匏曲沃上，孤篠汶陽隈。',48,'全唐诗/poet.tang.3000.json','["懸匏曲沃上，孤篠汶陽隈。", "形寫歌鸞翼，聲隨舞鳳哀。", "歡娛分北里，純孝即南陔。", "今日虞音奏，蹌蹌鳥獸來。"]'),
('29c300b2-0ccf-400a-8a13-ae8d693030ae','歌','李嶠','唐','唐诗','tang','','[]','漢帝臨汾水，周仙去洛濱。',48,'全唐诗/poet.tang.3000.json','["漢帝臨汾水，周仙去洛濱。", "郢中吟白雪，梁上繞飛塵。", "響發行雲駐，聲隨子夜新。", "願君聽扣角，當自識賢臣。"]'),
('fc3ac7dd-d3b8-4dff-af44-efb2a529cd25','舞','李嶠','唐','唐诗','tang','','[]','妙伎遊金谷，佳人滿石城。',48,'全唐诗/poet.tang.3000.json','["妙伎遊金谷，佳人滿石城。", "霞衣席上轉，花岫雪前明。", "儀鳳諧清曲，回鸞應雅聲。", "非君一顧重，誰賞素腰輕。"]'),
('f060ba9d-27f7-46c4-b566-010e181c2664','珠','李嶠','唐','唐诗','tang','','[]','燦爛金輿側，玲瓏玉殿隈。',48,'全唐诗/poet.tang.3000.json','["燦爛金輿側，玲瓏玉殿隈。", "昆池明月滿，合浦夜光回。", "彩逐靈蛇轉，行隨舞鳳來。", "甘泉宮起罷，花媚望風臺。"]'),
('39e171f2-dbc2-432e-9505-d5b6d47a3a0a','玉','李嶠','唐','唐诗','tang','','[]','映石先過魏，連城欲向秦。',48,'全唐诗/poet.tang.3000.json','["映石先過魏，連城欲向秦。", "洛陽陪勝友，燕趙類佳人。", "方水晴虹媚，常山瑞馬新。", "徒爲卞和識，不遇楚王珍。"]'),
('d4174d1a-5436-41d3-b619-7a1abb48b943','金','李嶠','唐','唐诗','tang','','[]','南楚標前貢，西秦識舊城。',48,'全唐诗/poet.tang.3000.json','["南楚標前貢，西秦識舊城。", "祭天封漢嶺，擲地警孫聲。", "向日披沙淨，含風振鐸鳴。", "方同楊伯起，獨有四知名。"]'),
('d41b10f4-00e6-4a37-b860-f720c3ff5a3e','銀','李嶠','唐','唐诗','tang','','[]','思婦屏輝掩，遊人燭影長。',48,'全唐诗/poet.tang.3000.json','["思婦屏輝掩，遊人燭影長。", "玉壺初下箭，桐井共安牀。", "色帶長河色，光浮滿月光。", "靈山有珍甕，仙闕薦君王。"]'),
('23cb2e95-cafb-44a2-ab19-2d4f2e828c81','錢','李嶠','唐','唐诗','tang','','[]','漢日五銖建，姬年九府流。',48,'全唐诗/poet.tang.3000.json','["漢日五銖建，姬年九府流。", "天龍帶泉寶，地馬列金溝。", "趙壹囊初乏，何曾箸欲收。", "金門應入論，玉井冀來求。"]'),
('ecc0070b-7766-4797-bb06-5998eacb08d2','錦','李嶠','唐','唐诗','tang','','[]','漢使巾車遠，河陽步障陳。',48,'全唐诗/poet.tang.3000.json','["漢使巾車遠，河陽步障陳。", "雲浮仙石日，霞滿蜀江春。", "機迥回文巧，紳兼束髪新。", "若逢楚王貴，不作夜行人。"]'),
('77a14021-e3ed-46b1-96fe-d70e97fa7e17','羅','李嶠','唐','唐诗','tang','','[]','妙舞隨裙動，行歌入扇清。',48,'全唐诗/poet.tang.3000.json','["妙舞隨裙動，行歌入扇清。", "蓮花依帳發，秋月鑒帷明。", "雲薄衣初捲，蟬飛翼轉輕。", "若珍三代服，同擅綺紈名。"]'),
('cb03871c-ff9b-4c9c-8205-9fae833ee55f','綾','李嶠','唐','唐诗','tang','','[]','金縷通秦國，爲裘指魏君。',48,'全唐诗/poet.tang.3000.json','["金縷通秦國，爲裘指魏君。", "落花遙寫霧，飛鶴近圖雲。", "馬眼冰凌影，竹根雪霰文。", "何當畫秦女，煙際坐氤氳。"]'),
('4da76ae6-03d6-4c12-a834-f05376f803b0','素','李嶠','唐','唐诗','tang','','[]','□□□□女，纖腰洛浦妃。',48,'全唐诗/poet.tang.3000.json','["□□□□女，纖腰洛浦妃。", "□□遠方望，雁足上林飛。", "妙奪鮫綃色，光騰月扇輝。", "非君下路去，誰賞故人機。"]'),
('a5c4f85a-fe05-4762-aea9-b47ec2b00f45','布','李嶠','唐','唐诗','tang','','[]','御績創羲黃，緇冠表素王。',48,'全唐诗/poet.tang.3000.json','["御績創羲黃，緇冠表素王。", "瀑飛臨碧海，火浣擅炎方。", "孫被登三相，劉衣闡四方。", "佇因舂斗粟，來曉棣華芳。"]'),
('8fa0eee9-157b-4ff3-a1e6-ac0f509dfe95','舟','李嶠','唐','唐诗','tang','','[]','征櫂三江暮，連檣萬里回。',48,'全唐诗/poet.tang.3000.json','["征櫂三江暮，連檣萬里回。", "相烏風際轉，畫鷁浪前開。", "羽客乘霞至，仙人弄月來。", "何當同傅說，特展巨川材。"]'),
('e41d18ad-3b3a-4185-a609-a916908bb01f','車','李嶠','唐','唐诗','tang','','[]','天子馭金根，蒲輪闢四門。',48,'全唐诗/poet.tang.3000.json','["天子馭金根，蒲輪闢四門。", "五神趨雪至，雙轂似雷奔。", "丹鳳棲金轄，非熊載寶軒。", "無階忝虛左，珠乘奉王言。"]'),
('87734cde-e40f-42ce-937d-59cd2b198cc9','牀','李嶠','唐','唐诗','tang','','[]','傳聞有象牀，疇昔獻君王。',48,'全唐诗/poet.tang.3000.json','["傳聞有象牀，疇昔獻君王。", "玳瑁千金起，珊瑚七寶妝。", "桂筵含柏馥，蘭席拂沈香。", "願奉羅帷夜，長乘秋月光。"]'),
('c6678e73-d4ee-4b39-8dd9-81a4bb5d5c2d','席','李嶠','唐','唐诗','tang','','[]','避席承宣父，重筵揖戴公。',48,'全唐诗/poet.tang.3000.json','["避席承宣父，重筵揖戴公。", "桂香浮半月，蘭氣襲回風。", "舞拂丹霞上，歌清白雪中。", "佇將文綺色，舒卷帝王宮。"]'),
('3becd0ae-ea65-4936-997f-0030d305dde4','帷','李嶠','唐','唐诗','tang','','[]','久閉先生戶，高褰太守車。',48,'全唐诗/poet.tang.3000.json','["久閉先生戶，高褰太守車。", "羅將翡翠合，錦逐鳳皇舒。", "明月彈琴夜，清風入幌初。", "方知決勝策，黃石受兵書。"]'),
('f34ae469-7eb2-420f-9d65-41540ea931ee','簾','李嶠','唐','唐诗','tang','','[]','清風時入燕，紫殿幾含秋。',48,'全唐诗/poet.tang.3000.json','["清風時入燕，紫殿幾含秋。", "曖曖籠鈴閣，纖纖上玉鉤。", "窗中翡翠動，戶外水精浮。", "巧作盤龍勢，長迎飛燕遊。"]'),
('1a559f0f-e54a-4208-84d2-36bc6392ffc0','屏','李嶠','唐','唐诗','tang','','[]','洞徹琉璃蔽，威紆屈膝回。',48,'全唐诗/poet.tang.3000.json','["洞徹琉璃蔽，威紆屈膝回。", "錦中雲母列，霞上織成開。", "山上含春動，神仙倒景來。", "脩身兼竭節，誰識作銘才。"]'),
('bb562a18-61b6-4bff-9199-7c6e11e2855e','被','李嶠','唐','唐诗','tang','','[]','桂友尋東閣，蘭交聚北堂。',48,'全唐诗/poet.tang.3000.json','["桂友尋東閣，蘭交聚北堂。", "象筵分錦繡，羅薦合鴛鴦。", "光逸偷眠穩，王章泣恨長。", "孔懷欣共寢，棣萼幾含芳。"]'),
('be15183e-ac11-4df8-becd-802fd6d376ee','鑑','李嶠','唐','唐诗','tang','','[]','明鑑掩塵埃，含情照魏臺。',48,'全唐诗/poet.tang.3000.json','["明鑑掩塵埃，含情照魏臺。", "日中烏鵲至，花裏鳳皇來。", "玉彩疑冰徹，金輝似月開。", "方知樂彥輔，自有鑒人才。"]'),
('78066d78-48e6-480c-8d07-f789f103b614','扇','李嶠','唐','唐诗','tang','','[]','翟羽舊傳名，蒲葵價不輕。',48,'全唐诗/poet.tang.3000.json','["翟羽舊傳名，蒲葵價不輕。", "花芳不滿面，羅薄詎障聲。", "禦熱含風細，臨秋帶月明。", "同心如可贈，持表合歡情。"]'),
('5f1cacdf-ff25-4110-9273-d12f486d410a','燭','李嶠','唐','唐诗','tang','','[]','兔月清光隱，龍盤畫燭新。',48,'全唐诗/poet.tang.3000.json','["兔月清光隱，龍盤畫燭新。", "三星花入夜，四序玉調晨。", "浮炷依羅幌，吹香匝綺茵。", "若逢燕國相，持用舉賢人。"]'),
('65104886-e39a-4fcb-af82-343115df6d5b','酒','李嶠','唐','唐诗','tang','','[]','孔坐洽良儔，陳筵幾獻酬。',48,'全唐诗/poet.tang.3000.json','["孔坐洽良儔，陳筵幾獻酬。", "臨風竹葉滿，湛月桂香浮。", "每接高陽宴，長陪河朔遊。", "會從玄石飲，雲雨出圓丘。"]'),
('ebab8cfc-f58d-46f3-9e58-88f5f65fc390','蘭','李嶠','唐','唐诗','tang','','[]','虛室重招尋，忘言契斷金。',48,'全唐诗/poet.tang.3000.json','["虛室重招尋，忘言契斷金。", "英浮漢家酒，雪儷楚王琴。", "廣殿輕香發，高臺遠吹吟。", "河汾應擢秀，誰肯訪山陰。"]'),
('8fee5db3-d6de-4569-8bf8-58982e99902e','菊','李嶠','唐','唐诗','tang','','[]','玉律三秋暮，金精九日開。',48,'全唐诗/poet.tang.3000.json','["玉律三秋暮，金精九日開。", "榮舒洛媛浦，香泛野人杯。", "靃靡寒潭側，丰茸曉岸隈。", "黃花今日晚，無復白衣來。"]'),
('edc80b2b-224d-4759-9d03-5f02c6515c32','竹','李嶠','唐','唐诗','tang','','[]','高簳楚江濆，嬋娟含曙氛。',48,'全唐诗/poet.tang.3000.json','["高簳楚江濆，嬋娟含曙氛。", "白花搖鳳影，青節動龍文。", "葉埽東南日，枝捎西北雲。", "誰知湘水上，流淚獨思君。"]'),
('d56b4fae-8941-4f08-a0ee-9ba662d03646','藤','李嶠','唐','唐诗','tang','','[]','吐葉依松磴，舒苗長石臺。',48,'全唐诗/poet.tang.3000.json','["吐葉依松磴，舒苗長石臺。", "神農嘗藥罷，質子寄書來。", "色映蒲萄架，花分竹葉杯。", "金堤不見識，玉潤幾重開。"]'),
('2c994d39-eea3-4384-8f4e-1996f6004a03','萱','李嶠','唐','唐诗','tang','','[]','屣步尋芳草，忘憂自結叢。',48,'全唐诗/poet.tang.3000.json','["屣步尋芳草，忘憂自結叢。", "黃英開養性，綠葉正依籠。", "色湛仙人露，香傳少女風。", "還依北堂下，曹植動文雄。"]'),
('08dc1b87-9585-46e0-a144-c98b53906814','茅','李嶠','唐','唐诗','tang','','[]','楚甸供王日，衡陽入貢年。',48,'全唐诗/poet.tang.3000.json','["楚甸供王日，衡陽入貢年。", "麏包青野外，鴟嘯綺楹前。", "堯帝成茨罷，殷湯祭雨旋。", "方期大君錫，不懼小巫捐。"]'),
('7ee8d5cc-bb25-499f-8d1c-4df1581916fa','荷','李嶠','唐','唐诗','tang','','[]','新溜滿澄陂，圓荷影若規。',48,'全唐诗/poet.tang.3000.json','["新溜滿澄陂，圓荷影若規。", "風來香氣遠，日落蓋陰移。", "魚戲排緗葉，龜浮見綠池。", "魏朝難接採，楚服但同披。"]'),
('ce521476-6455-4ee5-a06d-c270defa7eed','萍','李嶠','唐','唐诗','tang','','[]','二月虹初見，三春蟻正浮。',48,'全唐诗/poet.tang.3000.json','["二月虹初見，三春蟻正浮。", "青蘋含吹轉，紫蒂帶波流。", "屢逐明神薦，常隨旅客遊。", "既能甜似蜜，還遶楚王舟。"]'),
('6b20cce1-79a1-4e0a-97a9-ce6a59c2d484','菱','李嶠','唐','唐诗','tang','','[]','鉅野韶光暮，東平春溜通。',48,'全唐诗/poet.tang.3000.json','["鉅野韶光暮，東平春溜通。", "影搖江浦月，香引櫂歌風。", "日色翻池上，潭花發鏡中。", "五湖多賞樂，千里望難窮。"]'),
('441e1725-3470-45c5-a565-74249fade679','瓜','李嶠','唐','唐诗','tang','','[]','欲識東陵味，青門五色瓜。',48,'全唐诗/poet.tang.3000.json','["欲識東陵味，青門五色瓜。", "龍蹄遠珠履，女臂動金花。", "六子方呈瑞，三仙實可嘉。", "終朝奉絺綌，謁帝佇非賒。"]'),
('e6275cdf-0b32-4e37-9ff7-539ee40fac1d','松','李嶠','唐','唐诗','tang','','[]','鬱鬱高巖表，森森幽澗陲。',48,'全唐诗/poet.tang.3000.json','["鬱鬱高巖表，森森幽澗陲。", "鶴棲君子樹，風拂大夫枝。", "百尺條陰合，千年蓋影披。", "歲寒終不改，勁節幸君知。"]'),
('86f3f477-affc-41a9-923b-5d586bac2c21','桂','李嶠','唐','唐诗','tang','','[]','未[殖]銀宮裏，寧移玉殿幽。',50,'全唐诗/poet.tang.3000.json','["未[殖]銀宮裏，寧移玉殿幽。", "枝生無限月，花滿自然秋。", "俠客條爲馬，仙人葉作舟。", "願君期道術，攀折可淹留。"]'),
('4a59add5-9f03-4a78-9200-057b51d2aef9','槐','李嶠','唐','唐诗','tang','','[]','暮律移寒火，春宮長舊栽。',48,'全唐诗/poet.tang.3000.json','["暮律移寒火，春宮長舊栽。", "葉生馳道側，花落鳳庭隈。", "烈士懷忠觸，鴻儒訪業來。", "何當赤墀下，疎幹擬三台。"]'),
('02132c8c-6c18-4c19-902c-d5588136be76','柳','李嶠','唐','唐诗','tang','','[]','楊柳鬱氤氳，金堤總翠氛。',48,'全唐诗/poet.tang.3000.json','["楊柳鬱氤氳，金堤總翠氛。", "庭前花類雪，樓際葉如雲。", "列宿分龍影，芳池寫鳳文。", "短簫何以奏，攀折爲思君。"]'),
('da21af11-9ae8-488e-a5ab-f475f0ee7409','桐','李嶠','唐','唐诗','tang','','[]','孤秀嶧陽岑，亭亭出衆林。',48,'全唐诗/poet.tang.3000.json','["孤秀嶧陽岑，亭亭出衆林。", "春光雜鳳影，秋月弄圭陰。", "高映龍門迥，雙依玉井深。", "不因將入爨，誰謂作鳴琴。"]'),
('c5766e2a-5744-4365-ab71-bc646fd389ac','桃','李嶠','唐','唐诗','tang','','[]','獨有成蹊處，穠華發井傍。',48,'全唐诗/poet.tang.3000.json','["獨有成蹊處，穠華發井傍。", "山風凝笑臉，朝露泫啼妝。", "隱士顏應改，仙人路漸長。", "還欣上林苑，千歲奉君王。"]'),
('435848e9-8b7e-4e9c-8e6d-e3bedba8225e','李','李嶠','唐','唐诗','tang','','[]','潘岳閑居日，王戎戲陌辰。',48,'全唐诗/poet.tang.3000.json','["潘岳閑居日，王戎戲陌辰。", "蝶游芳徑馥，鸎囀弱枝新。", "葉暗青房晚，花明玉井春。", "方知有靈幹，特用表真人。"]'),
('d26fcebf-9555-46f1-be3f-d0a554a7f9e0','梨','李嶠','唐','唐诗','tang','','[]','擅美玄光側，傳芳瀚海中。',48,'全唐诗/poet.tang.3000.json','["擅美玄光側，傳芳瀚海中。", "鳳文疎象郡，花影麗新豐。", "色對瑤池紫，甘依大谷紅。", "若令逢漢主，還冀識張公。"]'),
('89cafa47-5cbd-4228-b465-7d54876c605a','梅','李嶠','唐','唐诗','tang','','[]','大庾歛寒光，南枝獨早芳。',48,'全唐诗/poet.tang.3000.json','["大庾歛寒光，南枝獨早芳。", "雪含朝暝色，風引去來香。", "妝面回青鏡，歌塵起畫梁。", "若能遙止渴，何暇泛瓊漿。"]'),
('5739588d-93b0-41f0-b389-e466fb63fed1','橘','李嶠','唐','唐诗','tang','','[]','萬里盤根植，千秋布葉繁。',48,'全唐诗/poet.tang.3000.json','["萬里盤根植，千秋布葉繁。", "既榮潘子賦，方重陸生言。", "玉蘤含霜動，金衣逐吹翻。", "願辭湘水曲，長茂上林園。"]'),
('dfd05dae-8933-46c8-82e0-b9bbc0ab47b8','鳳','李嶠','唐','唐诗','tang','','[]','有鳥居丹穴，其名曰鳳皇。',48,'全唐诗/poet.tang.3000.json','["有鳥居丹穴，其名曰鳳皇。", "九苞應靈瑞，五色成文章。", "屢向秦樓側，頻過洛水陽。", "鳴岐今日見，阿閣佇來翔。"]'),
('ab80b3b0-27ca-487d-9ef1-a18c9001d24e','鶴','李嶠','唐','唐诗','tang','','[]','黃鶴遠聯翩，從鸞下紫煙。',48,'全唐诗/poet.tang.3000.json','["黃鶴遠聯翩，從鸞下紫煙。", "翱翔一萬里，來去幾千年。", "已憩青田側，時遊丹禁前。", "莫言空警露，猶冀一聞天。"]'),
('52ae7d46-b657-463c-bd24-249e1b1458bd','烏','李嶠','唐','唐诗','tang','','[]','日路朝飛急，霜臺夕影寒。',48,'全唐诗/poet.tang.3000.json','["日路朝飛急，霜臺夕影寒。", "聯翩依月樹，迢遞繞風竿。", "白首何年改，青琴此夜彈。", "靈臺如可託，千里向長安。"]'),
('1668d938-139f-41f4-8b2b-1a5a6fe3150b','鵲','李嶠','唐','唐诗','tang','','[]','不分荆山抵，甘從石印飛。',48,'全唐诗/poet.tang.3000.json','["不分荆山抵，甘從石印飛。", "危巢畏風急，繞樹覺星稀。", "喜逐行人至，愁隨織女歸。", "倘遊明鏡裏，朝夕動光輝。"]'),
('9aa1d77e-5533-4fe3-8209-09d251564ac3','雁','李嶠','唐','唐诗','tang','','[]','春暉滿朔方，歸雁發衡陽。',48,'全唐诗/poet.tang.3000.json','["春暉滿朔方，歸雁發衡陽。", "望月驚弦影，排雲結陣行。", "往還倦南北，朝夕苦風霜。", "寄語能鳴侶，相隨入帝鄉。"]'),
('b141d9da-4b9d-4d1a-95a9-fe00ab6fe4ce','鳧','李嶠','唐','唐诗','tang','','[]','颯沓睢陽涘，浮游漢水隈。',48,'全唐诗/poet.tang.3000.json','["颯沓睢陽涘，浮游漢水隈。", "錢飛出井見，鶴引入琴哀。", "李陵賦詩罷，王喬曳舄來。", "何當歸太液，翱集動成雷。"]'),
('749d5af7-f822-4ebd-98c5-0f1282be7fa7','鸎','李嶠','唐','唐诗','tang','','[]','芳樹雜花紅，羣鸎亂曉空。',48,'全唐诗/poet.tang.3000.json','["芳樹雜花紅，羣鸎亂曉空。", "聲分折楊吹，嬌韻落梅風。", "寫囀清弦裏，遷喬暗木中。", "友生若可冀，幽谷響還通。"]'),
('b5ead39e-f60d-4477-9db1-3249b2608452','雉','李嶠','唐','唐诗','tang','','[]','白雉振朝聲，飛來表太平。',48,'全唐诗/poet.tang.3000.json','["白雉振朝聲，飛來表太平。", "楚郊疑鳳出，陳寶若雞鳴。", "童子懷仁至，中郎作賦成。", "冀君看飲啄，耿介獨含情。"]'),
('0a220382-a0cf-49c7-a7ff-7e95f0cf934d','燕','李嶠','唐','唐诗','tang','','[]','天女伺辰至，玄衣澹碧空。',48,'全唐诗/poet.tang.3000.json','["天女伺辰至，玄衣澹碧空。", "差池沐時雨，頡頏舞春風。", "相賀雕闌側，雙飛翠幕中。", "勿驚留爪去，猶冀識吳宮。"]'),
('3e5bad91-e3d8-430a-8513-a9904840a36f','雀','李嶠','唐','唐诗','tang','','[]','大廈初成日，嘉賓集杏梁。',48,'全唐诗/poet.tang.3000.json','["大廈初成日，嘉賓集杏梁。", "銜書表周瑞，入幕應王祥。", "暮宿江城裏，朝遊漣水傍。", "願齊鴻鵠至，希逐鳳皇翔。"]'),
('752e69e6-c395-4c7c-b1ea-2f0215b851a4','龍','李嶠','唐','唐诗','tang','','[]','銜燭耀幽都，含章擬鳳雛。',48,'全唐诗/poet.tang.3000.json','["銜燭耀幽都，含章擬鳳雛。", "西秦飲渭水，東洛薦河圖。", "帶火移星陸，升雲出鼎湖。", "希逢聖人步，庭闕正晨趨。"]'),
('23a7ec55-a6f5-4163-9e3b-2d6d7a26f39e','麟','李嶠','唐','唐诗','tang','','[]','漢祀應祥開，魯郊西狩回。',48,'全唐诗/poet.tang.3000.json','["漢祀應祥開，魯郊西狩回。", "奇音中鍾呂，成角喻英才。", "畫像臨仙閣，藏書入帝臺。", "若驚能吐哺，爲待鳳皇來。"]'),
('7267a417-b11d-403c-8434-aeb692fe02b7','象','李嶠','唐','唐诗','tang','','[]','鬱林開郡畢，維揚作貢初。',48,'全唐诗/poet.tang.3000.json','["鬱林開郡畢，維揚作貢初。", "萬推方演夢，惠子正焚書。", "執燧奔吳戰，量舟入魏墟。", "六牙行致遠，千葉奉高居。"]'),
('ab867042-2c37-42e8-9537-5e51d728a2c1','馬','李嶠','唐','唐诗','tang','','[]','天馬本來東，嘶驚御史驄。',48,'全唐诗/poet.tang.3000.json','["天馬本來東，嘶驚御史驄。", "蒼龍遙逐日，紫燕迥追風。", "明月來鞍上，浮雲落蓋中。", "得隨穆天子，何假唐成公。"]'),
('47e0b243-e233-461d-a7a4-dc00b0ed7bab','牛','李嶠','唐','唐诗','tang','','[]','齊歌初入相，燕陣早橫功。',48,'全唐诗/poet.tang.3000.json','["齊歌初入相，燕陣早橫功。", "欲向桃林下，先過梓樹中。", "在吳頻喘月，奔夢屢驚風。", "不用五丁士，如何九折通。"]'),
('3acda38d-1e14-4bbe-9604-1ea488d12630','豹','李嶠','唐','唐诗','tang','','[]','車法肇宗周，鼷文闡大猷。',48,'全唐诗/poet.tang.3000.json','["車法肇宗周，鼷文闡大猷。", "還將君子變，來蘊太公籌。", "委質超羊鞟，飛名列虎侯。", "若令逢雨露，長隱南山幽。"]'),
('08ee29a4-672f-42d9-84d2-0b65502752d0','熊','李嶠','唐','唐诗','tang','','[]','導洛宜陽右，乘春別館前。',48,'全唐诗/poet.tang.3000.json','["導洛宜陽右，乘春別館前。", "昭儀忠漢日，太傅翊周年。", "列射三侯滿，興師七步旋。", "莫言舒紫褥，猶異飲清泉。"]'),
('c4227428-5c74-4a04-8ad2-240bc6c47cf2','鹿','李嶠','唐','唐诗','tang','','[]','涿鹿聞中冀，秦原闢帝畿。',48,'全唐诗/poet.tang.3000.json','["涿鹿聞中冀，秦原闢帝畿。", "柰花開舊苑，萍葉藹前詩。", "道士乘仙日，先生折角時。", "方懷丈夫志，抗首別心期。"]'),
('287695d6-23fd-4432-b763-07a7c2ccb862','羊','李嶠','唐','唐诗','tang','','[]','絕飲懲澆俗，行驅夢逸材。',48,'全唐诗/poet.tang.3000.json','["絕飲懲澆俗，行驅夢逸材。", "仙人擁石去，童子馭車來。", "夜玉含星動，晨氈映雪開。", "莫言鴻漸力，長牧上林隈。"]'),
('462d29a1-3633-4959-a5e8-eb348c87c77c','兔','李嶠','唐','唐诗','tang','','[]','上蔡應初擊，平岡遠不稀。',48,'全唐诗/poet.tang.3000.json','["上蔡應初擊，平岡遠不稀。", "目隨槐葉長，形逐桂條飛。", "漢月澄秋色，梁園映雪輝。", "唯當感純孝，郛郭引兵威。"]'),
('88653ecc-c560-41e1-8d9e-15c871ce7e71','人日侍宴大明宮恩賜綵縷人勝應制','李嶠','唐','唐诗','tang','','[]','鳳城景色已含韶，人日風光倍覺饒。',64,'全唐诗/poet.tang.3000.json','["鳳城景色已含韶，人日風光倍覺饒。", "桂吐半輪迎此夜，蓂開七葉應今朝。", "魚猜水凍行猶澁，鸎喜春熙弄欲嬌。", "媿奉登高搖彩翰，欣逢御氣上丹霄。"]'),
('c0f7ae8c-a20b-4893-b2de-5ef8cdc13a7d','奉和初春幸太平公主南莊應制','李嶠','唐','唐诗','tang','','[]','主家山第接雲開，天子春遊動地來。',64,'全唐诗/poet.tang.3000.json','["主家山第接雲開，天子春遊動地來。", "羽騎參差花外轉，霓旌搖曳日邊回。", "還將石溜調琴曲，更取峰霞入酒杯。", "鸞輅已辭烏鵲渚，簫聲猶繞鳳皇臺。"]'),
('647a3e19-b506-4d7c-9c7b-43dd5397f0e4','太平公主山亭侍宴應制','李嶠','唐','唐诗','tang','','[]','黃金瑞牓絳河隈，白玉仙輿紫禁來。',64,'全唐诗/poet.tang.3000.json','["黃金瑞牓絳河隈，白玉仙輿紫禁來。", "碧樹青岑雲外聳，朱樓畫閣水中開。", "龍舟下瞰鮫人室，羽節高臨鳳女臺。", "遽惜歡娛歌吹晚，揮戈更却曜靈回。"]'),
('d1c62a56-548f-4786-b7ec-6c1933a93e68','奉和拜洛應制','李嶠','唐','唐诗','tang','','[]','七萃鑾輿動，千年瑞檢開。',60,'全唐诗/poet.tang.3000.json','["七萃鑾輿動，千年瑞檢開。", "文如龜負出，圖似鳳銜來。", "殷薦三神享，明禋萬國陪。", "周旗黃鳥集，漢幄紫雲回。", "日暮鈎陳轉，清歌上帝臺。"]'),
('bc12d353-11e2-4dbf-a2fb-c423a416d745','奉和幸大薦福寺應制','李嶠','唐','唐诗','tang','','[]','雁沼開香域，鸚林降綵旃。',72,'全唐诗/poet.tang.3000.json','["雁沼開香域，鸚林降綵旃。", "還窺圖鳳宇，更坐躍龍川。", "桂轝朝羣辟，蘭宮列四禪。", "半空銀閣斷，分砌寶繩連。", "甘雨蘇燋澤，慈雲動沛篇。", "獨慙賢作礪，空喜福成田。"]'),
('df35ee88-c1b9-43d8-8f99-6d3f0b681f38','奉和幸長安故城未央宮應制','李嶠','唐','唐诗','tang','','[]','舊宮賢相築，新苑聖君來。',72,'全唐诗/poet.tang.3000.json','["舊宮賢相築，新苑聖君來。", "運改城隍變，年深棟宇摧。", "後池無復水，前殿久成灰。", "莫辨祈風觀，空傳承露杯。", "宸心千載合，睿律九韶開。", "今日聯章處，猶疑上柏臺。"]'),
('91fc34f7-50dd-4e48-8b7e-67488164b451','奉和幸望春宮送朔方總管張仁亶','李嶠','唐','唐诗','tang','','[]','玉塞征驕子，金符命老臣。',72,'全唐诗/poet.tang.3000.json','["玉塞征驕子，金符命老臣。", "三軍張武斾，萬乘餞行輪。", "猛氣凌玄朔，崇恩降紫宸。", "投醪還結士，辭第本忘身。", "露下鷹初擊，風高雁欲賓。", "方銷塞北祲，還靖漠南塵。"]'),
('d2f519d1-9a44-476f-ac7d-9d750ce1e5fe','奉和幸三會寺應制','李嶠','唐','唐诗','tang','','[]','故臺蒼頡里，新邑紫泉居。',72,'全唐诗/poet.tang.3000.json','["故臺蒼頡里，新邑紫泉居。", "歲在開金寺，時來降玉輿。", "龍形雖近剎，鳥跡尚留書。", "竹是蒸青外，池仍點墨餘。", "天文光聖草，寶思合真如。", "謬奉千齡日，欣陪十地初。"]'),
('0a35abcc-b3e1-481d-b16c-df3b4e9e997d','奉和天樞成宴夷夏羣僚應制','李嶠','唐','唐诗','tang','','[]','轍迹光西崦，勳庸紀北燕。',96,'全唐诗/poet.tang.3000.json','["轍迹光西崦，勳庸紀北燕。", "何如萬方會，頌德九門前。", "灼灼臨黃道，迢迢入紫煙。", "仙盤正下露，高柱欲承天。", "山類叢雲起，珠疑大火懸。", "聲流塵作刼，業固海成田。", "帝澤傾堯酒，宸歌掩舜弦。", "欣逢下生日，還覩上皇年。"]'),
('81abb6ad-3788-4606-9b2f-32675e2e87b0','皇帝上禮撫事述懷','李嶠','唐','唐诗','tang','','[]','配極輝光遠，承天顧託隆。',120,'全唐诗/poet.tang.3000.json','["配極輝光遠，承天顧託隆。", "負圖濟多難，脫履歸成功。", "聖道昭永錫，邕言讓在躬。", "還推萬方重，咸仰四門聰。", "恭己忘自逸，因人體至公。", "垂旒滄海晏，解網法星空。", "雲散天五色，春還日再中。", "稱觴合纓弁，率舞應絲桐。", "凱樂深居鎬，傳歌盛飲豐。", "小臣濫簪筆，無以頌唐風。"]'),
('c1854cf4-5d46-4e9f-b6c2-5d29f71a57cd','奉和幸韋嗣立山莊侍宴應制','李嶠','唐','唐诗','tang','','[]','南洛師臣契，東巖王佐居。',120,'全唐诗/poet.tang.3000.json','["南洛師臣契，東巖王佐居。", "幽情遺紱冕，宸眷屬樵漁。", "制下峒山蹕，恩回灞水輿。", "松門駐旌蓋，薜幄引簪裾。", "石磴平黃陸，煙樓半紫虛。", "雲霞仙路近，琴酒俗塵疎。", "喬木千齡外，懸泉百丈餘。", "崖深經鍊藥，穴古舊藏書。", "樹宿摶風鳥，池潛縱壑魚。", "寧知天子貴，尚憶武侯廬。"]'),
('51aff429-eb12-4478-b4ae-c4b9849c94c3','倡婦行','李嶠','唐','唐诗','tang','','[]','十年倡家婦，三秋邊地人。',96,'全唐诗/poet.tang.3000.json','["十年倡家婦，三秋邊地人。", "紅妝樓上歇，白髮隴頭新。", "夜夜風霜苦，年年征戍頻。", "山西長落日，塞北久無春。", "團扇辭恩寵，回文贈苦辛。", "胡兵屢攻戰，漢使絕和親。", "消息如瓶井，沈浮似路塵。", "空餘千里月，照妾兩眉嚬。"]'),
('438ea8a5-c4c5-494b-9b20-39f7569e5414','餞薛大夫護邊','李嶠','唐','唐诗','tang','','[]','荒隅時未通，副相下臨戎。',72,'全唐诗/poet.tang.3000.json','["荒隅時未通，副相下臨戎。", "授律星芒動，分兵月暈空。", "犀皮擁青橐，象齒飾雕弓。", "決勝三河勇，長驅六郡雄。", "登山窺代北，屈指計遼東。", "佇見燕然上，抽毫頌武功。"]'),
('2957a2b4-7e13-42a2-b35b-7c8d27cc95f5','和杜學士旅次淮口阻風','李嶠','唐','唐诗','tang','','[]','夕吹生寒浦，清淮上暝潮。',72,'全唐诗/poet.tang.3000.json','["夕吹生寒浦，清淮上暝潮。", "迎風欲舉櫂，觸浪反停橈。", "淼漫煙波闊，參差林岸遙。", "日沈丹氣斂，天敞白雲銷。", "水雁銜蘆葉，沙鷗隱荻苗。", "客行殊未已，川路幾迢迢。"]'),
('1b110291-f82a-4875-a6b3-29251c151896','送光祿劉主簿之洛','李嶠','唐','唐诗','tang','','[]','函谷雙崤右，伊川二陝東。',72,'全唐诗/poet.tang.3000.json','["函谷雙崤右，伊川二陝東。", "仙舟窅將隔，芳斝暫云同。", "朋席餘歡盡，文房舊侶空。", "他鄉千里月，岐路九秋風。", "背櫪嘶班馬，分洲呌斷鴻。", "別後青山外，相望白雲中。"]'),
('3ab78b9a-4242-497c-9628-e75c14c2fd86','送駱奉禮從軍','李嶠','唐','唐诗','tang','','[]','玉塞邊烽舉，金壇廟略申。',72,'全唐诗/poet.tang.3000.json','["玉塞邊烽舉，金壇廟略申。", "羽書資銳筆，戎幕引英賓。", "劍動三軍氣，衣飄萬里塵。", "琴尊留別賞，風景惜離晨。", "笛梅含晚吹，營柳帶餘春。", "希君勒石返，歌舞入城闉。"]'),
('b928a862-6be7-4ded-b121-75ddad706b10','王屋山第之側雜構小亭暇日與羣公同遊','李嶠','唐','唐诗','tang','','[]','桂亭依絕巘，蘭榭俯回溪。',84,'全唐诗/poet.tang.3000.json','["桂亭依絕巘，蘭榭俯回溪。", "綺棟魚鱗出，雕甍鳳羽棲。", "引泉聊漲沼，鑿磴且通蹊。", "席上山花落，簾前野樹低。", "弋林開曙景，釣渚發晴霓。", "狎水驚梁雁，臨風聽楚雞。", "復看題柳葉，彌喜蔭桐圭。"]'),
('4f83c615-ac3c-49fd-b1d9-cf91451a8663','奉和杜員外扈從教閱','李嶠','唐','唐诗','tang','','[]','杪冬嚴殺氣，窮紀送頹光。',120,'全唐诗/poet.tang.3000.json','["杪冬嚴殺氣，窮紀送頹光。", "薄狩三農隙，大閱五戎塲。", "菜田初起燒，蘭野正開防。", "夾岸虹旗轉，分朋獸罟張。", "燕弧帶曉月，吳劒動秋霜。", "原啓前禽路，山縈後騎行。", "雲區墜日羽，星苑斃天狼。", "禮振軍容肅，威宣武節揚。", "神心體殷祝，靈兆叶姬祥。", "幸陪仙駕末，欣採翰林芳。"]'),
('76d2c1f7-62a7-4686-8023-a49bdbff5326','軍師凱旋自邕州順流舟中','李嶠','唐','唐诗','tang','','[]','鳴鞞入嶂口，汎舸歷川湄。',96,'全唐诗/poet.tang.3000.json','["鳴鞞入嶂口，汎舸歷川湄。", "尚想江陵陣，猶疑下瀨師。", "岸回帆影疾，風逆鼓聲遲。", "萍葉沾蘭槳，林花拂桂旗。", "弓鳴蒼隼落，劒動白猿悲。", "芳樹吟羗管，幽篁入楚詞。", "全軍多勝策，無戰在明時。", "寄謝山東妙，長纓徒自欺。"]'),
('8d0451d4-5a61-4cce-af90-5b8cff356cb1','夏晚九成宮呈同僚','李嶠','唐','唐诗','tang','','[]','碣館分襄野，平臺架射峰。',156,'全唐诗/poet.tang.3000.json','["碣館分襄野，平臺架射峰。", "英藩信煒燁，勝地本從容。", "林引梧庭鳳，泉歸竹沼龍。", "小軒恆共處，長坂屬相從。", "野席蘭琴奏，山臺桂酒醲。", "一枰移晝景，六著盡宵鐘。", "枚藻清詞律，鄒談耀辯鋒。", "結歡良有裕，聯寀愧無庸。", "暫悅丘中賞，還希物外蹤。", "風煙遠近至，魚鳥去來逢。", "月澗橫千丈，雲崖列萬重。", "樹紅山果熟，崖綠水苔濃。", "願以西園柳，長間北巖松。"]'),
('6144f01e-6bb9-4ed8-8b1e-7a1ca0dd4dfa','田假限疾不獲還莊載想田園兼思親友率成短韻用寫長懷贈杜幽素','李嶠','唐','唐诗','tang','','[]','游宦勞牽網，風塵久化衣。',180,'全唐诗/poet.tang.3000.json','["游宦勞牽網，風塵久化衣。", "迹馳東苑路，望阻北巖扉。", "及此承休告，聊將狎遯肥。", "十旬俄委疾，三徑且殊歸。", "茂陵窅難即，靈臺暫可依。", "疲痾旅城寺，延想屬郊畿。", "夕夢園林是，晨瞻邑里非。", "綠疇良已穢，清濠曠不追。", "野花何處落？山月幾秋輝。", "彼美符商政，優游絕漢機。", "高情物累遣，逸氣煙霞飛。", "樂道方無悶，懷賢獨有違。", "尊虛舊園酒，琴靜故人徽。", "夏沼蓮初發，秋田麥稍稀。", "何當攜手去，歲暮采芳菲。"]'),
('2aeab157-f981-4aba-81f2-d4c5ef7bf666','劉侍讀見和山邸十篇重申此贈','李嶠','唐','唐诗','tang','','[]','神嶽瑤池圃，仙宮玉樹林。',216,'全唐诗/poet.tang.3000.json','["神嶽瑤池圃，仙宮玉樹林。", "乘時警天御，清暑滌宸襟。", "梁駕陪玄賞，淄庭掩翠岑。", "對巖龍岫出，分壑雁池深。", "簷迥松蘿映，窗高石鏡臨。", "落泉奔澗響，驚吹助猿吟。", "野氣迷涼燠，山花雜古今。", "英藩盛賓侶，勝景想招尋。", "踐徑披蘭葉，攀崖引桂陰。", "穆生時泛醴，鄒子或調琴。", "雉翳分塲合，魚鉤向浦沈。", "朝遊極斜景，夕宴待橫參。", "顧己慙鉛鍔，叨名齒玳簪。", "暫依朱邸館，還暢白雲心。", "丘壑信多美，煙霞得所欽。", "寓言攄宿志，竊吹簡知音。", "獎價踰珍石，酬文重振金。", "方從仁智所，攜手濯清潯。"]'),
('6c45d0f8-9bf0-4aae-9c46-e6e3bc12012b','晚秋喜雨','李嶠','唐','唐诗','tang','','[]','積陽躔首夏，隆旱屆徂秋。',240,'全唐诗/poet.tang.3000.json','["積陽躔首夏，隆旱屆徂秋。", "炎威振皇服，歊景暴神州。", "氣滌朝川朗，光澄夕照浮。", "草木委林甸，禾黍悴原疇。", "國懼流金眚，人深懸磬憂。", "紫宸兢履薄，丹扆念推溝。", "望肅壇場祀，冤申囹圄囚。", "御車遷玉殿，薦菲撤瓊羞。", "濟窘邦儲發，蠲窮井賦優。", "服閑雲驥屏，冗術土龍修。", "睿感通三極，天誠貫六幽。", "夏祈良未擬，商禱詎爲儔。", "穴蟻禎符應，山蛇毒影收。", "騰雲八際滿，飛雨四溟周。", "聚靄籠仙闕，連霏繞畫樓。", "旱陂仍積水，涸沼更通流。", "晚穗萎還結，寒苗瘁復抽。", "九農歡歲阜，萬宇慶時休。", "野洽如坻詠，途喧擊壤謳。", "幸聞東李道，欣奉北場遊。"]'),
('a443d0c2-46b8-481f-a0f6-15aa3948abfe','中秋月二首 一','李嶠','唐','唐诗','tang','','[]','盈缺青冥外，東風萬古吹。',24,'全唐诗/poet.tang.3000.json','["盈缺青冥外，東風萬古吹。", "何人種丹桂，不長出輪枝。"]'),
('707c3c73-4e8b-426e-b8a5-97ed10d8ca15','中秋月二首 二','李嶠','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u54f2\u7406", "\u6708\u4eae"]','圓魄上寒空，皆言四海同。',24,'全唐诗/poet.tang.3000.json','["圓魄上寒空，皆言四海同。", "安知千里外，不有雨兼風。"]'),
('1cf8203f-4163-4ad6-b5e0-e6ff9bc9bbe7','侍宴桃花園詠花應制','李嶠','唐','唐诗','tang','','[]','歲去無言忽顦顇，時來含笑吐氛氳。',32,'全唐诗/poet.tang.3000.json','["歲去無言忽顦顇，時來含笑吐氛氳。", "不能擁路迷仙客，故欲開蹊待聖君。"]'),
('18703f50-4ab1-4cfc-9037-987402b42383','奉和聖製幸韋嗣立山莊應制','李嶠','唐','唐诗','tang','','[]','萬騎千官擁帝車，八龍三馬訪仙家。',32,'全唐诗/poet.tang.3000.json','["萬騎千官擁帝車，八龍三馬訪仙家。", "鳳皇原上開青壁，鸚鵡杯中弄紫霞。"]'),
('9c5db886-fc4e-4c78-9a85-e013c1609595','遊苑遇雪應制','李嶠','唐','唐诗','tang','','[]','散漫祥雲逐聖回，飄颻瑞雪繞天來。',32,'全唐诗/poet.tang.3000.json','["散漫祥雲逐聖回，飄颻瑞雪繞天來。", "不能落後爭飛絮，故欲迎前賽早梅。"]'),
('de0e2fd0-1828-40af-b495-60b4a7f97bce','送司馬先生','李嶠','唐','唐诗','tang','','[]','蓬閣桃源兩處分，人間海上不相聞。',32,'全唐诗/poet.tang.3000.json','["蓬閣桃源兩處分，人間海上不相聞。", "一朝琴裏悲黃鶴，何日山頭望白雲。"]'),
('8cac9d77-a4b7-47c2-8bbf-eac58805e5e4','風','李嶠','唐','唐诗','tang','','["\u98ce", "\u52b1\u5fd7", "\u5199\u98ce"]','解落三秋葉，能開二月花。',24,'全唐诗/poet.tang.3000.json','["解落三秋葉，能開二月花。", "過江千尺浪，入竹萬竿斜。"]'),
('24406ef9-6653-4c93-982a-1afa1bb83f9d','上清暉閤遇雪','李嶠','唐','唐诗','tang','','[]','千鍾聖酒御筵披，六出祥英亂繞枝。',32,'全唐诗/poet.tang.3000.json','["千鍾聖酒御筵披，六出祥英亂繞枝。", "即此神仙對瓊圃，何須轍跡向瑤池。"]'),
('a12454e0-add9-4d8e-b0e0-42b656640ef0','石淙','李嶠','唐','唐诗','tang','','[]','羽蓋龍旗下絕冥，蘭除薜幄坐雲扃。',64,'全唐诗/poet.tang.3000.json','["羽蓋龍旗下絕冥，蘭除薜幄坐雲扃。", "鳥和百籟疑調管，花發千巖似畫屏。", "金竈浮煙朝漠漠，石牀寒水夜泠泠。", "自然碧洞窺仙境，何必丹丘是福庭。"]'),
('c8c48f21-10ec-4d93-b5ac-0c27e1183c34','南海亂石山作','杜審言','唐','唐诗','tang','','[]','漲海積稽天，羣山高嶪地。',120,'全唐诗/poet.tang.3000.json','["漲海積稽天，羣山高嶪地。", "相傳稱亂石，圖典失其事。", "懸危悉可驚，大小都不類。", "乍將雲島極，還與星河次。", "上聳忽如飛，下臨仍欲墜。", "朝暾赩丹紫，夜魄炯青翠。", "穹崇霧雨蓄，幽隱靈仙閟。", "萬尋挂鶴巢，千丈垂猿臂。", "昔去景風涉，今來姑洗至。", "觀此得詠歌，長時想精異。"]'),
('4b89b383-f06e-41e2-8d9b-edc10c39b2b0','送和西蕃使','杜審言','唐','唐诗','tang','','[]','使出鳳皇池，京師陽春晚。',72,'全唐诗/poet.tang.3000.json','["使出鳳皇池，京師陽春晚。", "聖朝尚邊策，詔諭兵戈偃。", "拜手明光殿，搖心上林苑。", "種落踰青羌，關山度赤坂。", "疆場及無事，雅歌而餐飯。", "寧獨錫和戎，更當封定遠。"]'),
('dfa5b7e8-1eef-47be-aa88-898797cb41cd','蓬萊三殿侍宴奉敕詠終南山應制','杜審言','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','北斗挂城邊，南山倚殿前。',48,'全唐诗/poet.tang.3000.json','["北斗挂城邊，南山倚殿前。", "雲標金闕迥，樹杪玉堂懸。", "半嶺通佳氣，中峰繞瑞煙。", "小臣持獻壽，長此戴堯天。"]'),
('0dace816-ab80-4f3c-a87c-1ac6a49d7795','望春亭侍遊應詔','杜審言','唐','唐诗','tang','','[]','帝出明光殿，天臨太液池。',48,'全唐诗/poet.tang.3000.json','["帝出明光殿，天臨太液池。", "堯樽隨步輦，舜樂繞行麾。", "萬壽禎祥獻，三春景物滋。", "小臣同酌海，歌頌荅無爲。"]'),
('63ecd5ea-2e61-4060-a925-27c350750650','宿羽亭侍宴應制','杜審言','唐','唐诗','tang','','[]','步輦千門出，離宮二月開。',48,'全唐诗/poet.tang.3000.json','["步輦千門出，離宮二月開。", "風光新柳報，宴賞落花催。", "碧水搖空閣，青山繞吹臺。", "聖情留晚興，歌管送餘杯。"]'),
('d466ddc1-2819-4adf-8585-10f81915aff7','歲夜安樂公主滿月侍宴應制','杜審言','唐','唐诗','tang','','[]','戚里生昌胤，天杯宴重臣。',48,'全唐诗/poet.tang.3000.json','["戚里生昌胤，天杯宴重臣。", "畫樓初滿月，香殿早迎春。", "睿作堯君寶，孫謀梁國珍。", "明朝元會日，萬壽樂章陳。"]'),
('9b37eae8-ad47-4b31-9353-976ba804c48d','奉和七夕侍宴兩儀殿應制','杜審言','唐','唐诗','tang','','[]','一年銜別怨，七夕始言歸。',48,'全唐诗/poet.tang.3000.json','["一年銜別怨，七夕始言歸。", "斂淚開星靨，微步動雲衣。", "天迴兔欲落，河曠鵲停飛。", "那堪盡此夜，復往弄殘機。"]'),
('f6548b26-739c-42c1-b6af-47ebddf23625','大酺','杜審言','唐','唐诗','tang','','[]','聖后乘乾日，皇明御曆辰。',48,'全唐诗/poet.tang.3000.json','["聖后乘乾日，皇明御曆辰。", "紫宮初啓坐，蒼璧正臨春。", "雷雨垂膏澤，金錢贈下人。", "詔酺歡賞徧，交泰覩惟新。"]'),
('46364a14-cc64-4f3f-8601-b9035a1c9866','賦得妾薄命','杜審言','唐','唐诗','tang','','[]','草綠長門掩，苔青永巷幽。',48,'全唐诗/poet.tang.3000.json','["草綠長門掩，苔青永巷幽。", "寵移新愛奪，淚落故情留。", "啼鳥驚殘夢，飛花攪獨愁。", "自憐春色罷，團扇復迎秋。"]'),
('f1a3ce19-0b48-456c-b6ce-1657eb6de21c','和韋承慶過義陽公主山池五首 一','杜審言','唐','唐诗','tang','','[]','野興城中發，朝英物外求。',48,'全唐诗/poet.tang.3000.json','["野興城中發，朝英物外求。", "情懸朱紱望，契動赤泉遊。", "海燕巢書閣，山雞舞畫樓。", "雨餘清晚夏，共坐北巖幽。"]'),
('2eedc678-3efb-4b1c-bba0-8f096c3dcba8','和韋承慶過義陽公主山池五首 二','杜審言','唐','唐诗','tang','','[]','逕轉危峰逼，橋回缺岸妨。',48,'全唐诗/poet.tang.3000.json','["逕轉危峰逼，橋回缺岸妨。", "玉泉移酒味，石髓換粳香。", "綰霧青絲弱，牽風紫蔓長。", "猶言宴樂少，別向後池塘。"]'),
('52b04458-2e97-4c40-86fd-6f4a17219b54','和韋承慶過義陽公主山池五首 三','杜審言','唐','唐诗','tang','','[]','攜琴遶碧沙，搖筆弄青霞。',48,'全唐诗/poet.tang.3000.json','["攜琴遶碧沙，搖筆弄青霞。", "杜若幽庭草，芙蓉曲沼花。", "宴遊成野客，形勝得仙家。", "往往留仙步，登攀日易斜。"]'),
('bfb6764d-41ce-4929-946c-2bce0573be04','和韋承慶過義陽公主山池五首 四','杜審言','唐','唐诗','tang','','[]','攢石當軒倚，懸泉度牖飛。',48,'全唐诗/poet.tang.3000.json','["攢石當軒倚，懸泉度牖飛。", "鹿麛衝妓席，鶴子曳童衣。", "園果嘗難遍，池蓮摘未稀。", "卷簾唯待月，應在醉中歸。"]'),
('6c22e201-31c0-4927-9685-893955b78356','和韋承慶過義陽公主山池五首 五','杜審言','唐','唐诗','tang','','[]','賞翫期他日，高深愛此時。',48,'全唐诗/poet.tang.3000.json','["賞翫期他日，高深愛此時。", "池分八水背，峰作九山疑。", "地靜魚偏逸，人閑鳥欲欺。", "青溪留別興，更與白雲期。"]'),
('b881b056-6d92-45e8-9620-4710a375776f','和晉陵陸丞早春遊望','杜審言','唐','唐诗','tang','','["\u6625\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4f24\u6000", "\u548c\u8bd7", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','獨有宦遊人，偏驚物候新。',48,'全唐诗/poet.tang.3000.json','["獨有宦遊人，偏驚物候新。", "雲霞出海曙，梅柳渡江春。", "淑氣催黃鳥，晴光轉綠蘋。", "忽聞歌古調，歸思欲霑巾。"]'),
('c115189b-63c5-41cb-b9f9-5e716e1003c7','秋夜宴臨津鄭明府宅','杜審言','唐','唐诗','tang','','["\u5bb4\u4f1a", "\u79cb\u5929", "\u6292\u6000", "\u665a\u4e0a"]','行止皆無地，招尋獨有君。',48,'全唐诗/poet.tang.3000.json','["行止皆無地，招尋獨有君。", "酒中堪累月，身外即浮雲。", "露白宵鐘徹，風清曉漏聞。", "坐攜餘興往，還似未離羣。"]'),
('62e870d6-3a23-440d-a5f9-f7df841f7f4a','和康五庭芝望月有懷','杜審言','唐','唐诗','tang','','[]','明月高秋迥，愁人獨夜看。',48,'全唐诗/poet.tang.3000.json','["明月高秋迥，愁人獨夜看。", "暫將弓並曲，飜與扇俱團。", "霧濯清輝苦，風飄素影寒。", "羅衣一此鑒，頓使別離難。"]'),
('cb73222f-8a80-4905-8441-08ce08c91e0e','登襄陽城','杜審言','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u767b\u9ad8", "\u601d\u4e61", "\u5c71\u6c34", "\u548f\u53f2\u6000\u53e4"]','旅客三秋至，層城四望開。',48,'全唐诗/poet.tang.3000.json','["旅客三秋至，層城四望開。", "楚山橫地出，漢水接天回。", "冠蓋非新里，章華即舊臺。", "習池風景異，歸路滿塵埃。"]'),
('69e6a763-2664-4a5f-bad7-4cd097c51844','旅寓安南','杜審言','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u666f"]','交趾殊風候，寒遲暖復催。',48,'全唐诗/poet.tang.3000.json','["交趾殊風候，寒遲暖復催。", "仲冬山果熟，正月野花開。", "積雨生昏霧，輕霜下震雷。", "故鄉踰萬里，客思倍從來。"]'),
('189d4bfd-d1fa-401e-9c69-f2a5bf2839b9','春日懷歸','杜審言','唐','唐诗','tang','','[]','心是傷歸望，春歸異往年。',48,'全唐诗/poet.tang.3000.json','["心是傷歸望，春歸異往年。", "河山鑒魏闕，桑梓憶秦川。", "花雜芳園鳥，風和綠野煙。", "更懷歡賞地，車馬洛橋邊。"]'),
('796333f6-7fe6-47f0-aa58-9d6b89a14718','代張侍御傷美人','杜審言','唐','唐诗','tang','','[]','二八泉扉掩，帷屏寵愛空。',48,'全唐诗/poet.tang.3000.json','["二八泉扉掩，帷屏寵愛空。", "淚痕消夜燭，愁緒亂春風。", "巧笑人疑在，新妝曲未終。", "應憐脂粉氣，留著舞衣中。"]'),
('9e63a20b-7a26-41b9-9e72-4c5bcf0f0efa','送高郎中北使','杜審言','唐','唐诗','tang','','[]','北狄願和親，東京發使臣。',48,'全唐诗/poet.tang.3000.json','["北狄願和親，東京發使臣。", "馬銜邊地雪，衣染異方塵。", "歲月催行旅，恩榮變苦辛。", "歌鐘期重錫，拜手落花春。"]'),
('e398bdb7-e2fa-4bba-b19f-45bdc9074fc1','都尉山亭','杜審言','唐','唐诗','tang','','[]','紫藤縈葛藟，綠刺罥薔薇。',48,'全唐诗/poet.tang.3000.json','["紫藤縈葛藟，綠刺罥薔薇。", "下釣看魚躍，探巢畏鳥飛。", "葉疎荷已晚，枝亞果新肥。", "勝迹都無限，只應伴月歸。"]'),
('1658fad0-6e6c-4d3f-aa5a-7b21450ff96a','夏日過鄭七山齋','杜審言','唐','唐诗','tang','','[]','共有樽中好，言尋谷口來。',48,'全唐诗/poet.tang.3000.json','["共有樽中好，言尋谷口來。", "薜蘿山逕入，荷芰水亭開。", "日氣含殘雨，雲陰送晚雷。", "洛陽鐘鼓至，車馬繫遲回。"]'),
('25e70bc0-e40f-499e-92ff-d2c546f529a7','送崔融','杜審言','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u795d\u613f"]','君王行出將，書記遠從征。',48,'全唐诗/poet.tang.3000.json','["君王行出將，書記遠從征。", "祖帳連河闕，軍麾動洛城。", "旌旃朝朔氣，笳吹夜邊聲。", "坐覺煙塵掃，秋風古北平。"]'),
('926afdf1-dd5b-44a9-be3a-62dda48c07e8','經行嵐州','杜審言','唐','唐诗','tang','','[]','北地春光晚，邊城氣候寒。',48,'全唐诗/poet.tang.3000.json','["北地春光晚，邊城氣候寒。", "往來花不發，新舊雪仍殘。", "水作琴中聽，山疑畫裏看。", "自驚牽遠役，艱險促征鞍。"]'),
('7efe3c86-7478-46c1-9fef-aa02594af9fb','重九日宴江陰','杜審言','唐','唐诗','tang','','[]','蟋蟀期歸晚，茱萸節候新。',48,'全唐诗/poet.tang.3000.json','["蟋蟀期歸晚，茱萸節候新。", "降霜青女月，送酒白衣人。", "高興要長壽，卑棲隔近臣。", "龍沙即此地，舊俗坐爲鄰。"]'),
('ea021f19-e544-4b26-abaa-211a23a2e499','除夜有懷','杜審言','唐','唐诗','tang','','[]','故節當歌守，新年把燭迎。',48,'全唐诗/poet.tang.3000.json','["故節當歌守，新年把燭迎。", "冬氛戀虬箭，春色候雞鳴。", "興盡聞壺覆，宵闌見斗橫。", "還將萬億壽，更謁九重城。"]'),
('5d4d8531-ec39-4bde-8f77-718cafe5432a','晦日宴遊','杜審言','唐','唐诗','tang','','[]','日晦隨蓂莢，春情著杏花。',48,'全唐诗/poet.tang.3000.json','["日晦隨蓂莢，春情著杏花。", "解紳宜就水，張幕會連沙。", "歌管風輕度，池臺日半斜。", "更看金谷騎，爭向石崇家。"]'),
('4378da93-d144-4fbf-beba-45173f7d1f86','七夕','杜審言','唐','唐诗','tang','','[]','白露含明月，青霞斷絳河。',48,'全唐诗/poet.tang.3000.json','["白露含明月，青霞斷絳河。", "天街七襄轉，閣道二神過。", "袨服鏘環珮，香筵拂綺羅。", "年年今夜盡，機杼別情多。"]'),
('9bfce051-60ed-46bf-9bc3-aa8b7b4f4aac','守歲侍宴應制','杜審言','唐','唐诗','tang','','[]','季冬除夜接新年，帝子王孫捧御筵。',64,'全唐诗/poet.tang.3000.json','["季冬除夜接新年，帝子王孫捧御筵。", "宮闕星河低拂樹，殿廷燈燭上薰天。", "彈弦奏節梅風入，對局探鉤柏酒傳。", "欲向正元歌萬壽，暫留歡賞寄春前。"]'),
('e3b5b535-b51f-4c68-8bf5-070617049ca4','大酺','杜審言','唐','唐诗','tang','','[]','毘陵震澤九州通，士女歡娛萬國同。',64,'全唐诗/poet.tang.3000.json','["毘陵震澤九州通，士女歡娛萬國同。", "伐鼓撞鐘驚海上，新妝袨服照江東。", "梅花落處疑殘雪，柳葉開時任好風。", "火德雲官逢道泰，天長地久屬年豐。"]'),
('9be6ee69-ac5d-4f11-ba9f-b11b277d93b1','春日京中有懷','杜審言','唐','唐诗','tang','','["\u601d\u5ff5", "\u5b64\u72ec", "\u6625\u5929"]','今年遊寓獨遊秦，愁思看春不當春。',64,'全唐诗/poet.tang.3000.json','["今年遊寓獨遊秦，愁思看春不當春。", "上林苑裏花徒發，細柳營前葉漫新。", "公子南橋應盡興，將軍西第幾留賓。", "寄語洛城風日道，明年春色倍還人。"]'),
('f79247a6-7cf2-4d27-a6d9-bc2b6727eda9','扈從出長安應制','杜審言','唐','唐诗','tang','','[]','分野都畿列，時乘六御均。',120,'全唐诗/poet.tang.3000.json','["分野都畿列，時乘六御均。", "京師舊西幸，洛道此東巡。", "文物驅三統，聲名走百神。", "龍旗縈漏夕，鳳輦拂鈎陳。", "撫迹地靈古，游情皇鑒新。", "山追散馬日，水憶釣魚人。", "禹食傳中使，堯樽遍下臣。", "省方稱國阜，問道識風淳。", "歲晚天行吉，年豐景從親。", "歡娛包歷代，宇宙忽疑春。"]'),
('ed0ebb3a-b2b4-4529-8070-caf23fb9633c','春日江津遊望','杜審言','唐','唐诗','tang','','[]','旅客搖邊思，春江弄晚晴。',72,'全唐诗/poet.tang.3000.json','["旅客搖邊思，春江弄晚晴。", "煙銷垂柳弱，霧捲落花輕。", "飛棹乘空下，回流向日平。", "鳥啼移幾處，蝶舞亂相迎。", "忽歎人皆濁，堤防水至清。", "谷王常不讓，深可戒中盈。"]'),
('19ebf97a-e873-429e-b074-750258f377fa','泛舟送鄭卿入京','杜審言','唐','唐诗','tang','','[]','帝坐蓬萊殿，恩追社稷臣。',72,'全唐诗/poet.tang.3000.json','["帝坐蓬萊殿，恩追社稷臣。", "長安遙向日，宗伯正乘春。", "相宅開基地，傾都送別人。", "行舟縈淥水，列戟滿紅塵。", "酒助歡娛洽，風催景氣新。", "此時光乃命，誰爲惜無津。"]'),
('75a1bf2b-7eb6-44fe-af37-f7220ae97faa','度石門山','杜審言','唐','唐诗','tang','','[]','石門千仞斷，迸水落遙空。',120,'全唐诗/poet.tang.3000.json','["石門千仞斷，迸水落遙空。", "道束懸崖半，橋欹絕澗中。", "仰攀人屢息，直下騎纔通。", "泥擁奔虵徑，雲埋伏獸叢。", "星躔牛斗北，地脈象牙東。", "開塞隨行變，高深觸望同。", "江聲連驟雨，日氣抱殘虹。", "未改朱明律，先含白露風。", "堅貞深不憚，險澁諒難窮。", "有異登臨賞，徒爲造化功。"]'),
('14d0288b-6a5a-454d-b12e-e802574f9d1a','贈崔融二十韻','杜審言','唐','唐诗','tang','','[]','十年俱薄宦，萬里各他方。',240,'全唐诗/poet.tang.3000.json','["十年俱薄宦，萬里各他方。", "雲天斷書札，風土異炎涼。", "太息幽蘭紫，勞歌奇樹黃。", "日疑懷叔度，夜似憶真長。", "北使從江表，東歸在洛陽。", "相逢慰疇昔，相對敘存亡。", "草深窮巷毀，竹盡故園荒。", "雅節君彌固，衰顏余自傷。", "人事盈虛改，交遊寵辱妨。", "雀羅爭去翟，鶴氅競尋王。", "思極歡娛至，朋情詎可忘。", "琴樽橫宴席，巖谷臥詞場。", "連騎追佳賞，城中及路傍。", "三川宿雨霽，四月晚花芳。", "復此開懸榻，寧唯入後堂。", "興酣鴝鵒舞，言洽鳳皇翔。", "高選俄遷職，嚴程已飭裝。", "撫躬銜道義，攜手戀輝光。", "玉振先推美，金銘舊所防。", "勿嗟離別易，行役共時康。"]'),
('2aea77b5-e023-4478-bcf9-ee6ddf01a434','贈蘇味道','杜審言','唐','唐诗','tang','','[]','北地寒應苦，南庭戍未歸。',96,'全唐诗/poet.tang.3000.json','["北地寒應苦，南庭戍未歸。", "邊聲亂羗笛，朔氣卷戎衣。", "雨雪關山暗，風霜草木稀。", "胡兵戰欲盡，虜騎獵猶肥。", "雁塞何時入，龍城幾度圍。", "據鞍雄劒動，插筆羽書飛。", "輿駕還京邑，朋遊滿帝畿。", "方期來獻凱，歌舞共春輝。"]'),
('58447b81-6032-4ef6-ade1-2fd3fefe0a89','和李大夫嗣真奉使存撫河東','杜審言','唐','唐诗','tang','','[]','六位乾坤動，三微曆數遷。',288,'全唐诗/poet.tang.3000.json','["六位乾坤動，三微曆數遷。", "謳歌移火德，圖讖在金天。", "子月開階統，房星受命年。", "禎符龍馬出，寶籙鳳凰傳。", "地即交風雨，都仍卜澗瀍。", "明堂唯御極，清廟乃尊先。", "不宰神功運，無爲大象懸。", "八荒平物土，四海接人煙。", "已屬羣生泰，猶言至道偏。", "璽書傍問俗，旌節近推賢。", "秩比司空位，官臨御史員。", "雄詞執刀筆，直諫罷樓船。", "國有大臣器，朝加小會筵。", "將行備禮樂，送別仰神仙。", "城闕周京轉，關河陝服連。", "稍觀汾水曲，俄指絳臺前。", "姑射聊長望，平陽遂宛然。", "舜耕餘草木，禹鑿舊山川。", "昔出諸侯上，無何霸業全。", "中軍歸戰敵，外府絕兵權。", "隱隱帝鄉遠，瞻瞻肅命虔。", "西河偃風俗，東壁挂星躔。", "井邑枌榆社，陵園松柏田。", "榮光晴掩代，佳氣曉侵燕。"]'),
('fcda09e6-2d91-449a-8ef2-2a996746a9ce','贈蘇綰書記','杜審言','唐','唐诗','tang','','[]','知君書記本翩翩，爲許從戎赴朔邊。',32,'全唐诗/poet.tang.3000.json','["知君書記本翩翩，爲許從戎赴朔邊。", "紅粉樓中應計日，燕支山下莫經年。"]'),
('2adf2ec4-c087-4b64-8eb0-ce60b10ce54c','渡湘江','杜審言','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u60c5", "\u5373\u666f\u6292\u60c5", "\u6005\u60d8"]','遲日園林悲昔遊，今春花鳥作邊愁。',32,'全唐诗/poet.tang.3000.json','["遲日園林悲昔遊，今春花鳥作邊愁。", "獨憐京國人南竄，不似湘江水北流。"]'),
('6ba1c9a5-409c-461e-b8a2-1408a4590e4c','戲贈趙使君美人','杜審言','唐','唐诗','tang','','[]','紅粉青娥暎楚雲，桃花馬上石榴帬。',32,'全唐诗/poet.tang.3000.json','["紅粉青娥暎楚雲，桃花馬上石榴帬。", "羅敷獨向東方去，謾學他家作使君。"]'),
('772fe6c9-b1e8-4b96-952b-abe4b4f9b4a7','三婦豔','董思恭','唐','唐诗','tang','','[]','大婦裁紈素，中婦弄明璫。',36,'全唐诗/poet.tang.3000.json','["大婦裁紈素，中婦弄明璫。", "小婦多姿態，登樓紅粉妝。", "丈人且安坐，初日漸流光。"]'),
('4304996f-9598-4419-9fb5-4eeeaf762d64','感懷','董思恭','唐','唐诗','tang','','[]','野郊愴新別，河橋非舊餞。',60,'全唐诗/poet.tang.3000.json','["野郊愴新別，河橋非舊餞。", "慘日映峰沈，愁雲隨蓋轉。", "哀笳時斷續，悲旌乍舒卷。", "望望情何極，浪浪淚空泫。", "無復昔時人，芳春共誰遣。"]'),
('c19cf735-ff9e-4a31-a731-bf2db25bf91c','守歲二首 一','董思恭','唐','唐诗','tang','','["\u95f2\u9002", "\u6625\u8282"]','暮景斜芳殿，年華麗綺宮。',48,'全唐诗/poet.tang.3000.json','["暮景斜芳殿，年華麗綺宮。", "寒辭去冬雪，暖帶入春風。", "階馥舒梅素，盤花卷燭紅。", "共歡新故歲，迎送一宵中。"]'),
('1b37135d-0c99-4f1e-872b-5a88d9c74b5a','守歲二首 二','董思恭','唐','唐诗','tang','','[]','歲陰窮暮紀，獻節啓新芳。',48,'全唐诗/poet.tang.3000.json','["歲陰窮暮紀，獻節啓新芳。", "冬盡今宵促，年開明日長。", "冰銷出鏡水，梅散入風香。", "對此歡終宴，傾壺待曙光。"]'),
('da230f09-1dbc-4999-b819-26c94ca9daa5','昭君怨二首 一','董思恭','唐','唐诗','tang','','[]','新年猶尚小，那堪遠聘秦。',48,'全唐诗/poet.tang.3000.json','["新年猶尚小，那堪遠聘秦。", "裾衫霑馬汗，眉黛染胡塵。", "舉眼無相識，路逢皆異人。", "唯有梅將李，猶帶故鄉春。"]'),
('5d982b4a-8584-4c3a-8e4d-b860d5c37949','昭君怨二首 二','董思恭','唐','唐诗','tang','','[]','琵琶馬上彈，行路曲中難。',48,'全唐诗/poet.tang.3000.json','["琵琶馬上彈，行路曲中難。", "漢月正南遠，燕山直北寒。", "髻鬟風拂亂，眉黛雪霑殘。", "斟酌紅顏改，徒勞握鏡看。"]'),
('1813c627-8c26-4f33-ae10-05c1e1f2d7fe','詠日','董思恭','唐','唐诗','tang','','[]','滄海十枝暉，懸圃重輪慶。',48,'全唐诗/poet.tang.3000.json','["滄海十枝暉，懸圃重輪慶。", "蕣華發晨楹，菱彩飜朝鏡。", "忽遇驚風飄，自有浮雲映。", "更也人皆仰，無待揮戈正。"]'),
('de56b03d-02f9-4d82-b2da-166771890344','詠月','董思恭','唐','唐诗','tang','','[]','北堂未安寢，西園聊騁望。',48,'全唐诗/poet.tang.3000.json','["北堂未安寢，西園聊騁望。", "玉戶照羅幃，珠軒明綺障。", "別客長安道，思婦高樓上。", "所願君莫違，清風時可訪。"]'),
('4a914fb3-5571-4822-b95a-e64a0d2853e9','詠星','董思恭','唐','唐诗','tang','','[]','歷歷東井舍，昭昭右掖垣。',48,'全唐诗/poet.tang.3000.json','["歷歷東井舍，昭昭右掖垣。", "雲際龍文出，池中鳥色飜。", "流輝下月路，墜影入河源。", "方知潁川集，別有太丘門。"]'),
('f433cb66-864d-48c9-b8f9-55ebc3525f29','詠風','董思恭','唐','唐诗','tang','','[]','蕭蕭度閶闔，習習下庭闈。',48,'全唐诗/poet.tang.3000.json','["蕭蕭度閶闔，習習下庭闈。", "花蝶自飄舞，蘭蕙生光輝。", "相烏正舉翼，退鷁已驚飛。", "方從列子御，更逐浮雲歸。"]'),
('c0376bb0-4c4c-44c1-8519-2cae57fce8ae','詠雲','董思恭','唐','唐诗','tang','','[]','帝鄉白雲起，飛蓋上天衢。',48,'全唐诗/poet.tang.3000.json','["帝鄉白雲起，飛蓋上天衢。", "帶月綺羅映，從風枝葉敷。", "參差過層閣，倏忽下蒼梧。", "因風望既遠，安得久踟躕。"]'),
('0143fea2-a4f4-4d32-a476-dec38620e82b','詠雪','董思恭','唐','唐诗','tang','','[]','天山飛雪度，言是落花朝。',48,'全唐诗/poet.tang.3000.json','["天山飛雪度，言是落花朝。", "惜哉不我與，蕭索從風飄。", "鮮潔凌紈素，紛糅下枝條。", "良時竟何在，坐見容華銷。"]'),
('ec12a9f1-97aa-4a5f-83dc-f19622ec37a4','詠露','董思恭','唐','唐诗','tang','','[]','夜色凝仙掌，晨甘下帝庭。',48,'全唐诗/poet.tang.3000.json','["夜色凝仙掌，晨甘下帝庭。", "不覺九秋至，遠向三危零。", "蘆渚花初白，葵園葉尚青。", "晞陽一灑惠，方願益滄溟。"]'),
('a171b0d9-ffc7-4bdc-89ce-e6075754394b','詠霧','董思恭','唐','唐诗','tang','','[]','蒼山寂已暮，翠觀黯將沈。',48,'全唐诗/poet.tang.3000.json','["蒼山寂已暮，翠觀黯將沈。", "終南晨豹隱，巫峽夜猿吟。", "天寒氣不歇，景晦色方深。", "待訪公超市，將予赴華陰。"]'),
('77ae50af-e0a1-44f5-9d40-b319a0549ea5','詠虹','董思恭','唐','唐诗','tang','','[]','春暮萍生早，日落雨飛餘。',48,'全唐诗/poet.tang.3000.json','["春暮萍生早，日落雨飛餘。", "橫彩分長漢，倒色媚清渠。", "梁前朝影出，橋上晚光舒。", "願逐旌旗轉，飄飄侍直廬。"]'),
('03d41a55-1682-4cb4-8635-dba61d512367','詠桃','董思恭','唐','唐诗','tang','','[]','禁苑春光麗，花蹊幾樹裝。',48,'全唐诗/poet.tang.3000.json','["禁苑春光麗，花蹊幾樹裝。", "綴條深淺色，點露參差光。", "向日分千笑，迎風共一香。", "如何仙嶺側，獨秀隱遙芳。"]'),
('b77f6dda-ffc5-496a-b66c-ed7bff6ae4a6','詠李','董思恭','唐','唐诗','tang','','[]','盤根植瀛渚，交幹橫倚天。',24,'全唐诗/poet.tang.3000.json','["盤根植瀛渚，交幹橫倚天。", "舒華光四海，卷葉蔭山川。"]'),
('90b3dcc4-2242-40a0-95d9-a426f7892037','詠弓','董思恭','唐','唐诗','tang','','[]','上弦明月半，激箭流星遠。',24,'全唐诗/poet.tang.3000.json','["上弦明月半，激箭流星遠。", "落雁帶書驚，啼猿映枝轉。"]'),
('3b2d68dd-6800-4f46-8ab5-50c1e380082d','詠琵琶','董思恭','唐','唐诗','tang','','[]','半月無雙影，金花有四時。',60,'全唐诗/poet.tang.3000.json','["半月無雙影，金花有四時。", "摧藏千里態，掩抑幾重悲。", "促節縈紅袖，清音滿翠帷。", "駛彈風響急，緩曲釧聲遲。", "空餘關隴恨，因此代相思。"]'),
('80a62573-63b4-45f1-a215-83d09ba61a3b','經廬岳回望江州想洛川有作','劉允濟','唐','唐诗','tang','','[]','龜山帝始營，龍門禹初鑿。',288,'全唐诗/poet.tang.3000.json','["龜山帝始營，龍門禹初鑿。", "出入經變化，俯仰憑寥廓。", "未若茲山功，連延竝巫霍。", "東北疏艮象，西南距坤絡。", "宏阜自鬱盤，高標復迴薄。", "勢入柴桑渚，陰開彭蠡壑。", "九江杳無際，七澤紛相錯。", "雲雨散吳會，風波騰鄬鄀。", "跡隨造化久，利與乾坤博。", "肸蠁精氣通，紛綸潛怪作。", "石渠忽見踐，金房安可託。", "地入天子都，巖有仙人藥。", "二門幾迢遰，三宮何儵爚。", "咫尺窮杳冥，跬步皆恬漠。", "仙才驚羽翰，幽居靜龍蠖。", "明牧振雄詞，棣華殊灼灼。", "盛業匡西夏，深謀贊禹亳。", "黃雲覆鼎飛，絳氣橫川躍。", "佐曆符賢運，人期茂天爵。", "禮樂富垂髫，詩書成舞勺。", "清輝靖嵒電，利器騰霜鍔。", "遊聖挹衢尊，鄰畿恭木鐸。", "巖仞包武侯，波瀾控文若。", "旋聞刈薪楚，遽覩升葵藿。"]'),
('d1e47e2b-1e63-44fe-a5e3-6ca0e1f4aa27','詠琴','劉允濟','唐','唐诗','tang','','[]','昔在龍門側，誰想鳳鳴時。',48,'全唐诗/poet.tang.3000.json','["昔在龍門側，誰想鳳鳴時。", "雕琢今爲器，宮商不自持。", "巴人緩疎節，楚客弄繁絲。", "欲作高張引，飜成下調悲。"]'),
('5d76fc64-ca0d-4a79-b14e-005502fcd939','怨情','劉允濟','唐','唐诗','tang','','[]','玉關芳信斷，蘭閨錦字新。',48,'全唐诗/poet.tang.3000.json','["玉關芳信斷，蘭閨錦字新。", "愁來好自抑，念切已含嚬。", "虛牖風驚夢，空牀月厭人。", "歸期倘可促，勿度柳園春。"]'),
('966b0c06-1f75-4417-8f02-ae68a6f1d618','見道邊死人','劉允濟','唐','唐诗','tang','','[]','淒涼徒見日，冥寞詎知年。',24,'全唐诗/poet.tang.3000.json','["淒涼徒見日，冥寞詎知年。", "魂兮不可問，應爲直如弦。"]'),
('83397093-44b2-41c1-a254-9a3490f47b6e','九日登玄武山旅眺','邵大震','唐','唐诗','tang','','["\u6052\u5c71"]','九月九日望遙空，秋水秋天生夕風。',32,'全唐诗/poet.tang.3000.json','["九月九日望遙空，秋水秋天生夕風。", "寒雁一向南去遠，遊人幾度菊花叢。"]'),
('455875de-13ca-4546-bc21-f048af541d2d','軍中行路難','辛常伯','唐','唐诗','tang','','[]','君不見封狐雄虺自成羣，憑深負固結妖氛。',343,'全唐诗/poet.tang.3000.json','["君不見封狐雄虺自成羣，憑深負固結妖氛。", "玉璽分兵徵惡少，金壇授律動將軍。", "將軍擁麾宣廟略，戰士橫戈靜夷落。", "長驅一息背銅梁，直指三危登劒閣。", "閣道岧嶢起戍樓，劒門遙裔俯靈丘。", "邛關九折無平路，江水雙源有急流。", "征役無期返，他鄉歲華晚。", "杳杳丘陵出，蒼蒼林薄遠。", "途危紫蓋峰，路澀青泥坂。", "去去指哀牢，行行入不毛。", "絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。", "交阯枕南荒，昆彌臨北戶。", "川原饒毒霧，谿谷多霪雨。", "行潦四時流，崩查千歲古。", "漂梗飛蓬不暫安，捫蘿引葛陟危巒。", "昔時聞道從軍樂，今日方知行路難。", "滄江綠水東流駛，炎州丹徼南中地。", "南中南斗映星河，秦關秦塞阻煙波。", "三春邊地風光少，五月瀘川瘴癘多。", "朝驅疲斥候，夕息倦樵歌。", "向月彎繁弱，連星轉太阿。", "重義輕生懷一顧，東伐西征凡幾度。", "夜夜朝朝斑鬢新，年年歲歲戎衣故。"]'),
('457c68c1-8ab5-436e-a7fd-901e044ff05c','奉和聖製夏日遊石淙山','姚崇','唐','唐诗','tang','','[]','二室三塗光地險，均霜揆日處天中。',64,'全唐诗/poet.tang.3000.json','["二室三塗光地險，均霜揆日處天中。", "石泉石鏡恆留月，山鳥山花競逐風。", "周王久謝瑤池賞，漢主懸慙玉樹宮。", "別有祥煙伴佳氣，能隨輕輦共蔥蔥。"]'),
('68c6f2e7-abc0-471c-9351-6d711e64f3c3','故洛陽城侍宴應制','姚崇','唐','唐诗','tang','','[]','遊豫停仙蹕，登臨對晚晴。',48,'全唐诗/poet.tang.3000.json','["遊豫停仙蹕，登臨對晚晴。", "川鳧連倒影，巖鳥應虛聲。", "野奏風成曲，山居雲作纓。", "今朝丘壑上，高興小蓬瀛。"]'),
('878d2299-db2f-4e38-bcab-f370f637bd6e','春日洛陽城侍宴','姚崇','唐','唐诗','tang','','[]','南山開寶曆，北渚對芳蹊。',48,'全唐诗/poet.tang.3000.json','["南山開寶曆，北渚對芳蹊。", "的歷風梅度，參差露草低。", "堯樽臨上席，舜樂下前溪。", "任重由來醉，乘酣志轉迷。"]'),
('713514a9-9744-4c9d-be03-8197ce2e2c6c','秋夜望月','姚崇','唐','唐诗','tang','','[]','明月有餘鑒，羈人殊未安。',48,'全唐诗/poet.tang.3000.json','["明月有餘鑒，羈人殊未安。", "桂含秋樹晚，波入夜池寒。", "灼灼雲枝淨，光光草露團。", "所思迷所在，長望獨長歎。"]'),
('7973312c-4db5-481e-9b03-41457658f413','夜渡江','姚崇','唐','唐诗','tang','','[]','夜渚帶浮煙，蒼茫晦遠天。',48,'全唐诗/poet.tang.3000.json','["夜渚帶浮煙，蒼茫晦遠天。", "舟輕不覺動，纜急始知牽。", "聽草遙尋岸，聞香暗識蓮。", "唯看孤帆影，常似客心懸。"]'),
('19697728-2d26-4021-bd5d-9a509addd964','奉和聖製龍池篇','姚崇','唐','唐诗','tang','','[]','恭聞帝里生靈沼，應報明君鼎業新。',64,'全唐诗/poet.tang.3000.json','["恭聞帝里生靈沼，應報明君鼎業新。", "既協翠泉光寶命，還符白水出真人。", "此時舜海潛龍躍，此地堯河帶馬巡。", "獨有前池一小雁，叨承舊惠入天津。"]'),
('0beb441d-401f-41db-a962-37d96107e401','句','姚崇','唐','唐诗','tang','','[]','扇掩將雛曲，釵承墮馬鬟。',12,'全唐诗/poet.tang.3000.json','["扇掩將雛曲，釵承墮馬鬟。"]'),
('dd5e3176-7951-4a02-8f9b-67a32b879f47','奉和御製璟與張說源乾曜同日上官命宴都堂賜詩應制','宋璟','唐','唐诗','tang','','[]','丞相邦之重，非賢諒不居。',96,'全唐诗/poet.tang.3000.json','["丞相邦之重，非賢諒不居。", "老臣慵且憊，何德以當諸。", "厚秩先爲忝，崇班復此除。", "太常陳禮樂，中掖降簪裾。", "聖酒山河潤，仙文象緯舒。", "冒恩懷寵錫，陳力省空虛。", "郭隗慙無駿，馮諼媿有魚。", "不知周勃者，榮幸定何如。"]'),
('2738f200-69ab-4c8d-a601-3db0dc2a5b83','奉和聖製同二相已下羣官樂遊園宴','宋璟','唐','唐诗','tang','','[]','侍飲終酺會，承恩續勝遊。',72,'全唐诗/poet.tang.3000.json','["侍飲終酺會，承恩續勝遊。", "戴天惟慶幸，選地即殊尤。", "北向祗雙闕，南臨賞一丘。", "曲江新溜暖，上苑雜花稠。", "亹亹韶弦屢，戔戔賁帛周。", "醉歸填畛陌，榮耀接軒裘。"]'),
('24456bc4-6c68-403d-add5-c457d96d939e','奉和聖製送張說巡邊','宋璟','唐','唐诗','tang','','[]','帝道薄存兵，王師尚有征。',120,'全唐诗/poet.tang.3000.json','["帝道薄存兵，王師尚有征。", "是關司馬法，爰命總戎行。", "畫閫崇威信，分麾盛寵榮。", "聚觀方結轍，出祖遂傾城。", "聖酒江河潤，天詞象緯明。", "德風邊草偃，勝氣朔雲平。", "宰國推良器，爲軍挹壯聲。", "至和常得體，不戰即亡精。", "以智泉寧竭，其徐海自清。", "遲還廟堂坐，贈別故人情。"]'),
('53d0c581-0e12-44e7-9ccf-7dc0cd15ef43','奉和聖製荅張說扈從南出雀鼠谷','宋璟','唐','唐诗','tang','','[]','秦地雄西夏，幷州近北胡。',72,'全唐诗/poet.tang.3000.json','["秦地雄西夏，幷州近北胡。", "禹行山啓路，舜在邑爲都。", "忽視寒暄隔，深思險易殊。", "四時宗伯敘，六義宰臣鋪。", "徵作宮常應，星環日每紆。", "盛哉逢道合，良以致亨衢。"]'),
('ff89bf17-7bc1-4cfa-9ae1-780480585dc3','蒲津迎駕','宋璟','唐','唐诗','tang','','[]','回鑾下蒲坂，飛斾指秦京。',72,'全唐诗/poet.tang.3000.json','["回鑾下蒲坂，飛斾指秦京。", "雒上黃雲送，關中紫氣迎。", "霞朝看馬色，月曉聽雞鳴。", "防拒連山險，長橋壓水平。", "省方知化洽，察俗覺時清。", "天下長無事，空餘襟帶名。"]'),
('a8df3232-510b-4e12-9bdf-ffbb10e3842d','送蘇尚書赴益州','宋璟','唐','唐诗','tang','','[]','我望風煙接，君行霰雪飛。',24,'全唐诗/poet.tang.3000.json','["我望風煙接，君行霰雪飛。", "園亭若有送，楊柳最依依。"]'),
('906a6a83-5bcd-4def-bb92-4de4ba2f17a4','初春行宮侍宴應制','蘇味道','唐','唐诗','tang','','[]','溫液吐涓涓，跳波急應弦。',48,'全唐诗/poet.tang.3000.json','["溫液吐涓涓，跳波急應弦。", "簪裾承睿賞，花柳發韶年。", "聖酒千鍾洽，宸章七曜懸。", "微臣從此醉，還似夢鈞天。"]'),
('ba41f5b3-0724-4b6b-92ce-053736997079','單于川對雨二首 一','蘇味道','唐','唐诗','tang','','[]','崇朝遘行雨，薄晚屯密雲。',48,'全唐诗/poet.tang.3000.json','["崇朝遘行雨，薄晚屯密雲。", "緣階起素沫，竟水聚圓文。", "河柳低未舉，山花落已芬。", "清尊久不薦，淹留遂待君。"]'),
('0ddedd95-afc8-4aea-9391-a26facab3ba1','單于川對雨二首 二','蘇味道','唐','唐诗','tang','','[]','飛雨欲迎旬，浮雲已送春。',48,'全唐诗/poet.tang.3000.json','["飛雨欲迎旬，浮雲已送春。", "還從濯枝後，來應洗兵辰。", "氣合龍祠外，聲過鯨海濱。", "伐邢知有屬，已見靜邊塵。"]'),
('89f42555-6e9c-4dc6-83fb-43ab4d4078d8','正月十五夜','蘇味道','唐','唐诗','tang','','["\u8282\u65e5", "\u5143\u5bb5\u8282", "\u5143\u5bb5"]','火樹銀花合，星橋鐵鎖開。',48,'全唐诗/poet.tang.3000.json','["火樹銀花合，星橋鐵鎖開。", "暗塵隨馬去，明月逐人來。", "遊伎皆穠李，行歌盡落梅。", "金吾不禁夜，玉漏莫相催。"]'),
('88077fb4-9f1a-4297-acee-43a8384aec75','詠霧','蘇味道','唐','唐诗','tang','','[]','氤氳起洞壑，遙裔匝平疇。',48,'全唐诗/poet.tang.3000.json','["氤氳起洞壑，遙裔匝平疇。", "乍似含龍劒，還疑映蜃樓。", "拂林隨雨密，度徑帶煙浮。", "方謝公超步，終從彥輔遊。"]'),
('805134d3-3d71-496b-a4ae-08e6871461ec','詠虹','蘇味道','唐','唐诗','tang','','[]','紆餘帶星渚，窈窕架天潯。',48,'全唐诗/poet.tang.3000.json','["紆餘帶星渚，窈窕架天潯。", "空因壯士見，還共美人沈。", "逸照含良玉，神花藻瑞金。", "獨留長劒彩，終負昔賢心。"]'),
('0a73ae7a-1c7a-4cf9-9672-21f862e10993','詠霜','蘇味道','唐','唐诗','tang','','[]','金祇暮律盡，玉女暝氛歸。',48,'全唐诗/poet.tang.3000.json','["金祇暮律盡，玉女暝氛歸。", "孕冷隨鐘徹，飄華逐劒飛。", "帶日浮寒影，乘風進晚威。", "自有貞筠質，寧將庶草腓。"]'),
('c684ee9b-bc8e-4200-95ea-99111a47a544','詠井','蘇味道','唐','唐诗','tang','','[]','玲瓏映玉檻，澄澈瀉銀牀。',48,'全唐诗/poet.tang.3000.json','["玲瓏映玉檻，澄澈瀉銀牀。", "流聲集孔雀，帶影出羵羊。", "桐落秋蛙散，桃舒春錦芳。", "帝力終何有，機心庶此忘。"]'),
('a2880bfc-d719-4112-996d-1966277498af','詠石','蘇味道','唐','唐诗','tang','','["\u6cf0\u5c71"]','濟北甄神貺，河西濯錦文。',48,'全唐诗/poet.tang.3000.json','["濟北甄神貺，河西濯錦文。", "聲應天池雨，影觸岱宗雲。", "燕歸猶可候，羊起自成羣。", "何當握靈髓，高枕絕囂氛。"]'),
('c0588e68-3c28-4e1c-8556-9bddc9ba72e2','奉和受圖溫洛應制','蘇味道','唐','唐诗','tang','','[]','綠綺膺河檢，清壇俯洛濱。',60,'全唐诗/poet.tang.3000.json','["綠綺膺河檢，清壇俯洛濱。", "天旋俄制蹕，孝享屬嚴禋。", "陟配光三祖，懷柔洎百神。", "霧開中道日，雪歛屬車塵。", "預奉咸英奏，長歌億萬春。"]'),
('27f060ee-5220-495a-b43d-6f89453947f7','使嶺南聞崔馬二御史竝拜臺郎','蘇味道','唐','唐诗','tang','','[]','振鷺齊飛日，遷鶯遠聽聞。',72,'全唐诗/poet.tang.3000.json','["振鷺齊飛日，遷鶯遠聽聞。", "明光共待漏，清鑒各披雲。", "喜得廊廟舉，嗟爲臺閣分。", "故林懷柏悅，新幄阻蘭薰。", "冠去神羊影，車迎瑞雉羣。", "遠從南斗外，遙仰列星文。"]'),
('fb93bbef-9711-4f55-bf3d-f382d85d88f8','贈封御史入臺','蘇味道','唐','唐诗','tang','','[]','故事推三獨，茲辰對兩闈。',72,'全唐诗/poet.tang.3000.json','["故事推三獨，茲辰對兩闈。", "夕鴉共鳴舞，屈草接芳菲。", "盛府持清橐，殊章動繡衣。", "風連臺閣起，霜就簡書飛。", "凜凜當朝色，行行滿路威。", "惟當擊隼去，復覩落鵰歸。"]'),
('9da52e35-eb50-406d-a1eb-88f45e693fc3','始背洛城秋郊矚目奉懷臺中諸侍御','蘇味道','唐','唐诗','tang','','[]','薄遊忝霜署，直指戒冰心。',96,'全唐诗/poet.tang.3000.json','["薄遊忝霜署，直指戒冰心。", "荔浦方南紀，蘅臯暫北臨。", "山晴關塞斷，川暮廣城陰。", "場圃通圭甸，溝塍礙石林。", "野童來捃拾，田叟去謳吟。", "蟋蟀秋風起，蒹葭晚露深。", "帝城猶鬱鬱，征傳幾駸駸。", "迴憶披書地，勞歌謝所欽。"]'),
('42ee2e20-8a95-4add-b947-eaf2136cc75a','九江口南濟北接蘄春南與潯陽岸','蘇味道','唐','唐诗','tang','','[]','江路一悠哉，滔滔九派來。',96,'全唐诗/poet.tang.3000.json','["江路一悠哉，滔滔九派來。", "遠潭昏似霧，前浦沸成雷。", "鱗介多潛育，漁商幾泝洄。", "風搖蜀柹下，日照楚萍開。", "近漱湓城曲，斜吹蠡澤隈。", "錫龜猶入貢，浮獸罷爲災。", "津吏揮橈疾，郵童整傳催。", "歸心詎可問，爲視落潮迴。"]'),
('442e9d73-2d33-4a4b-992e-0b66097aada9','和武三思於天中寺尋復禮上人之作','蘇味道','唐','唐诗','tang','','[]','藩戚三雍暇，禪居二室隈。',120,'全唐诗/poet.tang.3000.json','["藩戚三雍暇，禪居二室隈。", "忽聞從桂苑，移步踐花臺。", "敏學推多藝，高談屬辯才。", "是非寧滯著，空有掠嫌猜。", "五行幽機暢，三蕃妙鍵開。", "味同甘露灑，香似逆風來。", "砌古留方石，池清辨燒灰。", "人尋鶴洲返，月逐虎谿迴。", "企躅瞻飛蓋，攀遊想渡杯。", "願陪爲善樂，從此去塵埃。"]'),
('3bb5db63-ce70-4f82-8e40-8aad78ae0f4b','嵩山石淙侍宴應制','蘇味道','唐','唐诗','tang','','[]','琱輿藻衞擁千官，仙洞靈谿訪九丹。',64,'全唐诗/poet.tang.3000.json','["琱輿藻衞擁千官，仙洞靈谿訪九丹。", "隱曖源花迷近路，參差嶺竹掃危壇。", "重崖對聳霞文駮，瀑水交飛雨氣寒。", "天洛宸襟有餘興，裴回周矖駐歸鑾。"]'),
('9466b4fb-2f61-4f56-af76-5fc24469b059','古劒篇','郭震','唐','唐诗','tang','','["\u6258\u7269\u8a00\u5fd7", "\u8c6a\u653e", "\u8c6a\u653e\u8bcd"]','君不見昆吾鐵冶飛炎煙，紅光紫氣俱赫然。',147,'全唐诗/poet.tang.3000.json','["君不見昆吾鐵冶飛炎煙，紅光紫氣俱赫然。", "良工鍛鍊凡幾年，鑄得寶劒名龍泉。", "龍泉顏色如霜雪，良工咨嗟歎奇絕。", "琉璃玉匣吐蓮花，錯鏤金環映明月。", "正逢天下無風塵，幸得周防君子身。", "精光黯黯青蛇色，文章片片綠龜鱗。", "非直結交游俠子，亦曾親近英雄人。", "何言中路遭棄捐，零落漂淪古獄邊。", "雖復塵埋無所用，猶能夜夜氣衝天。"]'),
('aa7c2c85-55c8-4d54-ab13-8f3fb6251fc5','塞上','郭震','唐','唐诗','tang','','[]','塞外虜塵飛，頻年出武威。',48,'全唐诗/poet.tang.3000.json','["塞外虜塵飛，頻年出武威。", "死生隨玉劒，辛苦向金微。", "久戍人將老，長征馬不肥。", "仍聞酒泉郡，已合數重圍。"]'),
('febe0eae-d6fd-4069-a337-d8dd9538c0b1','寄劉校書','郭震','唐','唐诗','tang','','["\u9ec4\u5c71"]','俗吏三年何足論，每將榮辱在朝昏。',64,'全唐诗/poet.tang.3000.json','["俗吏三年何足論，每將榮辱在朝昏。", "才微易向風塵老，身賤難酬知己恩。", "御苑殘鶯啼落日，黃山細雨濕歸軒。", "迴首漢家丞相府，昨來誰得掃重門。"]'),
('62f5584b-1083-4d0b-8fcd-16a80d900658','同徐員外除太子舍人寓直之作','郭震','唐','唐诗','tang','','[]','太子擅元良，宮臣命偉長。',72,'全唐诗/poet.tang.3000.json','["太子擅元良，宮臣命偉長。", "除榮辭會府，直宿總書坊。", "露濕幽巖桂，風吹便坐桑。", "閣連雲一色，池帶月重光。", "葉死蘭無氣，荷枯水不香。", "遙聞秋興作，言是晉中郎。"]'),
('d0ac00b2-92fa-4328-8db2-104d83d9a050','春江曲','郭震','唐','唐诗','tang','','["\u7231\u60c5"]','江水春沈沈，上有雙竹林。',24,'全唐诗/poet.tang.3000.json','["江水春沈沈，上有雙竹林。", "竹葉壞水色，郎亦壞人心。"]'),
('f1216559-15db-45c2-bb26-b812e75bda8d','王昭君三首 一','郭震','唐','唐诗','tang','','[]','自嫁單于國，長銜漢掖悲。',24,'全唐诗/poet.tang.3000.json','["自嫁單于國，長銜漢掖悲。", "容顏日憔悴，有甚畫圖時。"]'),
('ef9709b2-7956-4287-b3c5-666afb861638','王昭君三首 二','郭震','唐','唐诗','tang','','[]','厭踐冰霜域，嗟爲邊塞人。',24,'全唐诗/poet.tang.3000.json','["厭踐冰霜域，嗟爲邊塞人。", "思從漠南獵，一見漢家塵。"]'),
('98700c77-b793-4936-8930-3c7f92e64ff6','王昭君三首 三','郭震','唐','唐诗','tang','','[]','聞有南河信，傳言殺畫師。',24,'全唐诗/poet.tang.3000.json','["聞有南河信，傳言殺畫師。", "始知君念重，更肯惜蛾眉。"]'),
('fc2b73ee-d1ee-46c3-9e18-e1b686eb73b3','子夜四時歌六首 春歌 一','郭震','唐','唐诗','tang','','[]','陌頭楊柳枝，已被春風吹。',24,'全唐诗/poet.tang.3000.json','["陌頭楊柳枝，已被春風吹。", "妾心正斷絕，君懷那得知。"]'),
('fc751db7-c7cb-4162-af48-426a19260707','子夜四時歌六首 春歌 二','郭震','唐','唐诗','tang','','[]','青樓含日光，綠池起風色。',24,'全唐诗/poet.tang.3000.json','["青樓含日光，綠池起風色。", "贈子同心花，殷勤此何極。"]'),
('895e7596-5915-4c85-b423-6ac0dfe50c7a','子夜四時歌六首 秋歌 一','郭震','唐','唐诗','tang','','[]','邀歡空佇立，望美頻迴顧。',24,'全唐诗/poet.tang.3000.json','["邀歡空佇立，望美頻迴顧。", "何時復採菱，江中密相遇。"]'),
('b60f1d3b-accb-4a4b-ad54-822b34e508c7','子夜四時歌六首 秋歌 二','郭震','唐','唐诗','tang','','[]','辟惡茱萸囊，延年菊花酒。',24,'全唐诗/poet.tang.3000.json','["辟惡茱萸囊，延年菊花酒。", "與子結綢繆，丹心此何有。"]'),
('51cb95ca-86e1-4685-aa0f-29e68ca46d64','子夜四時歌六首 冬歌 一','郭震','唐','唐诗','tang','','[]','北極嚴氣昇，南至溫風謝。',24,'全唐诗/poet.tang.3000.json','["北極嚴氣昇，南至溫風謝。", "調絲競短歌，拂枕憐長夜。"]'),
('b6a14d98-8edb-461f-ad57-a894630ce352','子夜四時歌六首 冬歌 二','郭震','唐','唐诗','tang','','[]','帷橫雙翡翠，被卷兩鴛鴦。',24,'全唐诗/poet.tang.3000.json','["帷橫雙翡翠，被卷兩鴛鴦。", "婉態不自得，宛轉君王牀。"]'),
('bcafdc4a-26a8-4dfd-88cd-26f72992eda3','二月樂遊詩','郭震','唐','唐诗','tang','','[]','二月芳遊始，開軒望曉池。',48,'全唐诗/poet.tang.3000.json','["二月芳遊始，開軒望曉池。", "綠蘭日吐葉，紅蘂向盈枝。", "柳色行將改，君心幸莫移。", "陽春遽多意，唯願兩人知。"]'),
('ae6e1a23-7e8f-416d-be1a-f2475e1dc9ac','十月樂遊詩','郭震','唐','唐诗','tang','','[]','十月嚴陰盛，霜氣下玉臺。',48,'全唐诗/poet.tang.3000.json','["十月嚴陰盛，霜氣下玉臺。", "羅衣羞自解，綺帳待君開。", "銀箭更籌緩，金爐香氣來。", "愁仍夜未幾，已使炭成灰。"]'),
('8933ff79-8c52-4a93-822f-e9527aca2c0e','螢','郭震','唐','唐诗','tang','','[]','秋風凜凜月依依，飛過高梧影裏時。',32,'全唐诗/poet.tang.3000.json','["秋風凜凜月依依，飛過高梧影裏時。", "暗處若教同衆類，世間爭得有人知。"]'),
('1754c635-af53-4699-945e-ef1ebf8fa9de','蛩','郭震','唐','唐诗','tang','','[]','愁殺離家未達人，一聲聲到枕前聞。',32,'全唐诗/poet.tang.3000.json','["愁殺離家未達人，一聲聲到枕前聞。", "苦吟莫向朱門裏，滿耳笙歌不聽君。"]'),
('cc434ecd-0adc-4706-9218-de42a7f0d2d1','雲','郭震','唐','唐诗','tang','','[]','聚散虛空去復還，野人閑處倚筇看。',32,'全唐诗/poet.tang.3000.json','["聚散虛空去復還，野人閑處倚筇看。", "不知身是無根物，蔽月遮星作萬端。"]'),
('fd313e15-7845-4a24-be5f-34cd951f110a','野井','郭震','唐','唐诗','tang','','[]','縱無汲引味清澄，冷浸寒空月一輪。',32,'全唐诗/poet.tang.3000.json','["縱無汲引味清澄，冷浸寒空月一輪。", "鑿處若教當要路，爲君常濟往來人。"]'),
('da206264-d011-43ba-8b09-800ce616904b','米囊花','郭震','唐','唐诗','tang','','[]','開花空道勝于草，結實何曾濟得民。',32,'全唐诗/poet.tang.3000.json','["開花空道勝于草，結實何曾濟得民。", "却笑野田禾與黍，不聞弦管過青春。"]'),
('38b96fe2-4196-4a9d-9b80-2862e38376fd','惜花','郭震','唐','唐诗','tang','','[]','豔拂衣襟蘂拂杯，遶枝閑共蝶徘徊。',32,'全唐诗/poet.tang.3000.json','["豔拂衣襟蘂拂杯，遶枝閑共蝶徘徊。", "春風滿目還惆悵，半欲離披半未開。"]'),
('31bf5ad5-1a86-4866-9c6d-fc7a4aeee90b','蓮花','郭震','唐','唐诗','tang','','[]','臉膩香薰似有情，世間何物比輕盈。',32,'全唐诗/poet.tang.3000.json','["臉膩香薰似有情，世間何物比輕盈。", "湘妃雨後來池看，碧玉盤中弄水晶。"]'),
('cda42a70-1158-4d7e-a1de-b7580ff210cb','弘農清巖曲有磐石可坐宋十一每拂拭待余寄詩贈之','田遊巖','唐','唐诗','tang','','[]','信彼稱靈石，居然狎遁棲。',72,'全唐诗/poet.tang.3000.json','["信彼稱靈石，居然狎遁棲。", "裴回承翠巘，斌駁帶深谿。", "夕陰起層岫，清景半虹霓。", "風來應嘯阮，波動可琴嵇。", "僕也潁陽客，望彼空思齊。", "儻見山人至，簪嵩且杖藜。"]'),
('1459fba3-9168-4084-a1b4-07a2f567f1d1','和宋之問下山歌','王無競','唐','唐诗','tang','','[]','日云暮兮下嵩山，路連綿兮樹石間。',32,'全唐诗/poet.tang.3000.json','["日云暮兮下嵩山，路連綿兮樹石間。", "出谷口兮見明月，心裴回兮不能還。"]'),
('e82528ac-67d2-4f16-b739-e93558f132b1','北使長城','王無競','唐','唐诗','tang','','[]','秦世築長城，長城無極已。',108,'全唐诗/poet.tang.3000.json','["秦世築長城，長城無極已。", "暴兵四十萬，興工九千里。", "死人如亂麻，白骨相撐委。", "殫弊未云悟，窮毒豈知止。", "胡塵未北滅，楚兵遽東起。", "六國復囂囂，兩龍鬬觺觺。", "卯金竟握讖，反璧俄淪祀。", "仁義寢邦國，狙暴行終始。", "一旦咸陽宮，翻爲漢朝市。"]'),
('2e4b1b0b-32ba-4b99-b3dd-8a20ae5bba4a','鳳臺曲','王無競','唐','唐诗','tang','','[]','鳳臺何逶迤，嬴女管參差。',48,'全唐诗/poet.tang.3000.json','["鳳臺何逶迤，嬴女管參差。", "一旦綵雲至，身去無還期。", "遺曲此臺上，世人多學吹。", "一吹一落淚，至今憐玉姿。"]'),
('9dfa0900-dc39-41fb-ae4b-b63e01c508f8','銅雀臺','王無競','唐','唐诗','tang','','[]','北登銅雀上，西望青松郭。',72,'全唐诗/poet.tang.3000.json','["北登銅雀上，西望青松郭。", "繐帳空蒼蒼，陵田紛漠漠。", "平生事已變，歌吹宛猶昨。", "長袖拂玉塵，遺情結羅幕。", "妾怨在朝露，君恩豈中薄。", "高臺奏曲終，曲終淚橫落。"]'),
('df09ddaf-1bf8-4f8e-bd67-c0d38476507b','巫山','王無競','唐','唐诗','tang','','[]','神女向高唐，巫山下夕陽。',48,'全唐诗/poet.tang.3000.json','["神女向高唐，巫山下夕陽。", "裴回行作雨，婉孌逐荆王。", "電影江前落，雷聲峽外長。", "朝雲無處所，臺館曉蒼蒼。"]'),
('55c39448-211c-4209-882a-36e2cad7751b','和宋之問下山歌','賈曾','唐','唐诗','tang','','[]','良遊晼晚兮月呈光，錦路逶迤兮山路長。',36,'全唐诗/poet.tang.3000.json','["良遊晼晚兮月呈光，錦路逶迤兮山路長。", "王孫不留兮歲將晏，嵩巖仙草兮爲誰芳。"]'),
('cd0a6452-0a5d-49bb-9e3c-640a2a7132f5','孝和皇帝輓歌','賈曾','唐','唐诗','tang','','[]','新命千齡啓，鴻圖累聖餘。',48,'全唐诗/poet.tang.3000.json','["新命千齡啓，鴻圖累聖餘。", "天行應潛躍，帝出受圖書。", "禮若傳堯舊，功疑復夏初。", "夢遊長不返，何國是華胥。"]'),
('0c96c6d5-d2f9-469c-8d65-2aec39d01950','奉和春日出苑矚目應令','賈曾','唐','唐诗','tang','','[]','銅龍曉闢問安迴，金輅春遊博望開。',64,'全唐诗/poet.tang.3000.json','["銅龍曉闢問安迴，金輅春遊博望開。", "渭北晴光搖草樹，終南佳氣入樓臺。", "招賢已得商山老，託乘還徵鄴下才。", "臣在東周獨留滯，忻逢睿藻日邊來。"]'),
('3b77b1f0-92f2-45d4-bf1a-4816d576267f','有所思','賈曾','唐','唐诗','tang','','[]','洛陽城東桃李花，飛來飛去落誰家。',80,'全唐诗/poet.tang.3000.json','["洛陽城東桃李花，飛來飛去落誰家。", "幽閨女兒愛顏色，坐見落花長歎息。", "今歲花開君不待，明年花開復誰在。", "故人不共洛陽東，今來空對落花風。", "年年歲歲花相似，歲歲年年人不同。"]'),
('7c29f4de-276f-4e7e-8fd7-3bb81d7080d6','祭汾陰樂章','賈曾','唐','唐诗','tang','','[]','蠲我漸饎，潔我膋薌。',40,'全唐诗/poet.tang.3000.json','["蠲我漸饎，潔我膋薌。", "有豆孔碩，爲羞既臧。", "至城無昧，精意惟芳。", "神其醉止，欣欣樂康。"]'),
('1501641f-3a17-4e35-9acd-9e5740050a4d','使至汴州喜逢宋之問','李夔','唐','唐诗','tang','','[]','阮籍蓬池上，孤韻竹林才。',48,'全唐诗/poet.tang.3000.json','["阮籍蓬池上，孤韻竹林才。", "巨源從吏道，正擁使車來。", "相逢且交臂，相命且銜杯。", "醉後長歌畢，餘聲繞吹臺。"]'),
('6bddec91-2cbe-45b3-b738-7b43bf87bab3','祭汾陰樂章','崔玄童','唐','唐诗','tang','','[]','聿修嚴配，展事禋宗。',40,'全唐诗/poet.tang.3000.json','["聿修嚴配，展事禋宗。", "祥符寶鼎，禮備黃琮。", "祝詞以信，明德惟聰。", "介茲景福，永永無窮。"]'),
('5f3f7164-942a-470b-a3cc-70190f28690a','祭汾陰樂章','何鸞','唐','唐诗','tang','','[]','樂奏云闋，禮章載虔。',40,'全唐诗/poet.tang.3000.json','["樂奏云闋，禮章載虔。", "禋宗於地，昭假於天。", "惟馨薦矣，既醉歆焉。", "神之降福，永永萬年。"]'),
('9c1650df-0cab-4f13-afe9-d73e5a13d861','祭汾陰樂章','蔣挺','唐','唐诗','tang','','[]','維歲之吉，維辰之良。',40,'全唐诗/poet.tang.3000.json','["維歲之吉，維辰之良。", "聖君紱冕，肅事壇場。", "大禮已備，大樂斯張。", "神其醉止，降福無疆。"]'),
('9f83489d-3526-48c8-a5d6-ccff7c3ba9d7','關山月','崔融','唐','唐诗','tang','','[]','月生西海上，氣逐邊風壯。',48,'全唐诗/poet.tang.3000.json','["月生西海上，氣逐邊風壯。", "萬里度關山，蒼茫非一狀。", "漢兵開郡國，胡馬窺亭障。", "夜夜聞悲笳，征人起南望。"]'),
('5af9518c-089e-4d8d-8c52-51ae24c86142','擬古','崔融','唐','唐诗','tang','','[]','飲馬臨濁河，濁河深不測。',120,'全唐诗/poet.tang.3000.json','["飲馬臨濁河，濁河深不測。", "河水日東注，河源乃西極。", "思君正如此，誰爲生羽翼。", "日夕大川陰，雲霞千里色。", "所思在河處，宛在機中織。", "離夢當有魂，愁容定無力。", "夙齡負奇志，中夜三歎息。", "拔劒斬長榆，彎弓射小棘。", "班張固非擬，衞霍行可即。", "寄謝閨中人，努力加飱食。"]'),
('b7feb657-3ea9-410f-acca-c4d2b008bed3','西征軍行遇風','崔融','唐','唐诗','tang','','[]','北風卷塵沙，左右不相識。',120,'全唐诗/poet.tang.3000.json','["北風卷塵沙，左右不相識。", "颯颯吹萬里，昏昏同一色。", "馬煩莫敢進，人急未遑食。", "曹木春更悲，天景晝相匿。", "夙齡慕忠義，雅尚存孤直。", "覽史懷浸驕，讀詩歎孔棘。", "及茲戎旅地，忝從書記職。", "兵氣騰北荒，軍聲振西極。", "坐覺威靈遠，行看氛祲息。", "愚臣何以報，倚馬申微力。"]'),
('eea4adec-a57e-4303-963e-6d22a86a93f6','塞垣行','崔融','唐','唐诗','tang','','["\u9ec4\u6cb3"]','疾風捲溟海，萬里揚沙礫。',132,'全唐诗/poet.tang.3000.json','["疾風捲溟海，萬里揚沙礫。", "仰望不見天，昏昏竟朝夕。", "是時軍兩進，東拒復西敵。", "蔽山張旗鼓，間道潛鋒鏑。", "精騎突曉圍，奇兵襲暗壁。", "十月邊塞寒，四山沍陰積。", "雨雪鴈南飛，風塵景西迫。", "昔我事討論，未嘗怠經籍。", "一朝棄筆硯，十年操矛戟。", "豈要黃河誓，須勒燕山石。", "可嗟牧羊臣，海外久爲客。"]'),
('6d1a1b29-8a18-4332-bfd0-34be746bbbac','登東陽沈隱侯八詠樓','崔融','唐','唐诗','tang','','[]','旦登西北樓，樓峻石墉厚。',120,'全唐诗/poet.tang.3000.json','["旦登西北樓，樓峻石墉厚。", "宛生長定□，俯壓三江口。", "排階銜鳥衡，交疏過牛斗。", "左右會稽鎮，出入具區藪。", "越巖森其前，浙江漫其後。", "此地實東陽，由來山水鄉。", "隱侯有遺詠，落簡尚餘芳。", "具物昔未改，斯人今已亡。", "粵余忝藩左，束髪事文場。", "悵不見夫子，神期遙相望。"]'),
('c09f0472-304b-4e70-8577-6746b47945c4','從軍行','崔融','唐','唐诗','tang','','[]','穹廬雜種亂金方，武將神兵下玉堂。',112,'全唐诗/poet.tang.3000.json','["穹廬雜種亂金方，武將神兵下玉堂。", "天子旌旗過細柳，匈奴運數盡枯楊。", "關頭落月橫西嶺，塞下凝雲斷北荒。", "漠漠邊塵飛衆鳥，昏昏朔氣聚羣羊。", "依稀蜀杖迷新竹，髣髴胡牀識故桑。", "臨海舊來聞驃騎，尋河本自有中郎。", "坐看戰壁爲平土，近待軍營作破羌。"]'),
('62a22393-b9b9-498a-9991-91d5bb0ffee4','和宋之問寒食題黃梅臨江驛','崔融','唐','唐诗','tang','','[]','春分自淮北，寒食渡江南。',48,'全唐诗/poet.tang.3000.json','["春分自淮北，寒食渡江南。", "忽見潯陽水，疑是宋家潭。", "明主閽難呌，孤臣逐未堪。", "遙思故園陌，桃李正酣酣。"]'),
('18d34365-d89f-49e2-8aca-7e9a4e355677','留別杜審言幷呈洛中舊遊','崔融','唐','唐诗','tang','','[]','斑鬢今爲別，紅顏昨共遊。',48,'全唐诗/poet.tang.3000.json','["斑鬢今爲別，紅顏昨共遊。", "年年春不待，處處酒相留。", "駐馬西橋上，回車南陌頭。", "故人從此隔，風月坐悠悠。"]'),
('f7b620aa-a172-4bcf-8c03-0328c1113cbc','詠寶劒','崔融','唐','唐诗','tang','','[]','寶劒出昆吾，龜龍夾采珠。',48,'全唐诗/poet.tang.3000.json','["寶劒出昆吾，龜龍夾采珠。", "五精初獻術，千戶競淪都。", "匣氣衝牛斗，山形轉轆轤。", "欲知天下貴，持此問風胡。"]'),
('a53d834c-14a4-4ddf-8cfb-3f6e6d8a1b60','吳中好風景','崔融','唐','唐诗','tang','','[]','洛渚問吳潮，吳門想洛橋。',48,'全唐诗/poet.tang.3000.json','["洛渚問吳潮，吳門想洛橋。", "夕煙楊柳岸，春水木蘭橈。", "城邑高樓近，星辰北斗遙。", "無因生羽翼，輕舉託還飆。"]'),
('e6439a49-592a-40ad-a73e-801dc711eadf','則天皇后挽歌二首 一','崔融','唐','唐诗','tang','','[]','宵陳虛禁夜，夕臨空山陰。',48,'全唐诗/poet.tang.3000.json','["宵陳虛禁夜，夕臨空山陰。", "日月昏尺景，天地慘何心。", "紫殿金鋪澀，黃陵玉座深。", "鏡匳長不啓，聖主淚霑巾。"]'),
('1b4abac6-1205-4d47-98b2-609597527b97','則天皇后挽歌二首 二','崔融','唐','唐诗','tang','','[]','前殿臨朝罷，長陵合葬歸。',48,'全唐诗/poet.tang.3000.json','["前殿臨朝罷，長陵合葬歸。", "山川不可望，文物盡成非。", "陰月霾中道，軒星落太微。", "空餘天子孝，松上景雲飛。"]'),
('f39f0489-ddeb-447c-9c64-8f36596c1bea','戶部尚書崔公挽歌','崔融','唐','唐诗','tang','','[]','八座圖書委，三臺章奏盈。',48,'全唐诗/poet.tang.3000.json','["八座圖書委，三臺章奏盈。", "舉杯常有勸，曳履忽無聲。", "市若荆州罷，池如薛縣平。", "空餘濟南劒，天子署高名。"]'),
('b81758d0-66aa-4f12-ae5e-d1b5ffb6d355','韋長史挽詞','崔融','唐','唐诗','tang','','[]','日落桑榆下，寒生松柏中。',48,'全唐诗/poet.tang.3000.json','["日落桑榆下，寒生松柏中。", "冥冥多苦霧，切切有悲風。", "京兆新阡闢，扶陽甲第空。", "郭門從此去，荆棘漸蒙籠。"]'),
('08fa9396-b756-4bf1-830d-908b91be67ac','和梁王衆傳張光祿是王子晉後身','崔融','唐','唐诗','tang','','[]','聞有沖天客，披雲下帝畿。',120,'全唐诗/poet.tang.3000.json','["聞有沖天客，披雲下帝畿。", "三年上賓去，千載忽來歸。", "昔偶浮丘伯，今同丁令威。", "中郎才貌是，柱史姓名非。", "祗召趨龍闕，承恩拜虎闈。", "丹成金鼎獻，酒至玉杯揮。", "天仗分旄節，朝容間羽衣。", "舊壇何處所，新廟坐光輝。", "漢主存仙要，淮南愛道機。", "朝朝緱氏鶴，長向洛城飛。"]'),
('ee1cd0c3-f7ad-4ac8-a80f-21a4a14e2cf7','哭蔣詹事儼','崔融','唐','唐诗','tang','','[]','江上有長離，從容盛羽儀。',240,'全唐诗/poet.tang.3000.json','["江上有長離，從容盛羽儀。", "一鳴百獸舞，一舉羣鳥隨。", "應我聖明代，巢君阿閣垂。", "鉤陳侍帷扆，環衞奉旌麾。", "雅量滄海納，完才廟廊施。", "養親光孝道，事主竭忠規。", "貞節既已固，殊榮良不訾。", "朝遊雲漢省，夕宴芙蓉池。", "汲黯言當直，陳平智本奇。", "功成喜身退，時往惜年馳。", "鎮國山基毀，中天柱石頹。", "將軍空有頌，刺史獨留碑。", "蕪漫藏書壁，荒涼懸劒枝。", "昔余參下位，數載忝牽羈。", "置榻恩逾重，迎門禮自卑。", "竹林常接興，黍谷每逢吹。", "逸翰金相發，清談玉柄揮。", "不輕文舉少，深歎子雲疲。", "遺愛猶如在，殘編尚可窺。", "即今流水曲，何處俗人知。"]'),
('34447457-a278-449e-9750-5f2a39eef734','嵩山石淙侍宴應制','崔融','唐','唐诗','tang','','[]','洞口仙巖類削成，泉香石冷晝含清。',64,'全唐诗/poet.tang.3000.json','["洞口仙巖類削成，泉香石冷晝含清。", "龍旗畫月中天下，鳳管披雲此地迎。", "樹作帷屏陽景翳，芝如宮闕夏涼生。", "今朝出豫臨懸圃，明日陪遊向赤城。"]'),
('1f5818c2-5310-4d08-8f21-7c8a3abefae3','塞上寄內','崔融','唐','唐诗','tang','','[]','旅魂驚塞北，歸望斷河西。',24,'全唐诗/poet.tang.3000.json','["旅魂驚塞北，歸望斷河西。", "春風若可寄，暫爲遶蘭閨。"]'),
('64f7fdb5-a18e-483d-abdb-1aa4be47ffc3','侍從途中口號應制','閻朝隱','唐','唐诗','tang','','[]','疵賤出山東，忠貞任土風。',48,'全唐诗/poet.tang.3000.json','["疵賤出山東，忠貞任土風。", "因敷河朔藻，得奉洛陽宮。", "一顧侍御史，再顧給事中。", "常願粉肌骨，特荅造化功。"]'),
('59fee0f6-4c9e-4f8a-b203-2e96f11f3ad6','奉和聖製夏日遊石淙山','閻朝隱','唐','唐诗','tang','','[]','金臺隱隱陵黃道，玉輦亭亭下絳雰。',64,'全唐诗/poet.tang.3000.json','["金臺隱隱陵黃道，玉輦亭亭下絳雰。", "千種岡巒千種樹，一重巖壑一重雲。", "花落風吹紅的歷，藤垂日晃綠葐蒀。", "五百里內賢人聚，願陪閶闔侍天文。"]'),
('34751bd9-cc56-4d97-b75a-ff8665fd9b27','鸚鵡貓兒篇','閻朝隱','唐','唐诗','tang','','[]','霹靂引，豐隆鳴，猛獸噫氣蛇吼聲。',375,'全唐诗/poet.tang.3000.json','["霹靂引，豐隆鳴，猛獸噫氣蛇吼聲。", "鸚鵡鳥，同資造化兮殊粹精。", "鷫鸘毛，翡翠翼。", "鵷雛延頸，鵾雞弄色。", "鸚鵡鳥，同稟陰陽兮異埏埴。", "彼何爲兮，隱隱振振。", "此何爲兮，綠衣翠襟。", "彼何爲兮，窘窘蠢蠢。", "此何爲兮，好貌好音。", "彷彷兮徉徉，似妖姬躧步兮動羅裳。", "趨趨兮蹌蹌，若處子迴眸兮登玉堂。", "爰有獸也，安其忍，觜其脇，距其胸，與之放曠浪浪兮，從從容容。", "鉤爪鋸牙也，宵行晝伏無以當，遇之兮忘味。", "摶擊騰擲也，朝飛暮噪無以拒，逢之兮屏氣。", "由是言之，貪殘薄則智慧作，貪殘臨之兮不復攫。", "由是言之，智慧周則貪殘囚，智慧犯之兮不復憂。", "菲形陋質雖賤微，皇王顧遇長光輝。", "離宮別館臨朝市，妙舞繁弦雜宮徵。", "嘉喜堂前景福內，合歡殿上明光裏。", "雲母屏風文彩合，流蘇斗帳香煙起。", "承恩宴盼接宴喜，高視七頭金駱駝。", "平懷五尺銅獅子，國有君兮國有臣。", "君爲主兮臣爲賓，朝有賢兮朝有德。", "賢爲君兮德爲飾，千年萬歲兮心轉憶。"]'),
('f2d1e4b8-f91b-49d4-bbac-883e06e18231','三日曲水侍宴應制','閻朝隱','唐','唐诗','tang','','[]','三月重三日，千春續萬春。',48,'全唐诗/poet.tang.3000.json','["三月重三日，千春續萬春。", "聖澤如東海，天文似北辰。", "荷葉珠盤淨，蓮花寶蓋新。", "陛下制萬國，臣作水心人。"]'),
('e6e8562f-4559-4764-88d2-571bf6c453f9','奉和九日幸臨渭亭登高應制得筵字','閻朝隱','唐','唐诗','tang','','[]','九九侍神仙，高高坐半天。',48,'全唐诗/poet.tang.3000.json','["九九侍神仙，高高坐半天。", "文章二曜動，氣色五星連。", "簪紱趨皇極，笙歌接御筵。", "願因茱菊酒，相守百千年。"]'),
('4b82ee19-dea7-49e8-abf0-e112106ca294','奉和送金城公主適西蕃應制','閻朝隱','唐','唐诗','tang','','[]','甥舅重親地，君臣厚義鄉。',48,'全唐诗/poet.tang.3000.json','["甥舅重親地，君臣厚義鄉。", "還將貴公主，嫁與耨檀王。", "鹵簿山河暗，琵琶道路長。", "迴瞻父母國，日出在東方。"]'),
('33d16f6f-9b4c-44bf-aa91-a4bbdb69cc8d','奉和立春遊苑迎春應制','閻朝隱','唐','唐诗','tang','','[]','管籥周移寰極裏，乘輿望幸斗城闉。',64,'全唐诗/poet.tang.3000.json','["管籥周移寰極裏，乘輿望幸斗城闉。", "草根未結青絲縷，蘿蔦猶垂綠帔巾。", "鵲入巢中言改歲，燕銜書上道宜新。", "願得長繩繫取日，光臨天子萬年春。"]'),
('8bc76614-4316-4956-9a0b-a2e7445e0c25','奉和聖製春日幸望春宮應制','閻朝隱','唐','唐诗','tang','','[]','句芒人面乘兩龍，道是春神衞九重。',64,'全唐诗/poet.tang.3000.json','["句芒人面乘兩龍，道是春神衞九重。", "綵勝年年逢七日，酴醿歲歲滿千鍾。", "宮梅間雪祥光遍，城柳含煙淑氣濃。", "醉倒君前情未盡，願因歌舞自爲容。"]'),
('cbcb4558-8691-4316-8578-bba8e041f621','夜宴安樂公主新宅','閻朝隱','唐','唐诗','tang','','[]','鳳皇鳴舞樂昌年，蠟炬開花夜管弦。',32,'全唐诗/poet.tang.3000.json','["鳳皇鳴舞樂昌年，蠟炬開花夜管弦。", "半醉徐擊珊瑚樹，已聞鐘漏曉聲傳。"]'),
('87479a4e-45d9-46e9-8c31-3486c317f7c5','餞唐永昌','閻朝隱','唐','唐诗','tang','','[]','洛陽難理若棼絲，椎破連環定不疑。',32,'全唐诗/poet.tang.3000.json','["洛陽難理若棼絲，椎破連環定不疑。", "鸚鵡休言秦地樂，回頭一顧一相思。"]'),
('f6ed618a-fbeb-4f43-ae2d-833c60f477ba','明月歌','閻朝隱','唐','唐诗','tang','','[]','梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠泠刻漏長。',40,'全唐诗/poet.tang.3000.json','["梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠泠刻漏長。", "揮玉指，拂羅裳，爲君一奏楚明光。"]'),
('2d386c8a-aab5-4ed2-a19d-63db3efdbf91','采蓮女','閻朝隱','唐','唐诗','tang','','[]','采蓮女，采蓮舟，春日春江碧水流。',44,'全唐诗/poet.tang.3000.json','["采蓮女，采蓮舟，春日春江碧水流。", "蓮衣承玉釧，蓮刺罥銀鉤。", "薄暮斂容歌一曲，氛氳香氣滿汀洲。"]'),
('668a791f-5475-447f-a473-aff1a64754c1','奉和登驪山應制','閻朝隱','唐','唐诗','tang','','[]','龍行踏絳氣，天半語相聞。',24,'全唐诗/poet.tang.3000.json','["龍行踏絳氣，天半語相聞。", "混沌疑初判，洪荒若始分。"]'),
('3cbef4ae-209c-4d7a-8e59-034ae5638d29','奉和九日幸臨渭亭登高應制得月字','韋元旦','唐','唐诗','tang','','[]','雲物開千里，天行乘九月。',48,'全唐诗/poet.tang.3000.json','["雲物開千里，天行乘九月。", "絲言丹鳳池，斾轉蒼龍闕。", "灞水歡娛地，秦京游俠窟。", "欣承解慍詞，聖酒黃花發。"]'),
('784c6515-baff-443f-a581-6d66079a0806','奉和送金城公主適西蕃應制','韋元旦','唐','唐诗','tang','','[]','柔遠安夷俗，和親重漢年。',48,'全唐诗/poet.tang.3000.json','["柔遠安夷俗，和親重漢年。", "軍容旌節送，國命錦車傳。", "琴曲悲千里，簫聲戀九天。", "唯應西海月，來就掌珠圓。"]'),
('f50656c8-2f41-4214-8faa-3509c92bf247','餞唐州高使君赴任','韋元旦','唐','唐诗','tang','','[]','桐栢膺新命，芝蘭惜舊遊。',48,'全唐诗/poet.tang.3000.json','["桐栢膺新命，芝蘭惜舊遊。", "鳴臯夜鶴在，遷木早鶯求。", "傳擁淮源路，尊空灞水流。", "落花紛送遠，春色引離憂。"]'),
('891830f3-a5e9-491c-9c52-08f3a518341d','早朝','韋元旦','唐','唐诗','tang','','[]','震維芳月季，宸極衆星尊。',72,'全唐诗/poet.tang.3000.json','["震維芳月季，宸極衆星尊。", "珮玉朝三陛，鳴珂度九門。", "挈壺分早漏，伏檻耀初暾。", "北倚蒼龍闕，西臨紫鳳垣。", "詞庭草欲奏，溫室樹無言。", "鱗翰空爲忝，長懷聖主恩。"]'),
('978693d7-b514-4066-91b5-b0cbcc7612af','奉和立春游苑迎春應制','韋元旦','唐','唐诗','tang','','[]','灞涘長安恆近日，殷正臘月早迎新。',64,'全唐诗/poet.tang.3000.json','["灞涘長安恆近日，殷正臘月早迎新。", "池魚戲葉仍含凍，宮女裁花已作春。", "向苑雲疑承翠幄，入林風若起青蘋。", "年年斗柄東無限，願挹瓊觴壽北辰。"]'),
('d432e111-a6f1-4c17-8de9-242301dbc227','奉和聖製春日幸望春宮應制','韋元旦','唐','唐诗','tang','','[]','九重樓閣半山霞，四望韶陽春未賒。',64,'全唐诗/poet.tang.3000.json','["九重樓閣半山霞，四望韶陽春未賒。", "侍蹕妍歌臨灞涘，留觴豔舞出京華。", "危竿競捧中街日，戲馬爭銜上苑花。", "景色歡娛長若此，承恩不醉不還家。"]'),
('c658ad41-604f-4712-a4fb-28fc60eb82b8','奉和人日宴大明宮恩賜綵縷人勝應制','韋元旦','唐','唐诗','tang','','[]','鸞鳳旌旗拂曉陳，魚龍角觝大明辰。',64,'全唐诗/poet.tang.3000.json','["鸞鳳旌旗拂曉陳，魚龍角觝大明辰。", "青韶既肇人爲日，綺勝初成日作人。", "聖藻凌雲裁栢賦，仙歌促宴摘梅春。", "垂旒一慶宜年酒，朝野俱歡薦壽新。"]'),
('aeb87a16-962c-4c1f-9f0e-6d0d3297c8d6','奉和幸安樂公主山莊應制','韋元旦','唐','唐诗','tang','','[]','銀河南渚帝城隅，帝輦平明出九衢。',64,'全唐诗/poet.tang.3000.json','["銀河南渚帝城隅，帝輦平明出九衢。", "刻鳳蟠螭凌桂邸，穿池疊石寫蓬壺。", "瓊簫暫下鈞天樂，綺綴長懸明月珠。", "仙牓承恩爭既醉，方知朝野更歡娛。"]'),
('5053867b-e73f-4928-a7d5-634b4b5b3fcd','興慶池侍宴應制','韋元旦','唐','唐诗','tang','','[]','滄池漭沆帝城邊，殊勝昆明鑿漢年。',64,'全唐诗/poet.tang.3000.json','["滄池漭沆帝城邊，殊勝昆明鑿漢年。", "夾岸旌旗疏輦道，中流簫鼓振樓船。", "雲峰四起迎宸幄，水樹千重入御筵。", "宴樂已深魚藻詠，承恩更欲奏甘泉。"]'),
('835e1487-e59d-485b-b54d-9ca42734b145','夜宴安樂公主宅','韋元旦','唐','唐诗','tang','','[]','主第新成銀作牓，賓筵廣宴玉爲樓。',32,'全唐诗/poet.tang.3000.json','["主第新成銀作牓，賓筵廣宴玉爲樓。", "壺觴既卜仙人夜，歌舞宜停織女秋。"]'),
('21d11f74-3e97-4d16-be94-e8cc6aca8e96','奉和初春幸太平公主南莊應制','邵昇','唐','唐诗','tang','','[]','沁園佳麗奪蓬瀛，翠壁紅泉繞上京。',64,'全唐诗/poet.tang.3000.json','["沁園佳麗奪蓬瀛，翠壁紅泉繞上京。", "二聖忽從鸞殿幸，雙仙正下鳳樓迎。", "花含步輦空間出，樹雜帷宮畫裏行。", "無路乘槎窺漢渚，徒知訪卜就君平。"]'),
('5d3017ee-fdf9-4f87-a1ab-4f4fac7a974d','奉和送金城公主適西蕃應制','唐遠悊','唐','唐诗','tang','','[]','皇恩睠下人，割愛遠和親。',48,'全唐诗/poet.tang.3000.json','["皇恩睠下人，割愛遠和親。", "少女風遊兌，姮娥月去秦。", "龍笛迎金榜，驪歌送錦輪。", "那堪桃李色，移向虜庭春。"]'),
('de546d8c-ba1d-4031-b5ab-41576897784a','汾陰后土祠作','李適','唐','唐诗','tang','','[]','昔予讀舊史，遍覩漢世君。',120,'全唐诗/poet.tang.3000.json','["昔予讀舊史，遍覩漢世君。", "武皇實稽古，建茲百代勳。", "號令垂懋典，舊經備闕文。", "西巡歷九嶷，舳艫被江濱。", "勒兵十八萬，旌旗何紛紛。", "朅來茂陵下，英聲不復聞。", "我行歲方晏，極望山河分。", "神光終冥漠，鼎氣獨氛氳。", "攬涕步脽上，登高見彼汾。", "雄圖今安在，飛飛有白雲。"]'),
('07adc881-4b12-47dc-8691-e616f4c60032','荅宋十一崖口五渡見贈','李適','唐','唐诗','tang','','[]','聞君訪遠山，躋險造幽絕。',120,'全唐诗/poet.tang.3000.json','["聞君訪遠山，躋險造幽絕。", "眇然青雲境，觀奇彌年月。", "登嶺亦泝溪，孤舟事沿越。", "崿嶂傳彩翠，崖磴互欹缺。", "石林上攢藂，金澗下明滅。", "捫壁窺丹井，梯苔瞰乳穴。", "忽枉巖中贈，對翫未嘗輟。", "殷勤獨往事，委曲鍊藥說。", "邀余名山期，從爾泛海澨。", "歲晏秉宿心，斯言非徒設。"]'),
('5008f289-7310-407e-bad2-2cec0283392f','餞許州宋司馬赴任','李適','唐','唐诗','tang','','[]','昔吾遊箕山，朅來涉潁水。',48,'全唐诗/poet.tang.3000.json','["昔吾遊箕山，朅來涉潁水。", "復有許由廟，迢迢白雲裏。", "聞君佐繁昌，臨風悵懷此。", "儻到平輿泉，寄謝干將里。"]'),
('f6d104a2-b07d-49a0-9847-6100af4512fe','奉和聖製九日侍宴應制得高字','李適','唐','唐诗','tang','','[]','禁苑秋光入，宸遊霽色高。',48,'全唐诗/poet.tang.3000.json','["禁苑秋光入，宸遊霽色高。", "萸房頒綵笥，菊蘂薦香醪。", "後騎縈堤柳，前旌拂御桃。", "王枚俱得從，淺淺愧飛毫。"]'),
('9ae06ef1-da07-432f-9b40-1ff8f6b9f566','遊禁苑幸臨渭亭遇雪應制','李適','唐','唐诗','tang','','[]','長樂喜春歸，披香瑞雪霏。',48,'全唐诗/poet.tang.3000.json','["長樂喜春歸，披香瑞雪霏。", "花從銀閤度，絮繞玉窗飛。", "寫曜銜天藻，呈祥拂御衣。", "上林紛可望，無處不光輝。"]'),
('ff987161-b81b-4493-97c0-7e9ad0c9840c','奉和九日登慈恩寺浮圖應制','李適','唐','唐诗','tang','','[]','鳳輦乘朝霽，鸚林對晚秋。',48,'全唐诗/poet.tang.3000.json','["鳳輦乘朝霽，鸚林對晚秋。", "天文貝葉寫，聖澤菊花浮。", "塔似神功造，龕疑佛影留。", "幸陪清漢蹕，欣奉淨居遊。"]'),
('de1f9a15-20cd-466f-a15e-87f0396b7851','侍宴長寧公主東莊應制','李適','唐','唐诗','tang','','[]','鳳樓紆睿幸，龍舸暢宸襟。',48,'全唐诗/poet.tang.3000.json','["鳳樓紆睿幸，龍舸暢宸襟。", "歌舞平陽第，園亭沁水林。", "山花添聖酒，澗竹繞熏琴。", "願奉瑤池駕，千春侍德音。"]'),
('f1cb3949-a366-4e57-985d-126ae6481be4','奉和送金城公主適西蕃應制','李適','唐','唐诗','tang','','[]','絳河從遠聘，青海赴和親。',48,'全唐诗/poet.tang.3000.json','["絳河從遠聘，青海赴和親。", "月作臨邊曉，花爲度隴春。", "主歌悲顧鶴，帝策重安人。", "獨有瓊簫去，悠悠思錦輪。"]'),
('7b8aaaf0-3c10-4ef6-ba8b-f7d711da9b77','安樂公主移入新宅','李適','唐','唐诗','tang','','[]','星橋他日創，仙榜此時開。',48,'全唐诗/poet.tang.3000.json','["星橋他日創，仙榜此時開。", "馬向鋪錢埒，簫聞奏玉臺。", "人疑衞叔美，客似長卿才。", "借問遊天使，誰能取石回。"]'),
('001434fc-eb06-43dc-8601-4953e6878524','奉和幸望春宮送朔方軍大總管張仁亶','李適','唐','唐诗','tang','','[]','地限驕南牧，天臨餞北征。',48,'全唐诗/poet.tang.3000.json','["地限驕南牧，天臨餞北征。", "解衣延寵命，橫劒總威名。", "豹略恭宸旨，雄文動睿情。", "坐觀膜拜入，朝夕受降城。"]'),
('b1a9e168-42cd-4a42-a36f-c03de3f9908d','人日宴大明宮恩賜綵縷人勝應制','李適','唐','唐诗','tang','','[]','朱城待鳳韶年至，碧殿疏龍淑氣來。',64,'全唐诗/poet.tang.3000.json','["朱城待鳳韶年至，碧殿疏龍淑氣來。", "寶帳金屏人已帖，圖花學鳥勝初裁。", "林香近接宜春苑，山翠遙添獻壽杯。", "向夕憑高風景麗，天文垂耀象昭回。"]'),
('39f6ac48-3ca6-4c44-93ea-a75594aacabb','奉和春日幸望春宮應制','李適','唐','唐诗','tang','','[]','玉輦金輿天上來，花園四望錦屏開。',66,'全唐诗/poet.tang.3000.json','["玉輦金輿天上來，花園四望錦屏開。", "輕絲半拂朱門柳，細纈全披畫閣梅。", "舞蝶飛行飄御席，[歌鶯]度曲繞仙杯。", "聖詞今日光輝滿，漢主秋風莫道才。"]'),
('cae8ba8d-7886-4ec7-80b7-27004ef35090','奉和立春遊苑迎春','李適','唐','唐诗','tang','','[]','金輿翠輦迎嘉節，御苑仙宮待獻春。',64,'全唐诗/poet.tang.3000.json','["金輿翠輦迎嘉節，御苑仙宮待獻春。", "淑氣初銜梅色淺，條風半拂柳墻新。", "天杯慶壽齊南岳，聖藻光輝動北辰。", "稍覺披香歌吹近，龍驂日暮下城闉。"]'),
('cd4561b5-250a-4b37-953e-d03fca470562','帝幸興慶池戲競渡應制','李適','唐','唐诗','tang','','[]','拂露金輿丹斾轉，凌晨黼帳碧池開。',64,'全唐诗/poet.tang.3000.json','["拂露金輿丹斾轉，凌晨黼帳碧池開。", "南山倒影從雲落，北澗搖光寫溜迴。", "急槳爭標排荇度，輕帆截浦觸荷來。", "橫汾宴鎬歡無極，歌舞年年聖壽杯。"]'),
('695b62ab-eed4-4b1f-bb00-dc67a9e4f926','侍宴安樂公主莊應制','李適','唐','唐诗','tang','','[]','平陽金牓鳳皇樓，沁水銀河鸚鵡洲。',64,'全唐诗/poet.tang.3000.json','["平陽金牓鳳皇樓，沁水銀河鸚鵡洲。", "綵仗遙臨丹壑裏，仙輿暫幸綠亭幽。", "前池錦石蓮花豔，後嶺香鑪桂蘂秋。", "貴主稱觴萬年壽，還輕漢武濟汾遊。"]'),
('ae2260e3-9cd6-4217-9d3d-37580661dcce','侍宴安樂公主新宅應制','李適','唐','唐诗','tang','','[]','銀河半倚鳳皇臺，玉酒相傳鸚鵡杯。',32,'全唐诗/poet.tang.3000.json','["銀河半倚鳳皇臺，玉酒相傳鸚鵡杯。", "若見君平須借問，仙槎一去幾時來。"]'),
('9e38d0d4-b41c-45b7-8841-55a1a9bf93ec','餞唐永昌赴任東都','李適','唐','唐诗','tang','','[]','聞道飛鳧向洛陽，翩翩矯翮度文昌。',32,'全唐诗/poet.tang.3000.json','["聞道飛鳧向洛陽，翩翩矯翮度文昌。", "因聲寄意三花樹，少室巖前幾過香。"]'),
('68f2c09a-2e19-49c7-907a-87c7ba5c9abe','奉和聖製立春日侍宴內殿出剪綵花應制','劉憲','唐','唐诗','tang','','[]','上林宮館好，春光獨早知。',48,'全唐诗/poet.tang.3000.json','["上林宮館好，春光獨早知。", "剪花疑始發，刻燕似新窺。", "色濃輕雪點，香淺嫩風吹。", "此日叨陪侍，恩榮得數枝。"]'),
('f81757da-050e-4ff8-a9ea-18043f1e1bd0','奉和人日清暉閣宴羣臣遇雪應制','劉憲','唐','唐诗','tang','','[]','輿輦乘人日，登臨上鳳京。',48,'全唐诗/poet.tang.3000.json','["輿輦乘人日，登臨上鳳京。", "風尋歌曲颺，雪向舞行縈。", "千官隨興合，萬福與時幷。", "承恩長若此，微賤幸昇平。"]'),
('257201c7-12c4-41e6-8008-1bc6e99a1ed2','奉和七夕宴兩儀殿應制','劉憲','唐','唐诗','tang','','[]','秋吹過雙闕，星仙動二靈。',48,'全唐诗/poet.tang.3000.json','["秋吹過雙闕，星仙動二靈。", "更深移月鏡，河淺度雲軿。", "殿上呼方朔，人間失武丁。", "天文茲夜裏，光映紫微庭。"]'),
('516de5d1-b0ab-4c6d-b52e-f702d9a38b24','奉和九月九日聖製登慈恩寺浮圖應制','劉憲','唐','唐诗','tang','','[]','飛塔雲霄半，清晨羽斾遊。',48,'全唐诗/poet.tang.3000.json','["飛塔雲霄半，清晨羽斾遊。", "登臨憑季月，寥廓見中州。", "御酒新寒退，天文瑞景留。", "辟邪將獻壽，茲日奉千秋。"]'),
('2726cb71-88f7-4749-81b3-c36693076c23','閏九月九日幸總持寺登浮圖應制','劉憲','唐','唐诗','tang','','[]','重陽登閏序，上界叶時巡。',48,'全唐诗/poet.tang.3000.json','["重陽登閏序，上界叶時巡。", "駐輦天花落，開筵妓樂陳。", "城端剎柱見，雲表露盤新。", "臨睨光輝滿，飛文動睿神。"]'),
('23564ed4-148c-42e0-b15d-ffc93e05f10f','侍宴長寧公主東莊','劉憲','唐','唐诗','tang','','[]','公主林亭地，清晨降玉輿。',48,'全唐诗/poet.tang.3000.json','["公主林亭地，清晨降玉輿。", "畫橋飛渡水，仙閣涌臨虛。", "晴新看蛺蝶，夏早摘芙蕖。", "文酒娛遊盛，忻叨侍從餘。"]'),
('ca0d3a07-42ca-4052-a773-24014c95811b','奉和送金城公主入西蕃應制','劉憲','唐','唐诗','tang','','[]','外館踰河右，行營指路岐。',48,'全唐诗/poet.tang.3000.json','["外館踰河右，行營指路岐。", "和親悲遠嫁，忍愛泣將離。", "旌斾羗風引，軒車漢月隨。", "那堪馬上曲，時向管中吹。"]'),
('0badfafd-7d3f-4003-8a4e-80c643bdc10a','奉和聖製登驪山高頂寓目應制','劉憲','唐','唐诗','tang','','[]','驪阜鎮皇都，鑾遊眺八區。',48,'全唐诗/poet.tang.3000.json','["驪阜鎮皇都，鑾遊眺八區。", "原隰旌門裏，風雲扆座隅。", "直城如斗柄，官樹似星榆。", "從臣詞賦末，濫得上天衢。"]'),
('e5d4264b-a1e8-4331-a09a-04f54d9fdeee','奉和幸白鹿觀應制','劉憲','唐','唐诗','tang','','[]','玄遊乘落暉，仙宇藹霏微。',48,'全唐诗/poet.tang.3000.json','["玄遊乘落暉，仙宇藹霏微。", "石梁縈澗轉，珠斾掃壇飛。", "芝童薦膏液，松鶴舞驂騑。", "還似瑤池上，歌成周馭歸。"]'),
('2571834c-30da-4c33-831c-ad55226c30b4','折楊柳','劉憲','唐','唐诗','tang','','[]','沙塞三河道，金閨二月春。',48,'全唐诗/poet.tang.3000.json','["沙塞三河道，金閨二月春。", "碧煙楊柳色，紅粉綺羅人。", "露葉憐啼臉，風花思舞巾。", "攀持君不見，爲聽曲中新。"]'),
('0ded5bd0-ce40-4e0c-8e47-ea8e53e6c1a7','奉和立春日內出綵花樹應制','劉憲','唐','唐诗','tang','','[]','禁苑韶年此日歸，東郊道上轉青旂。',64,'全唐诗/poet.tang.3000.json','["禁苑韶年此日歸，東郊道上轉青旂。", "柳色梅芳何處所，風前雪裏覓芳菲。", "開冰池內魚新躍，剪綵花間燕始飛。", "欲識王遊布陽氣，爲觀天藻競春暉。"]'),
('bf138811-0247-4918-9bc8-6dc812a3aa3b','奉和春日幸望春宮應制','劉憲','唐','唐诗','tang','','[]','暮春春色最便妍，苑裏花開列御筵。',64,'全唐诗/poet.tang.3000.json','["暮春春色最便妍，苑裏花開列御筵。", "商山積翠臨城起，滻水浮光共幕連。", "鶯藏嫩葉歌相喚，蝶礙芳叢舞不前。", "歡娛節物今如此，願奉宸遊億萬年。"]'),
('4bc0ff85-ea67-41a4-b748-af836da05e4a','奉和幸安樂公主山莊應制','劉憲','唐','唐诗','tang','','[]','主家別墅帝城隈，無勞海上覓蓬萊。',64,'全唐诗/poet.tang.3000.json','["主家別墅帝城隈，無勞海上覓蓬萊。", "沓石懸流平地起，危樓曲閣半天開。", "庭莎作薦舞行出，浦樹相將歌棹回。", "此日風光與形勝，衹言作伴聖詞來。"]'),
('8d3e71c6-cddb-4291-a9db-48873615f1a5','興慶池侍宴應制','劉憲','唐','唐诗','tang','','[]','蒼龍闕下天泉池，軒駕來遊簫管吹。',64,'全唐诗/poet.tang.3000.json','["蒼龍闕下天泉池，軒駕來遊簫管吹。", "緣堤夏篠縈不散，冐水新荷卷復披。", "帳殿疑從畫裏出，樓船直在鏡中移。", "自然東海神仙處，何用西崑轍迹疲。"]'),
('f65f6a94-dcc8-4429-849e-766ed1ffaa9a','奉和幸大薦福寺應制','劉憲','唐','唐诗','tang','','[]','地靈傳景福，天駕儼鉤陳。',72,'全唐诗/poet.tang.3000.json','["地靈傳景福，天駕儼鉤陳。", "佳哉藩邸舊，赫矣梵宮新。", "香塔魚山下，禪堂雁水濱。", "珠幡映白日，鏡殿寫青春。", "甚歡延故吏，大覺拯生人。", "幸承歌頌末，長奉屬車塵。"]'),
('cdcf3f45-3d7a-4399-b972-4a5597ad55db','奉和幸三會寺應制','劉憲','唐','唐诗','tang','','[]','岧嶤倉史臺，敞朗紺園開。',72,'全唐诗/poet.tang.3000.json','["岧嶤倉史臺，敞朗紺園開。", "戒旦壺人集，翻霜羽騎來。", "下輦登三襲，褰旒望九垓。", "林披舘陶牓，水浸昆明灰。", "網戶飛花綴，幡竿度鳥迴。", "豫遊仙唱動，瀟灑出塵埃。"]'),
('a7b9e810-21fd-41c1-a64d-0cdb0c6dab69','奉和幸長安故城未央宮應制','劉憲','唐','唐诗','tang','','[]','漢宮千祀外，軒駕一來遊。',72,'全唐诗/poet.tang.3000.json','["漢宮千祀外，軒駕一來遊。", "夷蕩長如此，威靈不復留。", "憑高睿賞發，懷古聖情周。", "寒向南山歛，春過北渭浮。", "土功昔云盛，人英今所求。", "幸聽熏風曲，方知霸道羞。"]'),
('a1d7c2cc-b778-4257-acee-404582b175e3','奉和幸禮部尚書竇希玠宅應制','劉憲','唐','唐诗','tang','','[]','北斗樞機任，西京肺腑親。',72,'全唐诗/poet.tang.3000.json','["北斗樞機任，西京肺腑親。", "疇昔王門下，今茲御幸辰。", "恩光山水被，聖作管弦新。", "遶坐熏紅藥，當軒暗綠筠。", "摘荷纔早夏，聽鳥尚餘春。", "行漏今徒晚，風煙起觀津。"]'),
('9c154414-92e5-4805-96e3-ae798baeb2ab','奉和聖製幸望春宮送朔方大總管張仁亶','劉憲','唐','唐诗','tang','','[]','命將擇耆年，圖功勝必全。',72,'全唐诗/poet.tang.3000.json','["命將擇耆年，圖功勝必全。", "光輝萬乘餞，威武二庭宣。", "中衢橫鼓角，曠野蔽旌旃。", "推食天廚至，投醪御酒傳。", "涼風過雁苑，殺氣下雞田。", "分閫恩何極，臨岐動睿篇。"]'),
('bbcbbb9b-b3be-4a39-a41b-0c01993c2b5b','奉和幸韋嗣立山莊侍宴應制','劉憲','唐','唐诗','tang','','[]','東山有謝安，枉道降鳴鑾。',96,'全唐诗/poet.tang.3000.json','["東山有謝安，枉道降鳴鑾。", "緹騎分初日，霓旌度曉寒。", "雲蹕巖間下，虹橋澗底盤。", "幽棲俄以届，聖矚宛餘歡。", "崖懸飛溜直，岸轉綠潭寬。", "桂華堯酒泛，松響舜琴彈。", "明主恩斯極，賢臣節更殫。", "不才叨侍從，詠德以濡翰。"]'),
('901756ab-621e-46e7-9dc5-502e11c59558','人日翫雪應制','劉憲','唐','唐诗','tang','','[]','勝日登臨雲葉起，芳風搖蕩雪花飛。',32,'全唐诗/poet.tang.3000.json','["勝日登臨雲葉起，芳風搖蕩雪花飛。", "呈暉幸得承金鏡，颺彩還將奉玉衣。"]'),
('c8723446-6f05-4b01-b97b-b0ab44f5bc5a','上巳日祓禊渭濱應制','劉憲','唐','唐诗','tang','','[]','桃花欲落柳條長，沙頭水上足風光。',32,'全唐诗/poet.tang.3000.json','["桃花欲落柳條長，沙頭水上足風光。", "此時御蹕來遊處，願奉年年祓禊觴。"]'),
('c44d50c8-eabc-4e14-84f7-fbe4d2af0e5b','苑中遇雪應制','劉憲','唐','唐诗','tang','','[]','龍驂曉入望春宮，正逢春雪舞東風。',32,'全唐诗/poet.tang.3000.json','["龍驂曉入望春宮，正逢春雪舞東風。", "花光倂灑天文上，寒氣行消御酒中。"]'),
('308d1e8b-69b0-482d-b5e2-8111e49e495d','夜宴安樂公主新宅','劉憲','唐','唐诗','tang','','[]','層軒洞戶旦新披，度曲飛觴夜不疲。',32,'全唐诗/poet.tang.3000.json','["層軒洞戶旦新披，度曲飛觴夜不疲。", "綺綴玲瓏河色曉，珠簾隱映月華窺。"]'),
('cf6b77dd-f548-43e4-90a9-5203bb71dcd0','奉和聖製幸韋嗣立山莊','劉憲','唐','唐诗','tang','','[]','非吏非隱晉尚書，一丘一壑降乘輿。',32,'全唐诗/poet.tang.3000.json','["非吏非隱晉尚書，一丘一壑降乘輿。", "天藻緣情兩曜合，山巵獻壽萬年餘。"]'),
('0b683d2e-949d-42b1-994d-25563faf420c','餞唐永昌','劉憲','唐','唐诗','tang','','[]','始見郎官拜洛陽，旋聞近侍發雕章。',32,'全唐诗/poet.tang.3000.json','["始見郎官拜洛陽，旋聞近侍發雕章。", "緒言已勖期年政，綺字當生滿路光。"]'),
('9e5c0091-3b8c-4843-a391-8765451cd122','晦日置酒林亭','高正臣','唐','唐诗','tang','','[]','正月符嘉節，三春翫物華。',48,'全唐诗/poet.tang.3000.json','["正月符嘉節，三春翫物華。", "忘懷寄尊酒，陶性狎山家。", "柳翠含煙葉，梅芳帶雪花。", "光陰不相借，遲遲落景斜。"]'),
('3b993be2-23fd-4469-a89f-a493bb442afd','晦日重宴','高正臣','唐','唐诗','tang','','[]','芳辰重游衍，乘景共追隨。',48,'全唐诗/poet.tang.3000.json','["芳辰重游衍，乘景共追隨。", "班荆陪舊識，傾蓋得新知。", "水葉分蓮沼，風花落柳枝。", "自符河朔趣，寧羨高陽池。"]'),
('834ac43f-692a-4a67-8292-3a80e4a930c1','晦日宴高氏林亭','崔知賢','唐','唐诗','tang','','[]','上月河陽地，芳辰景物華。',48,'全唐诗/poet.tang.3000.json','["上月河陽地，芳辰景物華。", "緜蠻變時鳥，照曜起春霞。", "柳搖風處色，梅散日前花。", "淹留洛城晚，歌吹石崇家。"]'),
('3eaa47b5-3860-41bd-8856-13cbdb2b81de','上元夜效小庾體','崔知賢','唐','唐诗','tang','','[]','今夜啓城闉，結伴戲芳春。',48,'全唐诗/poet.tang.3000.json','["今夜啓城闉，結伴戲芳春。", "鼓聲撩亂動，風光觸處新。", "月下多遊騎，燈前饒看人。", "歡樂無窮已，歌舞達明晨。"]'),
('b1478971-4188-4f24-b05f-ffd69291177f','三月三日宴王明府山亭','崔知賢','唐','唐诗','tang','','[]','京洛皇居，芳禊春餘。',60,'全唐诗/poet.tang.3000.json','["京洛皇居，芳禊春餘。", "影媚元巳，和風上除。", "雲開翠帟，水鶩鮮居。", "林渚縈暎，煙霞卷舒。", "花飄粉蝶，藻躍文魚。", "沿波式宴，其樂只且。"]'),
('73f08ddb-4bad-4f23-8017-600c13c6b1cd','三月三日宴王明府山亭','席元明','唐','唐诗','tang','','[]','日惟上巳，時亨有巢。',60,'全唐诗/poet.tang.3000.json','["日惟上巳，時亨有巢。", "中尊引桂，芳筵籍茅。", "書僮橐筆，膳夫行炰。", "煙霏萬雉，花明四郊。", "沼蘋白帶，山花紫苞。", "同人聚飲，千載神交。"]'),
('24bd0a93-c88c-4e63-a17b-622607387de0','晦日宴高氏林亭','韓仲宣','唐','唐诗','tang','','[]','欲知行有樂，芳尊對物華。',48,'全唐诗/poet.tang.3000.json','["欲知行有樂，芳尊對物華。", "地接安仁縣，園是季倫家。", "柳處雲疑葉，梅間雪似花。", "日落歸途遠，留興伴煙霞。"]'),
('9f023ffc-e9fe-4261-8c25-0f3a2cd635de','晦日重宴','韓仲宣','唐','唐诗','tang','','[]','鳳苑先吹晚，龍樓夕照披。',48,'全唐诗/poet.tang.3000.json','["鳳苑先吹晚，龍樓夕照披。", "陳遵已投轄，山公正坐池。", "落日催金奏，飛霞送玉巵。", "此時陪綺席，不醉欲何爲。"]'),
('72233e48-4d10-4360-8dce-5d2044594ef8','上元夜效小庾體','韓仲宣','唐','唐诗','tang','','[]','他鄉月夜人，相伴看燈輪。',48,'全唐诗/poet.tang.3000.json','["他鄉月夜人，相伴看燈輪。", "光隨九華出，影共百枝新。", "歌鐘盛北里，車馬沸南鄰。", "今宵何處好？惟有洛城春。"]'),
('f229ca05-ff53-49de-b96a-931bfe645833','三月三日宴王明府山亭','韓仲宣','唐','唐诗','tang','','[]','河濱上巳，洛汭春華。',60,'全唐诗/poet.tang.3000.json','["河濱上巳，洛汭春華。", "碧池涵日，翠斝澄霞。", "溝垂細柳，岸擁平沙。", "歌鶯響樹，舞蝶驚花。", "雲浮寶馬，水韻香車。", "熟記行樂，淹留景斜。"]'),
('8aa2468a-862d-452c-ad4d-e7e6ec83635f','晦日宴高氏林亭','周彥昭','唐','唐诗','tang','','[]','勝地臨雞浦，高會偶龍沙。',48,'全唐诗/poet.tang.3000.json','["勝地臨雞浦，高會偶龍沙。", "御柳驚春色，仙筇掩月華。", "門邀千里馭，杯泛九光霞。", "日落山亭晚，雷送七香車。"]'),
('a5d81b06-c71c-4994-a6c7-5520b507821a','晦日宴高氏林亭','高球','唐','唐诗','tang','','[]','溫洛年光早，皇州景望華。',48,'全唐诗/poet.tang.3000.json','["溫洛年光早，皇州景望華。", "連鑣尋上路，乘興入山家。", "輕苔網危石，春水架平沙。", "賞極林塘暮，處處起煙霞。"]'),
('0b73a722-dad8-4e17-8509-642113227482','三月三日宴王[明]府山亭','高球','唐','唐诗','tang','','[]','洛城春禊，元巳芳年。',60,'全唐诗/poet.tang.3000.json','["洛城春禊，元巳芳年。", "季倫園裏，逸少亭前。", "曲中舉白，談際生玄。", "陸離軒蓋，淒清管弦。", "萍疎波蕩，柳弱風牽。", "未淹歡趣，林溪夕煙。"]'),
('55da3012-4d45-4fb6-ade9-1a7a0b421c22','晦日宴高氏林亭','弓嗣初','唐','唐诗','tang','','[]','上序春暉麗，中園物候華。',48,'全唐诗/poet.tang.3000.json','["上序春暉麗，中園物候華。", "高才盛文雅，逸興滿煙霞。", "參差金谷樹，皎鏡碧塘沙。", "蕭散林亭晚，倒載欲還家。"]'),
('9c2c293e-2e79-4a03-8fe7-fd97fb6ef824','晦日重宴','弓嗣初','唐','唐诗','tang','','[]','年華藹芳隰，春溜滿新池。',48,'全唐诗/poet.tang.3000.json','["年華藹芳隰，春溜滿新池。", "促賞依三友，延歡寄一巵。", "鳥聲隨管變，花影逐風移。", "行樂方無極，淹留惜晚曦。"]');
